def _team_standings_last_updated(group):
    if not group:
        return None
    try:
        return TeamStanding.objects.filter(group=group).aggregate(latest=Max('last_updated')).get('latest')
    except Exception:
        return None


def _latest_standings_group_for_team(primary_team):
    if not primary_team:
        return None
    try:
        standing = (
            TeamStanding.objects
            .select_related('group')
            .filter(team=primary_team)
            .order_by('-last_updated', '-played', '-id')
            .first()
        )
        return standing.group if standing else None
    except Exception:
        return None


def _refresh_rfaf_standings_inline(*, allow_fallback=False):
    """
    Refresco rápido (en-process) de la clasificación RFAF.
    Evita subprocess largos y permite devolver errores claros.
    """
    try:
        from scripts import import_from_rfef
    except Exception as exc:
        return False, f'No se pudo cargar el módulo RFAF: {exc}', None
    try:
        rows, html = import_from_rfef.parse_table(allow_fallback=bool(allow_fallback))
        next_match = import_from_rfef.extract_next_match_from_classification(html)
        if not next_match:
            next_match = import_from_rfef.fetch_next_match_from_classification(html)
        if next_match and next_match.get("status") != "next":
            next_match = None
        try:
            import_from_rfef.save_next_match_cache(next_match)
        except Exception:
            pass
        update_team_standings(
            rows,
            'RFAF',
            getattr(import_from_rfef, 'URL', '') or '',
        )
        return True, f'Clasificación actualizada (filas={len(rows)}).', next_match
    except Exception as exc:
        return False, str(exc) or 'Error desconocido actualizando RFAF.', None


@login_required
def session_keepalive(request):
    """
    Mantiene viva la sesión mientras el usuario está en el editor (pizarra) sin hacer requests.
    Evita perder trabajo por caducidad de sesión al pulsar "Guardar/Crear" tras estar tiempo editando.
    """
    request.session['__keepalive__'] = timezone.now().isoformat()
    response = JsonResponse({'ok': True})
    response['Cache-Control'] = 'no-store'
    return response


def public_build_info(request):
    """
    Endpoint público para verificar qué versión está desplegada (sin exponer secretos).

    Útil para depurar caches en Safari/iOS WebView/Service Worker y confirmar el commit en Render.
    """
    build_id = (
        os.getenv('RENDER_GIT_COMMIT')
        or os.getenv('RENDER_DEPLOY_ID')
        or os.getenv('SOURCE_VERSION')
        or os.getenv('GIT_SHA')
        or ''
    ).strip()
    return JsonResponse(
        {
            'ok': True,
            'build': {
                'id': build_id,
                'has_build_id': bool(build_id),
            },
            'flags': {
                'enable_public_signup': str(os.getenv('ENABLE_PUBLIC_SIGNUP', '0') or '').strip().lower() in {'1', 'true', 'yes', 'on'},
                'allow_single_club_fallback': str(os.getenv('ALLOW_SINGLE_CLUB_FALLBACK', '0') or '').strip().lower() in {'1', 'true', 'yes', 'on'},
            },
        }
    )


@login_required
def billing_page(request):
    workspace = _get_active_workspace(request)
    if not workspace or getattr(workspace, 'kind', None) != Workspace.KIND_CLUB:
        return HttpResponse('Selecciona un club (workspace) para ver la suscripción.', status=400)
    if not _can_manage_workspace(request.user, workspace) and not _can_access_platform(request.user):
        return HttpResponse('No tienes permisos para gestionar la suscripción.', status=403)

    expires_at = getattr(workspace, 'trial_expires_at', None)
    now = timezone.now()
    days_left = None
    if expires_at:
        try:
            days_left = max(0, int((expires_at - now).total_seconds() // 86400))
        except Exception:
            days_left = None
    status = str(getattr(workspace, 'subscription_status', '') or '').strip().lower() or 'trial'
    if status == 'trial' and expires_at and expires_at <= now:
        status = 'expired'
    return render(
        request,
        'football/billing.html',
        {
            'workspace': workspace,
            'subscription_status': status,
            'trial_expires_at': expires_at,
            'trial_days_left': days_left,
        },
    )


@login_required
@require_POST
def workspace_set_active_team(request):
    """
    Cambia el equipo/categoría activo del workspace club (persistido en sesión).

    Importante:
    - No modifica `workspace.primary_team` (equipo "principal" legacy del cliente).
    - Valida que el equipo pertenezca al workspace mediante WorkspaceTeam.
    """
    workspace = _get_active_workspace(request)
    next_url = (request.POST.get('next') or '').strip() or request.META.get('HTTP_REFERER') or reverse('dashboard-home')
    if not workspace or workspace.kind != Workspace.KIND_CLUB:
        return redirect(next_url)

    team_id = _parse_int(request.POST.get('team_id') or request.POST.get('team') or request.POST.get('active_team_id'))
    if not team_id:
        return redirect(next_url)

    links = _workspace_team_links_for_user(workspace, request.user)
    allowed_team_ids = {int(link.team_id) for link in links if getattr(link, 'team_id', None)}
    if int(team_id) not in allowed_team_ids:
        return redirect(next_url)

    mapping = request.session.get('active_team_by_workspace')
    if not isinstance(mapping, dict):
        mapping = {}
    mapping[str(workspace.id)] = int(team_id)
    request.session['active_team_by_workspace'] = mapping
    return redirect(next_url)


@login_required
@require_POST
def workspace_set_active_workspace(request):
    """
    Fija el workspace activo en sesión para usuarios no-Platform (y también Platform).
    Esto evita mezclar datos (p.ej. caer al equipo global Benagalbón cuando no hay contexto).
    """
    desired_id = _parse_int(request.POST.get('workspace_id') or request.POST.get('workspace') or 0)
    next_url = (request.POST.get('next') or '').strip() or request.META.get('HTTP_REFERER') or reverse('dashboard-home')
    if not desired_id:
        return redirect(next_url)
    available = _available_workspaces_for_user(request.user)
    workspace = available.filter(id=desired_id, is_active=True).first()
    if not workspace:
        return redirect(next_url)
    request.session['active_workspace_id'] = workspace.id
    return redirect(next_url)


@login_required
@require_POST
def workspace_sync_competition_api(request):
    """
    Sincroniza el contexto competitivo del workspace club actual (owner/admin).
    Útil para onboarding/autoservicio sin depender de Platform.
    """
    workspace = _get_active_workspace(request)
    if not workspace or workspace.kind != Workspace.KIND_CLUB:
        return JsonResponse({'status': 'error', 'message': 'No hay workspace club activo.'}, status=400)
    if not _can_manage_workspace(request.user, workspace):
        return JsonResponse({'status': 'error', 'message': 'No autorizado.'}, status=403)
    primary_team = _get_active_team_for_request(request) or getattr(workspace, 'primary_team', None)
    if not primary_team:
        return JsonResponse({'status': 'error', 'message': 'No hay equipo configurado.'}, status=400)

    lock_key = f'workspace_sync_lock:{workspace.id}:{primary_team.id}'
    if not cache.add(lock_key, '1', timeout=180):
        return JsonResponse({'status': 'error', 'message': 'Ya hay una sincronización en curso.'}, status=429)
    try:
        context, sync_error = _sync_workspace_competition_context(workspace, primary_team=primary_team)
        if sync_error:
            return JsonResponse({'status': 'error', 'message': sync_error}, status=500)
        return JsonResponse(
            {
                'status': 'success',
                'message': 'Sincronización completada.',
                'sync_status': str(getattr(context, 'sync_status', '') or '').strip(),
                'last_sync_at': getattr(context, 'last_sync_at', None).isoformat() if getattr(context, 'last_sync_at', None) else '',
            }
        )
    except Exception as exc:
        return JsonResponse({'status': 'error', 'message': str(exc) or 'No se pudo sincronizar.'}, status=500)
    finally:
        cache.delete(lock_key)


@login_required
def system_diagnostics(request):
    """Diagnóstico (solo admin) para comprobar persistencia en Render.

    No expone secretos: únicamente vendor/engine y flags.
    """
    if not _is_admin_user(request.user):
        return JsonResponse({'error': 'No autorizado'}, status=403)
    default_db = settings.DATABASES.get('default', {}) if hasattr(settings, 'DATABASES') else {}
    engine = str(default_db.get('ENGINE') or '').strip()
    name = str(default_db.get('NAME') or '').strip()
    vendor = ''
    try:
        vendor = str(getattr(connections['default'], 'vendor', '') or '')
    except Exception:
        vendor = ''
    return JsonResponse(
        {
            'ok': True,
            'database': {
                'vendor': vendor,
                'engine': engine,
                # Solo devolvemos NAME en DEBUG o sqlite (en Postgres se oculta).
                'name': name if (settings.DEBUG or vendor == 'sqlite') else '',
                'uses_database_url': bool(os.getenv('DATABASE_URL', '').strip()),
            },
            'session': {
                'engine': str(getattr(settings, 'SESSION_ENGINE', '') or '').strip(),
                'cookie_name': str(getattr(settings, 'SESSION_COOKIE_NAME', '') or '').strip(),
                'cookie_age': int(getattr(settings, 'SESSION_COOKIE_AGE', 0) or 0),
                'save_every_request': bool(getattr(settings, 'SESSION_SAVE_EVERY_REQUEST', False)),
            },
            'csrf': {
                'cookie_name': str(getattr(settings, 'CSRF_COOKIE_NAME', '') or '').strip(),
                'trusted_origins_count': len(getattr(settings, 'CSRF_TRUSTED_ORIGINS', []) or []),
            },
        }
    )


def system_healthcheck_api(request):
    # Operativa: permitir a administradores del club (workspace owner/admin) ver el healthcheck,
    # ya que es imprescindible para depurar PDFs en producción.
    if not _is_admin_user(request.user):
        workspace = _get_active_workspace(request)
        if not (workspace and _can_manage_workspace(request.user, workspace)):
            return JsonResponse({'error': 'No autorizado'}, status=403)
    try:
        from football.healthchecks import run_system_healthcheck  # lazy import
    except Exception as exc:
        return JsonResponse({'ok': False, 'error': f'No se pudo importar healthchecks: {exc}'}, status=500)

    report = run_system_healthcheck()
    # PDF smoke test (WeasyPrint)
    pdf_smoke = {'ok': False, 'detail': 'not checked'}
    if weasyprint:
        try:
            html = '<!doctype html><html><meta charset="utf-8"><body><h1>PDF OK</h1><p>Smoke test</p></body></html>'
            pdf_bytes, error = _render_pdf_bytes_with_error(request, html)
            if pdf_bytes:
                pdf_smoke = {'ok': True, 'detail': f'bytes={len(pdf_bytes)}'}
            else:
                pdf_smoke = {'ok': False, 'detail': error or 'unknown'}
        except Exception as exc:  # pragma: no cover
            pdf_smoke = {'ok': False, 'detail': f'{exc.__class__.__name__}: {exc}'}
    else:
        pdf_smoke = {'ok': False, 'detail': 'weasyprint not available'}

    report['pdf_smoke'] = pdf_smoke
    try:
        report['weasyprint_version'] = str(getattr(weasyprint, '__version__', '') or '')
    except Exception:
        report['weasyprint_version'] = ''
    try:
        import pydyf  # noqa: WPS433

        pydyf_version = str(getattr(pydyf, '__version__', '') or '')
        report['pydyf_version'] = pydyf_version
        parts = [int(p) for p in re.findall(r'\d+', pydyf_version)[:3]]
        while len(parts) < 3:
            parts.append(0)
        parsed = tuple(parts)
        pydyf_ok = (parsed >= (0, 10, 0)) and (parsed < (0, 11, 0))
        try:
            import inspect  # noqa: WPS433

            sig = inspect.signature(getattr(pydyf, 'PDF', None))
            report['pydyf_pdf_signature'] = str(sig)
            params = list(getattr(sig, 'parameters', {}).values()) if sig else []
            report['pydyf_pdf_args_ok'] = len(params) >= 2
            if len(params) < 2:
                pydyf_ok = False
        except Exception:
            report['pydyf_pdf_signature'] = ''
            report['pydyf_pdf_args_ok'] = False
        report['pydyf_ok'] = bool(pydyf_ok)
    except Exception:
        report['pydyf_version'] = ''
        report['pydyf_ok'] = False
        report['pydyf_pdf_signature'] = ''
        report['pydyf_pdf_args_ok'] = False
    return JsonResponse(report)


def kpi_audit(request):
    """
    Auditoría rápida (solo admin) de KPIs por jugador.

    Devuelve los valores ya calculados en `compute_player_dashboard()` junto con
    checks de coherencia (sin exponer secretos).
    """
    if not _is_admin_user(request.user):
        return JsonResponse({'error': 'No autorizado'}, status=403)
    team_id = _parse_int(request.GET.get('team_id'))
    force_refresh = str(request.GET.get('refresh') or '').strip().lower() in {'1', 'true', 'yes', 'on'}
    if team_id:
        team = Team.objects.filter(id=team_id).select_related('group', 'group__season').first()
    else:
        team = _get_active_team_for_request(request)
    if not team:
        return JsonResponse({'ok': False, 'error': 'Equipo no encontrado o no activo.'}, status=400)

    try:
        rows = compute_player_dashboard(team, force_refresh=force_refresh)
    except Exception:
        logger.exception('kpi_audit: no se pudo calcular el dashboard')
        return JsonResponse({'ok': False, 'error': 'No se pudieron calcular KPIs.'}, status=500)

    def _recalc_importance(row):
        total_possible = int(row.get('total_possible_minutes') or 0)
        max_successes = int(row.get('max_successes') or 0)
        calculated = calculate_importance_score(
            minutes=int(row.get('minutes') or 0),
            total_possible_minutes=total_possible,
            successes=int(row.get('successes') or 0),
            max_successes=max_successes,
        )
        return calculated

    issues_total = 0
    audited = []
    for row in rows:
        pj = int(row.get('pj') or 0)
        pt = int(row.get('pt') or 0)
        minutes = int(row.get('minutes') or 0)
        goals = int(row.get('goals') or 0)
        assists = int(row.get('assists') or 0)
        total_rounds = int(row.get('competition_total_rounds') or 0)
        match_minutes = int(row.get('match_regulation_minutes') or 0)
        total_possible = int(row.get('total_possible_minutes') or 0)
        participation = float(row.get('participation_pct') or 0)
        importance = float(row.get('importance_score') or 0)
        influence = float(row.get('influence_score') or 0)
        availability_pct = float(row.get('availability_pct') or 0)
        success_volume_pct = float(row.get('success_volume_pct') or 0)
        successes = int(row.get('successes') or 0)
        matches_payload = row.get('matches') or []
        matches_count = len(matches_payload) if isinstance(matches_payload, list) else 0
        key_passes_completed = int(row.get('key_passes_completed') or 0)
        max_decisive_actions_per90 = float(row.get('max_decisive_actions_per90') or 0)
        successes_per90 = float(row.get('successes_per90') or 0)
        decisive_actions_per90 = float(row.get('decisive_actions_per90') or 0)
        totals_locked = bool(row.get('totals_locked'))

        issues = []
        if pt > pj:
            issues.append('PT>PJ')
        if pj < 0 or pt < 0 or minutes < 0 or goals < 0 or assists < 0:
            issues.append('NEGATIVO')
        if total_rounds < 0 or match_minutes < 0 or total_possible < 0:
            issues.append('DENOM_NEGATIVO')
        if total_rounds > 0:
            expected_participation = round(min((pj / total_rounds) * 100, 100), 1)
            if abs(expected_participation - participation) > 0.11:
                issues.append('PARTICIPACION_MISMATCH')
        if not totals_locked:
            if matches_count != pj:
                issues.append('PJ_MATCHES_MISMATCH')
            if pt > matches_count:
                issues.append('PT_MATCHES_MISMATCH')
            if pj > 0 and matches_count == 0:
                issues.append('PJ_SIN_PARTIDOS')
            # Un jugador puede tener PJ>0 con 0 acciones si fue titular sin registros (alineación).
            # Lo que no debe ocurrir es PJ>0 con 0 acciones y PT=0 (banquillo sin acciones).
            if pj > 0 and int(row.get('total_actions') or 0) == 0 and pt == 0:
                issues.append('PJ_BENCH_WITHOUT_ACTIONS')
        if match_minutes > 0 and pj > 0:
            # Guardrail: margen extra por partidos con añadido / última acción > reglamentario.
            hard_cap = pj * (match_minutes + 30)
            if minutes > hard_cap:
                issues.append('MINUTOS_EXCESIVOS')
        expected_importance = _recalc_importance(row)
        expected_availability = float(expected_importance.get('availability_pct') or 0)
        expected_success_volume = float(expected_importance.get('success_volume_pct') or 0)
        expected_importance_score = float(expected_importance.get('importance_score') or 0)
        if abs(expected_availability - availability_pct) > 0.11:
            issues.append('AVAILABILITY_MISMATCH')
        if abs(expected_success_volume - success_volume_pct) > 0.11:
            issues.append('SUCCESS_VOLUME_MISMATCH')
        if abs(expected_importance_score - importance) > 0.11:
            issues.append('IMPORTANCIA_MISMATCH')

        expected_influence = calculate_influence_score(
            minutes=minutes,
            successes=successes,
            goals=goals,
            assists=assists,
            key_passes_completed=key_passes_completed,
            max_decisive_actions_per90=max_decisive_actions_per90,
            normalization_minutes=match_minutes or 90,
        )
        expected_successes_per90 = float(expected_influence.get('successes_per90') or 0)
        expected_decisive_actions_per90 = float(expected_influence.get('decisive_actions_per90') or 0)
        expected_influence_score = float(expected_influence.get('influence_score') or 0)
        if abs(expected_successes_per90 - successes_per90) > 0.011:
            issues.append('SUCCESS_PER90_MISMATCH')
        if abs(expected_decisive_actions_per90 - decisive_actions_per90) > 0.011:
            issues.append('DECISIVE_PER90_MISMATCH')
        if abs(expected_influence_score - influence) > 0.11:
            issues.append('INFLUENCE_MISMATCH')
        if not (0 <= availability_pct <= 100) or not (0 <= success_volume_pct <= 100):
            issues.append('PCT_FUERA_RANGO')
        if not (0 <= importance <= 100) or not (0 <= influence <= 100) or not (0 <= participation <= 100):
            issues.append('KPI_FUERA_RANGO')

        if issues:
            issues_total += len(issues)
        audited.append(
            {
                'player_id': int(row.get('player_id') or 0),
                'name': row.get('name') or '',
                'number': row.get('number'),
                'position': row.get('position') or '',
                'pj': pj,
                'pt': pt,
                'minutes': minutes,
                'goals': goals,
                'assists': assists,
                'successes': successes,
                'total_actions': int(row.get('total_actions') or 0),
                'success_rate': float(row.get('success_rate') or 0),
                'competition_total_rounds': total_rounds,
                'match_regulation_minutes': match_minutes,
                'total_possible_minutes': total_possible,
                'participation_pct': participation,
                'matches_count': matches_count,
                'availability_pct': availability_pct,
                'success_volume_pct': success_volume_pct,
                'importance_score': importance,
                'influence_score': influence,
                'successes_per90': successes_per90,
                'decisive_actions_per90': decisive_actions_per90,
                'max_successes': int(row.get('max_successes') or 0),
                'max_decisive_actions_per90': float(row.get('max_decisive_actions_per90') or 0),
                'totals_locked': bool(row.get('totals_locked')),
                'assists_locked': bool(row.get('assists_locked')),
                'issues': issues,
            }
        )

    return JsonResponse(
        {
            'ok': True,
            'team': {
                'id': int(team.id),
                'name': team.display_name,
                'slug': team.slug,
                'category': getattr(team, 'category', '') or '',
                'game_format': getattr(team, 'game_format', '') or '',
                'group_id': getattr(team, 'group_id', None),
            },
            'computed_at': timezone.localtime().isoformat(),
            'force_refresh': bool(force_refresh),
            'summary': {
                'players': len(audited),
                'issues_total': issues_total,
                'players_with_issues': sum(1 for r in audited if r['issues']),
            },
            'rows': audited,
        }
    )

