def build_task_material_library():
    materials = [dict(item) for item in TASK_MATERIAL_LIBRARY]
    if not TASK_MATERIAL_PPT_DIR.exists():
        return materials

    allowed_suffixes = {'.png', '.gif', '.jpg', '.jpeg', '.webp'}
    icon_files = [
        path
        for path in sorted(TASK_MATERIAL_PPT_DIR.iterdir())
        if path.is_file() and path.suffix.lower() in allowed_suffixes
    ]
    for index, icon_file in enumerate(icon_files, start=1):
        materials.append(
            {
                'label': f'P{index:02d}',
                'title': f'Recurso visual PPT {index:02d}',
                'kind': f'ppt-{index:02d}',
                'category': 'ppt',
                'icon': '',
                'asset': f"football/images/task-materials/ppt/{icon_file.name}",
            }
        )
    return materials


def _canonical_action_value(value):
    return ' '.join(str(value or '').split()).strip().lower()


def _build_pdf_response_or_html_fallback(request, html: str, filename: str, *, inline: bool = False, force_pdf: bool = False):
    def _parse_version_tuple(raw_version: str):
        parts = [int(p) for p in re.findall(r'\d+', str(raw_version or ''))[:3]]
        while len(parts) < 3:
            parts.append(0)
        return tuple(parts)

    def _pydyf_compat_status():
        """
        WeasyPrint 57.x requiere pydyf 0.10.x.

        Si pydyf es 0.11+ (firma PDF() sin args), WeasyPrint 57.x falla con:
        `TypeError: PDF.__init__() takes 1 positional argument but 3 were given`.
        """
        try:
            import pydyf  # noqa: WPS433
            import inspect  # noqa: WPS433

            version = str(getattr(pydyf, '__version__', '') or '')
            parsed = _parse_version_tuple(version)
            ok = (0, 10, 0) <= parsed < (0, 11, 0)
            # Guardrail extra: en entornos cacheados puede quedar un pydyf incompatible aunque la
            # versión reportada sea errónea. Preferimos chequear la firma real.
            try:
                pdf_cls = getattr(pydyf, 'PDF', None)
                sig = inspect.signature(pdf_cls) if pdf_cls else None
                params = list(getattr(sig, 'parameters', {}).values()) if sig else []
                # En pydyf 0.11+, PDF() no acepta args; en 0.10.x acepta (version, identifier).
                if len(params) < 2:
                    ok = False
            except Exception:
                pass
            return ok, version or 'unknown'
        except Exception:
            return False, 'not installed'

    if not weasyprint:
        if force_pdf:
            return HttpResponse('PDF no disponible en este servidor.', status=503)
        return HttpResponse(html, content_type='text/html; charset=utf-8')
    pydyf_ok, pydyf_version = _pydyf_compat_status()
    if not pydyf_ok:
        message = f'PDF no disponible: servidor desactualizado (pydyf {pydyf_version}).'
        if force_pdf:
            return HttpResponse(message, status=503, content_type='text/plain; charset=utf-8')
        return HttpResponse(html, content_type='text/html; charset=utf-8')
    # Nota: usamos el helper con error para poder mostrar detalle con `?debug=1` a admins del club.
    pdf_file, pdf_error = _render_pdf_bytes_with_error(request, html)
    if pdf_file:
        response = HttpResponse(pdf_file, content_type='application/pdf')
        disposition = 'inline' if inline else 'attachment'
        response['Content-Disposition'] = f'{disposition}; filename="{filename}.pdf"'
        # Ayuda a depurar despliegues/cachés (Safari/SW): permite ver el build activo.
        try:
            build_id = (
                os.getenv('RENDER_GIT_COMMIT')
                or os.getenv('RENDER_DEPLOY_ID')
                or os.getenv('SOURCE_VERSION')
                or os.getenv('GIT_SHA')
                or ''
            ).strip()
            if build_id:
                response['X-2J-Build'] = build_id
        except Exception:
            pass
        return response
    logger.exception('WeasyPrint: error generando PDF (response): %s', pdf_error or 'unknown')
    if force_pdf:
        debug = str(request.GET.get('debug') or '').strip().lower() in {'1', 'true', 'yes', 'on'}
        debug_allowed = False
        try:
            user = getattr(request, 'user', None)
            debug_allowed = bool(_is_admin_user(user))
            if not debug_allowed:
                workspace = _get_active_workspace(request)
                debug_allowed = bool(workspace and _can_manage_workspace(user, workspace))
        except Exception:
            debug_allowed = False
        if debug and debug_allowed:
            detail = (pdf_error or '').strip() or 'unknown'
            resp = HttpResponse(
                f'No se pudo generar el PDF. {detail}',
                status=503,
                content_type='text/plain; charset=utf-8',
            )
            resp['Cache-Control'] = 'no-store'
            return resp
        resp = HttpResponse('No se pudo generar el PDF.', status=503, content_type='text/plain; charset=utf-8')
        resp['Cache-Control'] = 'no-store'
        return resp
    return HttpResponse(html, content_type='text/html; charset=utf-8')


def _render_pdf_bytes(request, html: str):
    def _parse_version_tuple(raw_version: str):
        parts = [int(p) for p in re.findall(r'\d+', str(raw_version or ''))[:3]]
        while len(parts) < 3:
            parts.append(0)
        return tuple(parts)

    def _pydyf_ok():
        try:
            import pydyf  # noqa: WPS433
            import inspect  # noqa: WPS433

            version = str(getattr(pydyf, '__version__', '') or '')
            parsed = _parse_version_tuple(version)
            ok = (0, 10, 0) <= parsed < (0, 11, 0)
            try:
                pdf_cls = getattr(pydyf, 'PDF', None)
                sig = inspect.signature(pdf_cls) if pdf_cls else None
                params = list(getattr(sig, 'parameters', {}).values()) if sig else []
                if len(params) < 2:
                    ok = False
            except Exception:
                pass
            return ok
        except Exception:
            return False

    if not weasyprint:
        return None
    if not _pydyf_ok():
        return None
    try:
        def _safe_url_fetcher(url, timeout=4, ssl_context=None):
            try:
                default_fetcher = getattr(weasyprint, 'default_url_fetcher', None)
                if callable(default_fetcher):
                    return default_fetcher(url, timeout=timeout, ssl_context=ssl_context)
            except Exception:
                pass
            return {'string': b'', 'mime_type': 'text/plain'}

        return weasyprint.HTML(
            string=html,
            base_url=request.build_absolute_uri('/'),
            url_fetcher=_safe_url_fetcher,
        ).write_pdf()
    except Exception:
        logger.exception('WeasyPrint: error generando PDF')
        return None


def _render_pdf_bytes_with_error(request, html: str):
    def _parse_version_tuple(raw_version: str):
        parts = [int(p) for p in re.findall(r'\d+', str(raw_version or ''))[:3]]
        while len(parts) < 3:
            parts.append(0)
        return tuple(parts)

    def _pydyf_compat_status():
        try:
            import pydyf  # noqa: WPS433
            import inspect  # noqa: WPS433

            version = str(getattr(pydyf, '__version__', '') or '')
            parsed = _parse_version_tuple(version)
            ok = (0, 10, 0) <= parsed < (0, 11, 0)
            try:
                pdf_cls = getattr(pydyf, 'PDF', None)
                sig = inspect.signature(pdf_cls) if pdf_cls else None
                params = list(getattr(sig, 'parameters', {}).values()) if sig else []
                if len(params) < 2:
                    ok = False
            except Exception:
                pass
            return ok, version or 'unknown'
        except Exception:
            return False, 'not installed'

    if not weasyprint:
        return None, 'weasyprint not available'
    pydyf_ok, pydyf_version = _pydyf_compat_status()
    if not pydyf_ok:
        return None, f'pydyf incompatible ({pydyf_version}); requires 0.10.x for weasyprint 57.x'
    try:
        def _safe_url_fetcher(url, timeout=4, ssl_context=None):
            try:
                default_fetcher = getattr(weasyprint, 'default_url_fetcher', None)
                if callable(default_fetcher):
                    return default_fetcher(url, timeout=timeout, ssl_context=ssl_context)
            except Exception:
                pass
            return {'string': b'', 'mime_type': 'text/plain'}

        pdf_bytes = weasyprint.HTML(
            string=html,
            base_url=request.build_absolute_uri('/'),
            url_fetcher=_safe_url_fetcher,
        ).write_pdf()
        return pdf_bytes, ''
    except Exception as exc:
        logger.exception('WeasyPrint: error generando PDF (debug)')
        return None, f'{exc.__class__.__name__}: {exc}'


def pdf_view_guard(view_func):
    """
    Guardrail: evita 500 en endpoints de PDF y devuelve un 503 con mensaje estable.

    Motivo: en producción pueden fallar lecturas de media, imágenes externas, o el motor de PDF.
    El usuario debe ver un error legible y el admin puede activar `?debug=1` para ver el detalle.
    """

    @wraps(view_func)
    def _wrapped(request, *args, **kwargs):
        try:
            return view_func(request, *args, **kwargs)
        except Exception as exc:  # pragma: no cover
            logger.exception('PDF view error: %s', getattr(view_func, '__name__', 'pdf_view'))
            debug = str(getattr(request, 'GET', {}).get('debug') or '').strip().lower() in {'1', 'true', 'yes', 'on'}
            debug_allowed = False
            try:
                user = getattr(request, 'user', None)
                debug_allowed = bool(_is_admin_user(user))
                if not debug_allowed:
                    workspace = _get_active_workspace(request)
                    debug_allowed = bool(workspace and _can_manage_workspace(user, workspace))
            except Exception:
                debug_allowed = False
            if debug and debug_allowed:
                resp = HttpResponse(
                    f'No se pudo generar el PDF. {exc.__class__.__name__}: {exc}',
                    status=503,
                    content_type='text/plain; charset=utf-8',
                )
                resp['Cache-Control'] = 'no-store'
                return resp
            resp = HttpResponse('No se pudo generar el PDF.', status=503, content_type='text/plain; charset=utf-8')
            resp['Cache-Control'] = 'no-store'
            return resp

    return _wrapped


def _build_pdf_nav_urls(request):
    """
    URLs de navegación para PDFs:
    - platform_url: fallback estable (plataforma) cuando no hay referer.
    - pdf_return_url: mejor esfuerzo para volver "atrás" desde el visor PDF.
    """
    platform_path = reverse('platform-overview')
    try:
        platform_url = request.build_absolute_uri(platform_path)
    except Exception:
        platform_url = platform_path

    raw_return = (request.GET.get('return') or '').strip() or (request.META.get('HTTP_REFERER') or '').strip()
    if not raw_return:
        return {'platform_url': platform_url, 'pdf_return_url': platform_url}

    # Permite rutas relativas del mismo dominio.
    if raw_return.startswith('/'):
        try:
            return_url = request.build_absolute_uri(raw_return)
        except Exception:
            return_url = raw_return
        return {'platform_url': platform_url, 'pdf_return_url': return_url}

    parsed = urlparse(raw_return)
    if parsed.scheme in {'http', 'https'}:
        try:
            current_host = (request.get_host() or '').split(':', 1)[0].lower()
            target_host = (parsed.netloc or '').split(':', 1)[0].lower()
            if current_host and target_host and current_host != target_host:
                return {'platform_url': platform_url, 'pdf_return_url': platform_url}
        except Exception:
            return {'platform_url': platform_url, 'pdf_return_url': platform_url}
        return {'platform_url': platform_url, 'pdf_return_url': raw_return}

    return {'platform_url': platform_url, 'pdf_return_url': platform_url}


def resolve_player_photo_static_path(player):
    if not player:
        return ''
    players_dir = Path(settings.BASE_DIR) / 'static' / 'football' / 'images' / 'players'
    if not players_dir.exists():
        return ''

    name_slug = slugify(player.name or '')
    number_value = player.number if player.number is not None else ''
    candidates = []
    candidates.extend(
        [
            f'player-{player.id}.png',
            f'player-{player.id}.jpg',
            f'player-{player.id}.jpeg',
            f'player-{player.id}.webp',
        ]
    )
    if name_slug and number_value != '':
        candidates.extend(
            [
                f'{name_slug}-n{number_value}-final.png',
                f'{name_slug}-n{number_value}.png',
                f'{name_slug}-{number_value}.png',
            ]
        )
    if name_slug:
        candidates.extend(
            [
                f'{name_slug}-final.png',
                f'{name_slug}.png',
                f'{name_slug}.jpg',
                f'{name_slug}.jpeg',
            ]
        )
    if number_value != '':
        candidates.extend(
            [
                f'n{number_value}-{name_slug}.png',
                f'{name_slug}-n{number_value}-cut.png',
                f'{name_slug}-n{number_value}-crop.png',
            ]
        )

    seen = set()
    for filename in candidates:
        if filename in seen:
            continue
        seen.add(filename)
        file_path = players_dir / filename
        if file_path.exists():
            return f'football/images/players/{filename}'
    # Fallback por dorsal (wildcard) SOLO para el equipo principal legacy.
    # En multicategoría (Prebenjamín/Senior), el dorsal se repite y este fallback mezclaba fotos
    # entre equipos. Para categorías no-primary, preferimos mostrar avatar antes que foto errónea.
    try:
        is_primary_team = bool(getattr(getattr(player, 'team', None), 'is_primary', False))
    except Exception:
        is_primary_team = False
    if is_primary_team and number_value != '':
        wildcard_patterns = [
            f'*-n{number_value}-final.*',
            f'*-n{number_value}-cut.*',
            f'*-n{number_value}-crop.*',
            f'*-n{number_value}.*',
        ]
        for pattern in wildcard_patterns:
            for file_path in players_dir.glob(pattern):
                if file_path.is_file():
                    return f'football/images/players/{file_path.name}'
    return ''


def _player_photo_storage_candidates(player):
    if not player:
        return []
    return [
        f'player-photos/player-{player.id}.png',
        f'player-photos/player-{player.id}.jpg',
        f'player-photos/player-{player.id}.jpeg',
        f'player-photos/player-{player.id}.webp',
    ]


def _player_license_storage_candidates(player):
    if not player:
        return []
    base_name = f'player-licenses/player-{player.id}'
    return [
        f'{base_name}.pdf',
        f'{base_name}.jpg',
        f'{base_name}.jpeg',
        f'{base_name}.png',
        f'{base_name}.webp',
    ]


def save_player_license(player, uploaded_license):
    """
    Guarda una licencia federativa del jugador (PDF o imagen).

    - Usa nombre determinista `player-licenses/player-{id}.*`.
    - Limpia versiones previas (extensiones distintas).
    - Normaliza imágenes a JPEG cuando Pillow está disponible.
    """
    if not player or not uploaded_license:
        return ''
    try:
        storage = storages['default']
        if isinstance(storage, FileSystemStorage):
            storage = FileSystemStorage(location=getattr(settings, 'MEDIA_ROOT', None), base_url=getattr(settings, 'MEDIA_URL', '/media/'))

        raw_name = str(getattr(uploaded_license, 'name', '') or '')
        extension = Path(raw_name).suffix.lower()
        content_type = str(getattr(uploaded_license, 'content_type', '') or '').lower()
        is_pdf = extension == '.pdf' or content_type == 'application/pdf'

        if hasattr(uploaded_license, 'seek'):
            uploaded_license.seek(0)
        raw_bytes = uploaded_license.read()
        if not raw_bytes:
            return ''

        target_ext = '.pdf' if is_pdf else (extension if extension in {'.jpg', '.jpeg', '.png', '.webp'} else '.jpg')
        if is_pdf:
            content = ContentFile(raw_bytes)
            target_ext = '.pdf'
        else:
            if Image is None:
                if target_ext not in {'.jpg', '.jpeg', '.png', '.webp'}:
                    return ''
                content = ContentFile(raw_bytes)
            else:
                try:
                    with Image.open(io.BytesIO(raw_bytes)) as img:
                        if ImageOps is not None:
                            try:
                                img = ImageOps.exif_transpose(img)
                            except Exception:
                                pass
                        if img.mode in ('RGBA', 'LA', 'P'):
                            converted = img.convert('RGBA')
                            background = Image.new('RGBA', converted.size, (255, 255, 255, 255))
                            background.alpha_composite(converted)
                            normalized = background.convert('RGB')
                        else:
                            normalized = img.convert('RGB')
                        buffer = io.BytesIO()
                        normalized.save(buffer, format='JPEG', optimize=True, quality=82)
                        content = ContentFile(buffer.getvalue())
                        target_ext = '.jpg'
                except Exception:
                    return ''

        target_name = f'player-licenses/player-{player.id}{target_ext}'
        for candidate in _player_license_storage_candidates(player):
            try:
                if storage.exists(candidate):
                    storage.delete(candidate)
            except Exception:
                logger.exception('No se pudo limpiar una licencia previa del jugador %s', player.id)
        return storage.save(target_name, content)
    except Exception:
        logger.exception('No se pudo guardar la licencia del jugador %s', getattr(player, 'id', None))
        return ''


def resolve_player_license_url(request, player):
    if not player:
        return ''
    try:
        storage = storages['default']
        if isinstance(storage, FileSystemStorage):
            storage = FileSystemStorage(location=getattr(settings, 'MEDIA_ROOT', None), base_url=getattr(settings, 'MEDIA_URL', '/media/'))
        for candidate in _player_license_storage_candidates(player):
            try:
                if storage.exists(candidate):
                    url = reverse('player-license-file', args=[player.id])
                    return request.build_absolute_uri(url) if request is not None else url
            except Exception:
                continue
    except Exception:
        return ''
    return ''


def _build_public_media_url(request, raw_url):
    url = str(raw_url or '').strip()
    if not url:
        return ''
    if request is not None and url.startswith('/'):
        try:
            return request.build_absolute_uri(url)
        except Exception:
            return url
    return url


