@login_required
def pdf_graphic_asset_file(request, asset_id):
    asset = PdfGraphicAsset.objects.select_related('team', 'owner').filter(id=asset_id).first()
    if not asset or not getattr(asset, 'file', None):
        raise Http404('Recurso no disponible')
    # Permisos por alcance: equipo (coach/club) o owner (Task Studio).
    if asset.team_id:
        primary_team = _get_primary_team_for_request(request)
        if not primary_team or int(primary_team.id) != int(asset.team_id):
            return HttpResponse('No tienes permisos para acceder a este recurso.', status=403)
    elif asset.owner_id:
        if int(getattr(request.user, 'id', 0) or 0) != int(asset.owner_id) and not _is_admin_user(request.user):
            return HttpResponse('No tienes permisos para acceder a este recurso.', status=403)
    else:
        return HttpResponse('No tienes permisos para acceder a este recurso.', status=403)
    try:
        asset.file.open('rb')
    except Exception:
        return HttpResponse('No se pudo abrir el recurso.', status=500)
    extension = Path(asset.file.name).suffix.lower()
    content_type = {
        '.png': 'image/png',
        '.jpg': 'image/jpeg',
        '.jpeg': 'image/jpeg',
        '.webp': 'image/webp',
        '.gif': 'image/gif',
        '.svg': 'image/svg+xml',
    }.get(extension, 'application/octet-stream')
    response = FileResponse(asset.file, content_type=content_type)
    response['Content-Disposition'] = f'inline; filename="{Path(asset.file.name).name}"'
    response['Cache-Control'] = 'private, max-age=86400'
    return response


@csrf_exempt
@login_required
@require_POST
def pdf_graphic_asset_upload(request):
    """
    Sube iconos al catálogo de recursos para la pizarra.

    - coach/club: se guardan por Team (primary_team).
    - task_studio: se guardan por owner (usuario del estudio).
    """
    scope_key = str(request.POST.get('scope_key') or '').strip().lower() or 'coach'
    files = list(request.FILES.getlist('assets'))
    if not files:
        return JsonResponse({'ok': False, 'error': 'Selecciona al menos un archivo.'}, status=400)

    team = None
    owner = None
    if scope_key == 'task_studio':
        forbidden = _forbid_if_no_task_studio_access(request.user)
        if forbidden:
            return forbidden
        target_user = _task_studio_target_user(request)
        forbidden = _forbid_if_task_studio_module_disabled(request.user, target_user, 'task_studio_tasks', label='tareas Task Studio')
        if forbidden:
            return forbidden
        owner = target_user
    else:
        if not _can_access_sessions_workspace(request.user):
            return JsonResponse({'ok': False, 'error': 'No tienes permisos.'}, status=403)
        forbidden = _forbid_if_workspace_module_disabled(request, 'sessions', label='sesiones')
        if forbidden:
            return forbidden
        primary_team = _get_primary_team_for_request(request)
        if not primary_team:
            return JsonResponse({'ok': False, 'error': 'Equipo principal no configurado.'}, status=400)
        team = primary_team

    saved = []
    skipped = 0
    errors = 0

    def _already_exists(sha256_value):
        qs = PdfGraphicAsset.objects.filter(sha256=sha256_value)
        if team:
            qs = qs.filter(team=team)
        if owner:
            qs = qs.filter(owner=owner)
        return qs.exists()

    def _store_asset(*, data, title_hint='', ext_hint='png'):
        nonlocal skipped, errors, saved
        if not data:
            errors += 1
            return
        sha = hashlib.sha256(data).hexdigest()
        if _already_exists(sha):
            skipped += 1
            return
        width = None
        height = None
        if Image is not None:
            try:
                with Image.open(io.BytesIO(data)) as img:
                    img.load()
                    w, h = img.size
                    if w and h:
                        width = int(w)
                        height = int(h)
            except Exception:
                width = None
                height = None
        ext = str(ext_hint or 'png').lower().lstrip('.')
        if ext == 'jpeg':
            ext = 'jpg'
        if ext not in {'png', 'jpg', 'webp', 'gif'}:
            ext = 'png'
        filename = f'asset-{sha[:16]}.{ext}'
        try:
            obj = PdfGraphicAsset(
                team=team,
                owner=owner,
                sha256=sha,
                title=str(title_hint or '').strip()[:160],
                width=width,
                height=height,
                source_pdf_name='',
            )
            obj.file.save(filename, ContentFile(data), save=False)
            obj.save()
            saved.append(
                {
                    'id': int(obj.id),
                    'title': str(obj.title or '').strip(),
                    'url': reverse('pdf-graphic-asset-file', args=[obj.id]),
                    'width': int(obj.width or 0),
                    'height': int(obj.height or 0),
                }
            )
        except Exception:
            errors += 1

    def _convert_to_png_if_needed(data, ext):
        if not data:
            return b'', 'png'
        normalized = str(ext or '').lower().lstrip('.')
        if normalized in {'png', 'jpg', 'jpeg', 'webp'}:
            return data, ('jpg' if normalized == 'jpeg' else normalized)
        # TIFF y GIF: convertimos a PNG (mejor compatibilidad en Fabric/canvas).
        if normalized in {'tif', 'tiff', 'gif'}:
            if Image is None:
                return b'', 'png'
            try:
                with Image.open(io.BytesIO(data)) as img:
                    img.load()
                    if getattr(img, 'is_animated', False):
                        try:
                            img.seek(0)
                        except Exception:
                            pass
                    rgba = img.convert('RGBA')
                    out = io.BytesIO()
                    rgba.save(out, format='PNG', optimize=True)
                    return out.getvalue(), 'png'
            except Exception:
                return b'', 'png'
        return b'', 'png'

    def _extract_from_pptx(pptx_bytes):
        nonlocal skipped
        if not pptx_bytes:
            return
        try:
            with zipfile.ZipFile(io.BytesIO(pptx_bytes)) as zf:
                for info in zf.infolist():
                    name = str(info.filename or '')
                    if not name.startswith('ppt/media/'):
                        continue
                    base = name.rsplit('/', 1)[-1]
                    ext = Path(base).suffix.lower().lstrip('.')
                    # EMF/WMF no se pueden rasterizar sin herramientas externas.
                    if ext in {'emf', 'wmf'}:
                        skipped += 1
                        continue
                    try:
                        raw = zf.read(info) or b''
                    except Exception:
                        raw = b''
                    if not raw:
                        continue
                    data, out_ext = _convert_to_png_if_needed(raw, ext)
                    if not data:
                        continue
                    title_hint = Path(base).stem
                    _store_asset(data=data, title_hint=title_hint, ext_hint=out_ext)
        except Exception:
            return

    for uploaded in files[:40]:
        raw_name = str(getattr(uploaded, 'name', '') or '').rsplit('/', 1)[-1]
        raw_name = raw_name[:220]
        suffix = Path(raw_name).suffix.lower()
        try:
            data = uploaded.read() or b''
        except Exception:
            data = b''
        if not data:
            errors += 1
            continue
        if suffix == '.pptx':
            _extract_from_pptx(data)
            continue
        ext = suffix.lstrip('.')
        data2, out_ext = _convert_to_png_if_needed(data, ext)
        if not data2:
            errors += 1
            continue
        _store_asset(data=data2, title_hint=Path(raw_name).stem, ext_hint=out_ext)

    return JsonResponse({'ok': True, 'saved': saved, 'skipped': skipped, 'errors': errors})


def resolve_player_photo_url(request, player):
    resolved_storage_name = ''
    for storage_name in _player_photo_storage_candidates(player):
        try:
            if default_storage.exists(storage_name):
                resolved_storage_name = storage_name
                break
        except Exception:
            logger.exception('No se pudo resolver la foto subida del jugador %s', getattr(player, 'id', ''))
    if resolved_storage_name:
        url = reverse('player-photo-file', args=[player.id])
        version = ''
        # Fuente preferida: campo persistente (evita depender de caché en despliegues multi-instancia).
        try:
            updated_at = getattr(player, 'photo_updated_at', None)
            if updated_at:
                version = str(int(updated_at.timestamp()))
        except Exception:
            version = ''
        if not version:
            # Fallback: caché + metadatos del storage.
            cache_key = f'{PLAYER_PHOTO_VERSION_CACHE_KEY_PREFIX}:{player.id}'
            try:
                cached_version = cache.get(cache_key)
                if cached_version:
                    version = str(int(cached_version))
            except Exception:
                version = ''
            if not version:
                try:
                    modified = default_storage.get_modified_time(resolved_storage_name)
                    if modified:
                        version = str(int(modified.timestamp()))
                except Exception:
                    version = ''
            if not version:
                version = str(int(timezone.now().timestamp()))
            try:
                cache.set(cache_key, int(version), timeout=PLAYER_PHOTO_VERSION_CACHE_SECONDS)
            except Exception:
                pass
        if version:
            joiner = '&' if '?' in url else '?'
            url = f'{url}{joiner}v={version}'
        if request is None:
            return url
        return _build_public_media_url(request, url)
    static_path = resolve_player_photo_static_path(player)
    if not static_path:
        return ''
    if request is None:
        return static(static_path)
    try:
        return request.build_absolute_uri(static(static_path))
    except Exception:
        return static(static_path)


def _file_as_data_uri(file_path):
    try:
        path = Path(file_path)
        if not path.exists() or not path.is_file():
            return ''
        mime_type, _ = mimetypes.guess_type(str(path))
        if not mime_type:
            mime_type = 'image/png'
        encoded = base64.b64encode(path.read_bytes()).decode('ascii')
        return f'data:{mime_type};base64,{encoded}'
    except Exception:
        return ''

def _image_bytes_as_small_data_uri(raw_bytes: bytes, *, mime_type: str = 'image/jpeg', max_width=600, max_height=600, quality=75) -> str:
    if not raw_bytes:
        return ''
    if Image is None:
        encoded = base64.b64encode(raw_bytes).decode('ascii')
        safe_mime = mime_type or 'image/jpeg'
        return f'data:{safe_mime};base64,{encoded}'
    try:
        with Image.open(io.BytesIO(raw_bytes)) as img:
            if ImageOps is not None:
                try:
                    img = ImageOps.exif_transpose(img)
                except Exception:
                    pass
            normalized = img.convert('RGB')
            normalized.thumbnail((int(max_width), int(max_height)))
            buffer = io.BytesIO()
            normalized.save(buffer, format='JPEG', optimize=True, quality=int(quality))
        encoded = base64.b64encode(buffer.getvalue()).decode('ascii')
        return f'data:image/jpeg;base64,{encoded}'
    except Exception:
        encoded = base64.b64encode(raw_bytes).decode('ascii')
        safe_mime = mime_type or 'image/jpeg'
        return f'data:{safe_mime};base64,{encoded}'


def _image_file_as_small_data_uri(file_path, max_width=1200, max_height=800, quality=72):
    """Encode image files as a lightweight JPEG data URI for faster PDF rendering."""
    if Image is None:
        return _file_as_data_uri(file_path)
    try:
        path = Path(file_path)
        if not path.exists() or not path.is_file():
            return ''
        with Image.open(path) as img:
            if ImageOps is not None:
                try:
                    img = ImageOps.exif_transpose(img)
                except Exception:
                    pass
            normalized = img.convert('RGB')
            normalized.thumbnail((int(max_width), int(max_height)))
            buffer = io.BytesIO()
            normalized.save(buffer, format='JPEG', optimize=True, quality=int(quality))
        encoded = base64.b64encode(buffer.getvalue()).decode('ascii')
        return f'data:image/jpeg;base64,{encoded}'
    except Exception:
        return _file_as_data_uri(file_path)


def resolve_team_photo_for_pdf(request):
    default_path = Path(settings.BASE_DIR) / 'static' / 'football' / 'images' / 'team-01.jpg'
    fallback_url = request.build_absolute_uri(static('football/images/team-01.jpg'))
    fallback_data_uri = _image_file_as_small_data_uri(default_path)
    source_path = default_path
    source_url = fallback_url

    primary_team = None
    try:
        primary_team = _get_primary_team_for_request(request)
    except Exception:
        primary_team = None
    if primary_team and getattr(primary_team, 'cover_image', None):
        try:
            source_url = request.build_absolute_uri(primary_team.cover_image.url)
            if getattr(primary_team.cover_image, 'path', None):
                source_path = Path(primary_team.cover_image.path)
        except Exception:
            source_path = default_path
            source_url = fallback_url
        data_uri = _image_file_as_small_data_uri(source_path) or fallback_data_uri
        return {
            'url': source_url or fallback_url,
            'data_uri': data_uri or '',
        }

    carousel_cover = (
        HomeCarouselImage.objects
        .filter(is_active=True)
        .order_by('order', '-created_at', '-id')
        .first()
    )
    if not carousel_cover:
        carousel_cover = (
            HomeCarouselImage.objects
            .order_by('order', '-created_at', '-id')
            .first()
        )
    if carousel_cover and carousel_cover.image:
        try:
            source_url = request.build_absolute_uri(carousel_cover.image.url)
            if getattr(carousel_cover.image, 'path', None):
                source_path = Path(carousel_cover.image.path)
        except Exception:
            source_path = default_path
            source_url = fallback_url

    data_uri = _image_file_as_small_data_uri(source_path) or fallback_data_uri
    return {
        'url': source_url or fallback_url,
        'data_uri': data_uri or '',
    }


def get_competition_total_rounds(primary_team):
    if not primary_team:
        return 0
    group = primary_team.group
    if not group:
        # Club sin competición federativa asociada: estimar por el calendario propio del equipo.
        try:
            matches = _team_match_queryset(primary_team)
        except Exception:
            matches = Match.objects.none()
        round_numbers = []
        try:
            for round_value in matches.values_list('round', flat=True):
                round_num = extract_round_number(round_value)
                if round_num is not None:
                    round_numbers.append(round_num)
        except Exception:
            round_numbers = []
        total_by_rounds = max(round_numbers) if round_numbers else 0
        try:
            count_matches = int(matches.count())
        except Exception:
            count_matches = 0
        return max(total_by_rounds, count_matches, 0)

    matches = Match.objects.filter(group=group)
    round_numbers = []
    for round_value in matches.values_list('round', flat=True):
        round_num = extract_round_number(round_value)
        if round_num is not None:
            round_numbers.append(round_num)
    total_by_rounds = max(round_numbers) if round_numbers else 0
    teams_count = Team.objects.filter(group=group).exclude(id__isnull=True).count()
    total_double_round_robin = max((teams_count - 1) * 2, 0) if teams_count >= 2 else 0
    return max(total_by_rounds, total_double_round_robin)


def _serialize_match_event(event, duplicate=False):
    player = event.player
    return {
        'id': event.id,
        'minute': event.minute,
        'period': event.period,
        'action': event.event_type,
        'zone': event.zone,
        'result': event.result,
        'duplicate': bool(duplicate),
        'player': {
            'id': player.id if player else None,
            'name': player.name if player else 'Equipo',
            'number': (player.number if player and player.number is not None else '--'),
        },
    }


TEAM_ONLY_ACTION_TYPES = {
    'saque de esquina a favor',
    'saque de esquina en contra',
}

TECHNICAL_ROLES = {
    AppUserRole.ROLE_COACH,
    AppUserRole.ROLE_FITNESS,
    AppUserRole.ROLE_GOALKEEPER,
    AppUserRole.ROLE_ANALYST,
    AppUserRole.ROLE_ADMIN,
}

def _has_club_workspace_access(user):
    if not user or not user.is_authenticated:
        return False
    if _get_user_role(user) == AppUserRole.ROLE_PLAYER:
        return False
    return (
        WorkspaceMembership.objects.filter(user=user, workspace__kind=Workspace.KIND_CLUB, workspace__is_active=True).exists()
        or Workspace.objects.filter(owner_user=user, kind=Workspace.KIND_CLUB, is_active=True).exists()
    )


def _get_user_role(user):
    if not user or not user.is_authenticated:
        return None
    role_obj = getattr(user, 'app_role', None)
    role = str(getattr(role_obj, 'role', '') or '').strip() or None
    legacy_map = {
        'admin': AppUserRole.ROLE_ADMIN,
        'player': AppUserRole.ROLE_PLAYER,
        # Legacy: Task Studio deja de existir como producto. Trátalo como rol técnico estándar.
        AppUserRole.ROLE_TASK_STUDIO: AppUserRole.ROLE_COACH,
    }
    normalized_role = legacy_map.get(role, role)
    if normalized_role:
        return normalized_role
    if getattr(user, 'is_superuser', False) or getattr(user, 'is_staff', False):
        return AppUserRole.ROLE_ADMIN
    return None


def _is_admin_user(user):
    role = _get_user_role(user)
    return bool(user and user.is_authenticated and (user.is_superuser or user.is_staff or role == AppUserRole.ROLE_ADMIN))


def _can_edit_match_actions(user):
    if not user or not user.is_authenticated:
        return False
    if _is_admin_user(user):
        return True
    return _get_user_role(user) in TECHNICAL_ROLES or _has_club_workspace_access(user)


def _can_access_sessions_workspace(user):
    role = _get_user_role(user)
    if not user or not user.is_authenticated:
        return False
    if _is_admin_user(user):
        return True
    return role in TECHNICAL_ROLES or _has_club_workspace_access(user)


def _can_access_coach_workspace(user):
    if not user or not user.is_authenticated:
        return False
    if _is_admin_user(user):
        return True
    return _get_user_role(user) in TECHNICAL_ROLES or _has_club_workspace_access(user)


def _can_access_task_studio(user):
    if str(os.getenv('ENABLE_TASK_STUDIO', '1') or '').strip().lower() not in {'1', 'true', 'yes', 'on'}:
        return False
    if not user or not user.is_authenticated:
        return False
    if _is_admin_user(user):
        return True
    role = _get_user_role(user)
    if role not in {AppUserRole.ROLE_TASK_STUDIO, AppUserRole.ROLE_GUEST}:
        return False
    if role == AppUserRole.ROLE_GUEST:
        has_workspace = Workspace.objects.filter(kind=Workspace.KIND_TASK_STUDIO, owner_user=user, is_active=True).exists()
        has_profile = TaskStudioProfile.objects.filter(user=user).exists()
        if not has_workspace and not has_profile:
            # Invitados: si se les ha asignado el rol, deben poder entrar. Si aún no tienen workspace/perfil
            # (por ejemplo tras crearles acceso desde Platform), lo inicializamos sin crear tareas automáticamente.
            try:
                _ensure_task_studio_workspace(user)
            except Exception:
                return False
    profile = TaskStudioProfile.objects.filter(user=user).first()
    if profile and not profile.is_enabled:
        return False
    return True


def _task_studio_target_user(request):
    if not request.user.is_authenticated:
        return None
    selected_user = request.user
    selected_user_id = _parse_int(request.GET.get('user'))
    if _is_admin_user(request.user) and selected_user_id:
        candidate = User.objects.filter(id=selected_user_id).first()
        if candidate:
            selected_user = candidate
    return selected_user


def _task_studio_query_suffix(target_user, current_user):
    if not target_user or not current_user or int(getattr(target_user, 'id', 0) or 0) == int(getattr(current_user, 'id', 0) or 0):
        return ''
    if _is_admin_user(current_user):
        return f'?user={target_user.id}'
    return ''


def _task_studio_profile_for_user(user):
    if not user:
        return None
    role = _get_user_role(user)
    if role == AppUserRole.ROLE_GUEST:
        profile = TaskStudioProfile.objects.filter(user=user).first()
        workspace = Workspace.objects.filter(kind=Workspace.KIND_TASK_STUDIO, owner_user=user).first()
        if not workspace and profile and profile.workspace_id and getattr(profile.workspace, 'kind', None) == Workspace.KIND_TASK_STUDIO:
            workspace = profile.workspace
        if not profile and not workspace:
            workspace = _ensure_task_studio_workspace(user)
            if not workspace:
                return None
            profile = TaskStudioProfile.objects.create(user=user, workspace=workspace)
            return profile
        if not profile:
            profile = TaskStudioProfile.objects.create(user=user, workspace=workspace)
        elif workspace and profile.workspace_id != workspace.id:
            profile.workspace = workspace
            profile.save(update_fields=['workspace'])
        return profile
    workspace = _ensure_task_studio_workspace(user)
    profile, _ = TaskStudioProfile.objects.get_or_create(user=user, defaults={'workspace': workspace})
    if workspace and profile.workspace_id != workspace.id:
        profile.workspace = workspace
        profile.save(update_fields=['workspace'])
    return profile


def _forbid_if_no_task_studio_access(user):
    if _can_access_task_studio(user):
        return None
    return HttpResponse('No tienes permisos para acceder a Task Studio.', status=403)


def _can_access_platform(user):
    return _is_admin_user(user)


def _available_workspaces_for_user(user):
    if not user or not user.is_authenticated:
        return Workspace.objects.none()
    qs = Workspace.objects.select_related('primary_team', 'owner_user').filter(is_active=True)
    if _can_access_platform(user):
        return qs
    return qs.filter(Q(memberships__user=user) | Q(owner_user=user)).distinct()


def _single_club_fallback_enabled() -> bool:
    """
    Modo legacy (monoclub): permite auto-asignar el único club y caer al Team.is_primary.

    Importante para producto comercial/multicliente:
    - Por defecto debe estar desactivado para evitar que un usuario nuevo "herede" datos de otro club.
    - Activarlo explícitamente solo en entornos internos/demo legacy.
    """
    return str(os.getenv('ALLOW_SINGLE_CLUB_FALLBACK', '0') or '').strip().lower() in {'1', 'true', 'yes', 'on'}


def _trial_days_default() -> int:
    try:
        value = int(str(os.getenv('TRIAL_DAYS', '7') or '7').strip())
    except Exception:
        value = 7
    return max(1, min(value, 30))


def _workspace_trial_expires_at_default():
    return timezone.now() + timedelta(days=_trial_days_default())


def _workspace_is_subscription_active(workspace) -> bool:
    if not workspace:
        return False
    status = str(getattr(workspace, 'subscription_status', '') or '').strip().lower()
    return status in {'active'}


def _workspace_is_trial_active(workspace) -> bool:
    if not workspace:
        return False
    status = str(getattr(workspace, 'subscription_status', '') or '').strip().lower()
    if status not in {'trial'}:
        return False
    expires_at = getattr(workspace, 'trial_expires_at', None)
    if not expires_at:
        return True
    try:
        return expires_at > timezone.now()
    except Exception:
        return False


def _workspace_requires_subscription(workspace) -> bool:
    if not workspace or getattr(workspace, 'kind', None) != Workspace.KIND_CLUB:
        return False
    if _workspace_is_subscription_active(workspace):
        return False
    status = str(getattr(workspace, 'subscription_status', '') or '').strip().lower()
    # Si no hay estado, lo tratamos como trial activo por compatibilidad.
    if not status:
        return False
    if status == 'trial':
        # Trial caducado => requiere suscripción.
        return not _workspace_is_trial_active(workspace)
    if _workspace_is_trial_active(workspace):
        return False
    return status in {'expired', 'past_due', 'canceled'}


def _paywall_response(request, *, workspace=None):
    try:
        url = reverse('billing')
        if workspace and getattr(workspace, 'id', None):
            url = f'{url}?workspace={workspace.id}'
    except Exception:
        url = '/billing/'
    return HttpResponse(
        f'Periodo de prueba finalizado. Activa la suscripción para continuar. {url}',
        status=402,
    )


def _get_active_workspace(request):
    if not request or not getattr(request, 'user', None) or not request.user.is_authenticated:
        return None
    available_qs = _available_workspaces_for_user(request.user)
    workspace_id = _parse_int(request.GET.get('workspace'))
    if not workspace_id:
        workspace_id = _parse_int(request.session.get('active_workspace_id'))
    if workspace_id:
        workspace = available_qs.filter(id=workspace_id).first()
        if workspace:
            request.session['active_workspace_id'] = workspace.id
            return workspace
        request.session.pop('active_workspace_id', None)
    if _can_access_platform(request.user):
        # En modo plataforma, si no hay contexto seleccionado devolvemos None.
        # Excepción: si el sistema solo tiene 1 club activo, fijamos ese contexto para que
        # Dashboard/API no caigan en el "equipo primario global" y no se mezclen categorías.
        if _single_club_fallback_enabled():
            try:
                club_ws = list(
                    Workspace.objects
                    .filter(kind=Workspace.KIND_CLUB, is_active=True)
                    .order_by('id')[:2]
                )
                if len(club_ws) == 1:
                    workspace = club_ws[0]
                    request.session['active_workspace_id'] = workspace.id
                    return workspace
            except Exception:
                pass
        return None

    # Producto comercial: nunca auto-asignar un club a un usuario sin haberlo creado/seleccionado.
    # El comportamiento legacy monoclub se mantiene sólo si se habilita explícitamente.
    if _single_club_fallback_enabled():
        try:
            role = _get_user_role(request.user)
            if role and role != AppUserRole.ROLE_PLAYER:
                club_ws = list(Workspace.objects.filter(kind=Workspace.KIND_CLUB, is_active=True).order_by('id')[:2])
                if len(club_ws) == 1:
                    club = club_ws[0]
                    if not WorkspaceMembership.objects.filter(workspace=club, user=request.user).exists() and int(getattr(club, 'owner_user_id', 0) or 0) != int(request.user.id):
                        WorkspaceMembership.objects.get_or_create(
                            workspace=club,
                            user=request.user,
                            defaults={'role': WorkspaceMembership.ROLE_VIEWER},
                        )
        except Exception:
            pass
    fallback_workspace = available_qs.order_by('kind', 'name', 'id').first()
    if fallback_workspace:
        request.session['active_workspace_id'] = fallback_workspace.id
        return fallback_workspace
    # Producto comercial: no auto-crear membresía ni asignar un club "por defecto".
    if _single_club_fallback_enabled():
        role = _get_user_role(request.user)
        if role in {AppUserRole.ROLE_PLAYER, AppUserRole.ROLE_COACH, AppUserRole.ROLE_FITNESS, AppUserRole.ROLE_GOALKEEPER, AppUserRole.ROLE_ANALYST}:
            club_ws = list(Workspace.objects.filter(kind=Workspace.KIND_CLUB, is_active=True).order_by('id')[:2])
            if len(club_ws) == 1:
                workspace = club_ws[0]
                try:
                    WorkspaceMembership.objects.get_or_create(
                        workspace=workspace,
                        user=request.user,
                        defaults={'role': WorkspaceMembership.ROLE_MEMBER},
                    )
                except Exception:
                    pass
                request.session['active_workspace_id'] = workspace.id
                return workspace
    return None


def _workspace_team_links(workspace):
    if not workspace or workspace.kind != Workspace.KIND_CLUB:
        return []
    try:
        links = list(
            WorkspaceTeam.objects.filter(workspace=workspace)
            .select_related('team')
            .order_by('-is_default', 'team__name', 'id')
        )
    except Exception:
        links = []
    # Backfill defensivo: si existe primary_team pero no hay vínculo creado (migración no aplicada),
    # lo creamos sin tocar nada más.
    if not links and getattr(workspace, 'primary_team_id', None):
        try:
            WorkspaceTeam.objects.get_or_create(
                workspace_id=workspace.id,
                team_id=workspace.primary_team_id,
                defaults={'is_default': True},
            )
            links = list(
                WorkspaceTeam.objects.filter(workspace=workspace)
                .select_related('team')
                .order_by('-is_default', 'team__name', 'id')
            )
        except Exception:
            links = []
    return links


def _workspace_team_links_for_user(workspace, user):
    """
    Devuelve los vínculos (WorkspaceTeam) visibles para el usuario dentro del cliente.

    - Owner/Admin (workspace) y admin de plataforma: ven todas las categorías.
    - Miembros normales: si tienen accesos explícitos (WorkspaceTeamAccess) se restringe a ellos.
      Si no tienen accesos, se restringe a la categoría predeterminada del cliente.
    """
    links = _workspace_team_links(workspace)
    if not links or not workspace or workspace.kind != Workspace.KIND_CLUB:
        return links
    if not user or not getattr(user, 'is_authenticated', False):
        return []
    if _can_manage_workspace(user, workspace):
        return links
    try:
        access_rows = list(
            WorkspaceTeamAccess.objects
            .filter(workspace=workspace, user=user)
            .values_list('team_id', 'is_default')
        )
    except Exception:
        access_rows = []
    if access_rows:
        allowed_team_ids = {int(team_id) for (team_id, _) in access_rows if team_id}
        return [link for link in links if int(getattr(link, 'team_id', 0) or 0) in allowed_team_ids]
    default_link = next((link for link in links if getattr(link, 'is_default', False)), None)
    if default_link:
        return [default_link]
    return links[:1]


def _get_active_team_for_request(request):
    """
    Resuelve el equipo/categoría activo para el workspace actual.

    - Por defecto: workspace.primary_team (comportamiento legacy).
    - Si el workspace tiene varias categorías (WorkspaceTeam), se puede cambiar el equipo activo
      en sesión sin afectar al equipo "principal" del cliente.
    """
    workspace = _get_active_workspace(request)
    if workspace and workspace.kind == Workspace.KIND_CLUB:
        links = _workspace_team_links_for_user(workspace, request.user)
        team_lookup = {int(link.team_id): link.team for link in links if getattr(link, 'team_id', None)}
        desired_team_id = _parse_int(request.GET.get('team'))
        mapping = request.session.get('active_team_by_workspace') if request and hasattr(request, 'session') else None
        if not desired_team_id and isinstance(mapping, dict):
            desired_team_id = _parse_int(mapping.get(str(workspace.id)) or mapping.get(workspace.id))

        if desired_team_id and int(desired_team_id) in team_lookup:
            # Permite fijar desde querystring (solo si es válido).
            if request and request.GET.get('team') and hasattr(request, 'session'):
                try:
                    if not isinstance(mapping, dict):
                        mapping = {}
                    mapping[str(workspace.id)] = int(desired_team_id)
                    request.session['active_team_by_workspace'] = mapping
                except Exception:
                    pass
            return team_lookup[int(desired_team_id)]

        # Fallback: default por usuario (si hay acceso marcado como default).
        try:
            if request and getattr(request, 'user', None) and request.user.is_authenticated and workspace:
                preferred_team_id = (
                    WorkspaceTeamAccess.objects
                    .filter(workspace=workspace, user=request.user, is_default=True)
                    .values_list('team_id', flat=True)
                    .first()
                )
                if preferred_team_id and int(preferred_team_id) in team_lookup:
                    return team_lookup[int(preferred_team_id)]
        except Exception:
            pass

        # Fallback: default del workspace, si existe.
        default_link = next((link for link in links if getattr(link, 'is_default', False)), None)
        if default_link and getattr(default_link, 'team', None):
            return default_link.team

        # Fallback: primary_team legacy.
        if getattr(workspace, 'primary_team_id', None):
            return workspace.primary_team

        # Fallback: primer vínculo si existe.
        first_link = links[0].team if links else None
        if first_link:
            return first_link

        # Workspace club sin equipo configurado: NO caer al "equipo primario global" porque
        # mezcla datos entre clientes. El dashboard debe entrar en modo onboarding/demo.
        return None

    # Modo sin workspace / usuario no plataforma: mantenemos el fallback histórico.
    if request and getattr(request, 'user', None) and request.user.is_authenticated and not _can_access_platform(request.user):
        # Producto comercial: si no hay workspace activo, NO devolvemos el equipo global.
        # El usuario debe crear/seleccionar su club desde onboarding.
        if _single_club_fallback_enabled():
            role = _get_user_role(request.user)
            if role == AppUserRole.ROLE_PLAYER:
                return Team.objects.filter(is_primary=True).first()
            if role in TECHNICAL_ROLES or role is None:
                return Team.objects.filter(is_primary=True).first()
        return None
    return Team.objects.filter(is_primary=True).first() if _single_club_fallback_enabled() else None


def _get_primary_team_for_request(request):
    return _get_active_team_for_request(request)


def _get_player_team_for_request(request):
    return _get_active_team_for_request(request)


def _allowed_team_ids_for_request(request):
    """
    Equipos (Team.id) a los que el usuario puede acceder dentro del workspace club activo.

    Si no hay workspace activo (o no es club), devolvemos set vacío para mantener el comportamiento legacy.
    """
    workspace = _get_active_workspace(request)
    if not workspace or workspace.kind != Workspace.KIND_CLUB:
        return set()
    links = _workspace_team_links_for_user(workspace, getattr(request, 'user', None))
    return {int(getattr(link, 'team_id', 0) or 0) for link in links if getattr(link, 'team_id', None)}


def _resolve_player_for_request_scope(request, player_id):
    """
    Resuelve (primary_team, player) de forma robusta para navegación desde listados.

    Caso real: en setups multi-equipo, un link a `/player/<id>/` puede llegar sin `?team=`.
    Si el equipo activo en sesión no coincide, la ficha debe seguir abriendo si el jugador
    pertenece a un equipo permitido dentro del workspace activo.
    """
    primary_team = _get_player_team_for_request(request)
    allowed_team_ids = _allowed_team_ids_for_request(request)
    try:
        if allowed_team_ids and primary_team and int(primary_team.id) not in allowed_team_ids:
            primary_team = None
    except Exception:
        pass

    player = None
    if primary_team:
        player = Player.objects.filter(id=player_id, team=primary_team).first()
    if not player:
        qs = Player.objects.filter(id=player_id).select_related('team')
        if allowed_team_ids:
            qs = qs.filter(team_id__in=allowed_team_ids)
        player = qs.first()
        if player and getattr(player, 'team', None):
            primary_team = player.team
            workspace = _get_active_workspace(request)
            if workspace and workspace.kind == Workspace.KIND_CLUB and hasattr(request, 'session'):
                try:
                    mapping = request.session.get('active_team_by_workspace')
                    if not isinstance(mapping, dict):
                        mapping = {}
                    mapping[str(workspace.id)] = int(player.team_id)
                    request.session['active_team_by_workspace'] = mapping
                except Exception:
                    pass
    return primary_team, player


def _build_active_workspace_badge(request):
    workspace = _get_active_workspace(request)
    if not workspace:
        return None
    subtitle = ''
    if workspace.kind == Workspace.KIND_CLUB:
        active_team = _get_active_team_for_request(request)
        if active_team:
            subtitle = active_team.display_name or active_team.name
        elif workspace.primary_team_id:
            subtitle = workspace.primary_team.display_name or workspace.primary_team.name
    elif workspace.kind == Workspace.KIND_TASK_STUDIO and workspace.owner_user_id:
        subtitle = workspace.owner_user.get_username()
    return {
        'id': workspace.id,
        'name': workspace.name,
        'kind': workspace.kind,
        'kind_label': workspace.get_kind_display(),
        'subtitle': subtitle,
    }


def _unique_workspace_slug(base_text, *, exclude_id=None):
    base_slug = slugify(base_text or 'workspace') or 'workspace'
    candidate = base_slug
    suffix = 2
    qs = Workspace.objects.all()
    if exclude_id:
        qs = qs.exclude(id=exclude_id)
    while qs.filter(slug=candidate).exists():
        candidate = f'{base_slug}-{suffix}'
        suffix += 1
    return candidate


