def _build_demo_dashboard_payload(request):
    today = timezone.localdate()
    user_id = int(getattr(getattr(request, 'user', None), 'id', 0) or 0)
    seed = f"demo:{user_id}:{today.isoformat()}"
    rng = random.Random(seed)

    team_name = "Equipo Demo"
    crest_url = static("football/images/player-avatar.svg")

    team_names = [
        team_name,
        "Atlético Costa",
        "Unión Sierra",
        "Sporting Bahía",
        "Racing Valle",
        "Deportivo Centro",
        "CF Horizonte",
        "CD Marina",
        "Inter Sur",
        "Olympic Norte",
        "Real Puente",
        "Academia 12",
        "Juventud Atlético",
        "Stadium FC",
        "Villa United",
        "Puerto FC",
    ]
    rng.shuffle(team_names)
    if team_name not in team_names:
        team_names[0] = team_name

    rows = []
    for name in team_names:
        played = rng.randint(18, 28)
        wins = rng.randint(0, max(0, played - 2))
        draws = rng.randint(0, max(0, played - wins))
        losses = max(0, played - wins - draws)
        points = wins * 3 + draws
        goal_difference = rng.randint(-18, 24)
        rows.append(
            {
                "team": name,
                "full_name": name,
                "played": played,
                "wins": wins,
                "draws": draws,
                "losses": losses,
                "points": points,
                "goal_difference": goal_difference,
                "crest_url": crest_url,
            }
        )

    rows.sort(key=lambda r: (int(r.get("points") or 0), int(r.get("goal_difference") or 0)), reverse=True)
    standings = []
    for idx, row in enumerate(rows, start=1):
        row = dict(row)
        row["rank"] = idx
        standings.append(row)

    opponents = [row["full_name"] for row in standings if row.get("full_name") != team_name]
    opponent = rng.choice(opponents) if opponents else "Rival Demo"

    weekday = today.weekday()  # Monday=0
    days_until_sat = (5 - weekday) % 7
    if days_until_sat == 0:
        days_until_sat = 7
    match_date = today + timedelta(days=days_until_sat)

    next_match = {
        "status": "next",
        "opponent": {"full_name": opponent, "crest_url": crest_url},
        "date": match_date.isoformat(),
        "time": rng.choice(["10:00", "11:30", "12:00", "17:00", "18:30", "19:00"]),
        "round": str(rng.randint(1, 30)),
        "location": rng.choice(["Campo Municipal", "Ciudad Deportiva", "Estadio Principal"]),
    }

    return {
        "team": {
            "name": team_name,
            "group": "Liga Demo · Grupo A",
            "competition": "Liga Demo",
            "season": str(today.year),
            "corporate_line": "Demo comercial · Datos simulados",
            "crest_url": crest_url,
        },
        "standings": standings,
        "next_match": next_match,
        "standings_meta": {
            "provider": "demo",
            "last_updated": today.strftime("%d/%m/%Y"),
            "group": "Liga Demo",
            "season": str(today.year),
        },
        "team_metrics": {},
        "player_metrics": [],
        "player_cards": [],
        "player_cards_scope": {"type": "demo", "label": "Demo"},
    }


@login_required
def dashboard_data(request):
    """Devuelve los datos principales que alimentarán la home cuerpo técnico/jugador."""
    forbidden = _forbid_if_workspace_module_disabled(request, 'dashboard', label='dashboard')
    if forbidden:
        return forbidden
    # Demo comercial: para usuarios "invitado" con rol viewer en un workspace club,
    # devolvemos datos simulados (sin foto/escudo real, clasificación y próximo rival ficticios).
    try:
        if _is_demo_mode_for_request(request):
            return JsonResponse(_build_demo_dashboard_payload(request))
    except Exception:
        pass
    primary_team = _get_primary_team_for_request(request)
    if not primary_team:
        # Workspace sin configurar: devolvemos datos simulados (avatar + clasificación random)
        # y permitimos que la UI guíe al onboarding.
        workspace = _get_active_workspace(request)
        if not workspace and request and getattr(request, 'user', None) and request.user.is_authenticated and not _can_access_platform(request.user):
            return JsonResponse(_build_first_run_dashboard_payload(request))
        if workspace and _workspace_needs_setup(workspace):
            return JsonResponse(_build_setup_dashboard_payload(request, workspace))
        return JsonResponse({'error': 'No hay equipo principal configurado'}, status=400)

    workspace = _get_active_workspace(request)
    setup_banner = {}
    # Guardrail UX: evita mostrar rival/clasificación de otra categoría si comparten grupo/competición.
    # Caso real: Prebenjamín creado clonando Senior y se queda con el mismo Group/Universo ID.
    try:
        if workspace and workspace.kind == Workspace.KIND_CLUB and getattr(primary_team, 'group_id', None):
            group_id = int(primary_team.group_id)
            primary_group_external = str(getattr(getattr(primary_team, 'group', None), 'external_id', '') or '').strip()
            context_for_team = None
            try:
                context_for_team = WorkspaceCompetitionContext.objects.filter(workspace=workspace, team=primary_team).first()
            except Exception:
                context_for_team = None
            primary_context_key = str(getattr(context_for_team, 'external_group_key', '') or '').strip()
            primary_competition_key = primary_context_key or primary_group_external
            links = list(
                WorkspaceTeam.objects
                .filter(workspace=workspace)
                .select_related('team')
            )
            other_team_ids = [
                int(getattr(getattr(link, 'team', None), 'id', 0) or 0)
                for link in links
                if getattr(link, 'team_id', None) and int(getattr(link, 'team_id', 0) or 0) != int(primary_team.id)
            ]
            context_map = {}
            if other_team_ids:
                try:
                    rows = WorkspaceCompetitionContext.objects.filter(workspace=workspace, team_id__in=other_team_ids)
                    context_map = {int(row.team_id): row for row in rows if getattr(row, 'team_id', None)}
                except Exception:
                    context_map = {}
            conflicts = []
            for link in links:
                team = getattr(link, 'team', None)
                if not team or int(getattr(team, 'id', 0) or 0) == int(primary_team.id):
                    continue
                other_group_id = getattr(team, 'group_id', None)
                other_group_external = str(getattr(getattr(team, 'group', None), 'external_id', '') or '').strip()
                other_context = context_map.get(int(getattr(team, 'id', 0) or 0))
                other_context_key = str(getattr(other_context, 'external_group_key', '') or '').strip()
                other_competition_key = other_context_key or other_group_external
                group_id_collision = bool(other_group_id and int(other_group_id) == group_id)
                key_collision = bool(primary_competition_key and other_competition_key and primary_competition_key == other_competition_key)
                if group_id_collision or key_collision:
                    conflicts.append(team)
            if conflicts:
                category = str(getattr(primary_team, 'category', '') or '').strip()
                conflict_labels = []
                for item in conflicts[:3]:
                    c = str(getattr(item, 'category', '') or '').strip() or 'Sin categoría'
                    conflict_labels.append(c)
                conflict_hint = ', '.join(conflict_labels)
                team_name = str(getattr(primary_team, 'display_name', '') or getattr(primary_team, 'name', '') or '').strip() or 'Equipo'
                if category and category.lower() not in team_name.lower():
                    team_name = f'{team_name} · {category}'
                fix_url = reverse('admin-page') + '?tab=teams'
                if _can_access_platform(request.user):
                    # Admin Platform puede preferir arreglarlo desde Platform/club detalle.
                    fix_url = reverse('admin-page') + '?tab=teams'
                payload = {
                    'team': {
                        'name': primary_team.name,
                        'group': '',
                        'competition': '',
                        'season': '',
                        'corporate_line': '',
                        'crest_url': resolve_team_crest_url(request, primary_team, sync=False),
                    },
                    'standings': [],
                    'next_match': None,
                    'standings_meta': {
                        'provider': '',
                        'last_updated': '',
                        'group': '',
                        'season': '',
                    },
                    'team_metrics': {},
                    'player_metrics': [],
                    'player_cards': compute_player_cards(primary_team),
                    'player_cards_scope': {'type': 'global', 'label': 'Jugador · datos La Preferente'},
                    'setup_required': True,
                    'setup_url': fix_url,
                    'setup_message_title': 'Categoría mezclada con otra competición',
                    'setup_message_body': (
                        f'Esta categoría comparte el mismo grupo/competición que otra ({conflict_hint}). '
                        'Así se mezclan rivales/partidos. Entra en Admin → Categorías y asigna el Universo ID de grupo correcto.'
                    ),
                    'setup_action_label': 'Arreglar ahora',
                }
                return JsonResponse(payload)
    except Exception:
        pass

    group = primary_team.group
    if not group:
        # En multicategoría, una categoría puede existir sin grupo todavía.
        # Devolvemos payload vacío para que la UI no se rompa y el admin pueda completar la configuración.
        player_cards = compute_player_cards(primary_team)
        payload = {
            'team': {
                'name': primary_team.name,
                'group': '',
                'competition': '',
                'season': '',
                'corporate_line': '',
                'crest_url': resolve_team_crest_url(request, primary_team, sync=False),
            },
            'standings': [],
            'next_match': None,
            'standings_meta': {
                'provider': '',
                'last_updated': '',
                'group': '',
                'season': '',
            },
            'team_metrics': {},
            'player_metrics': [],
            'player_cards': player_cards,
            'player_cards_scope': {'type': 'global', 'label': 'Jugador · datos La Preferente'},
        }
        return JsonResponse(payload)

    force_fresh = str(request.GET.get('fresh') or '').strip().lower() in {'1', 'true', 'yes', 'on'}
    cache_key = _dashboard_cache_key(primary_team.id)
    if not force_fresh:
        cached_payload = cache.get(cache_key)
        if isinstance(cached_payload, dict):
            # Autorreparación: si en caché se guardó un próximo rival nulo (p.ej. porque todavía no
            # existía el match en BD o falló una extracción externa), intentamos reconstruirlo sin
            # coste (solo DB) y actualizar la caché.
            try:
                cached_next = cached_payload.get('next_match')
                if not _next_match_payload_is_reliable(cached_next):
                    repaired_next = load_preferred_next_match_payload(primary_team=primary_team) or (
                        get_next_match(primary_team, group, allow_external_fetch=False) if group else None
                    )
                    if _next_match_payload_is_reliable(repaired_next):
                        cached_payload = dict(cached_payload)
                        cached_payload['next_match'] = repaired_next
                        cache.set(cache_key, cached_payload, DASHBOARD_CACHE_SECONDS)
            except Exception:
                pass
            return JsonResponse(cached_payload)

    refresh_roster_on_load = str(
        os.getenv('PREFERENTE_ROSTER_REFRESH_ON_LOAD', '0')
    ).strip().lower() in {'1', 'true', 'yes', 'on'}
    if refresh_roster_on_load:
        try:
            refresh_primary_roster_cache(primary_team, force=False)
        except Exception:
            pass

    dashboard_allow_auto_sync = str(os.getenv('DASHBOARD_ALLOW_AUTO_SYNC', '0') or '').strip().lower() in {
        '1',
        'true',
        'yes',
        'on',
    }
    competition_payload = _competition_payload_for_team(workspace, primary_team, allow_auto_sync=dashboard_allow_auto_sync)
    context = _bootstrap_workspace_competition_context(workspace, primary_team=primary_team) if workspace else None
    provider_key = str(getattr(context, 'provider', '') or '').strip().lower()
    # Debug opcional (solo admin): ayuda a detectar mezclas de contexto (Senior vs Prebenjamín).
    debug_payload = None
    try:
        if _is_admin_user(request.user) and str(request.GET.get('debug') or '').strip().lower() in {'1', 'true', 'yes', 'on'}:
            debug_payload = {
                'workspace_id': int(getattr(workspace, 'id', 0) or 0) if workspace else None,
                'team_id': int(primary_team.id),
                'team_category': str(getattr(primary_team, 'category', '') or '').strip(),
                'team_group_id': int(getattr(primary_team, 'group_id', 0) or 0) if getattr(primary_team, 'group_id', None) else None,
                'team_group_external_id': str(getattr(getattr(primary_team, 'group', None), 'external_id', '') or '').strip(),
                'context_provider': provider_key,
                'context_external_group_key': str(getattr(context, 'external_group_key', '') or '').strip() if context else '',
                'context_external_team_key': str(getattr(context, 'external_team_key', '') or '').strip() if context else '',
            }
    except Exception:
        debug_payload = None
    standings_group = _latest_standings_group_for_team(primary_team) or primary_team.group
    standings_last_updated = _team_standings_last_updated(standings_group)
    standings = _enrich_standings_rows_with_crests(competition_payload.get('standings') or [])
    next_match = _enrich_next_match_payload_with_crests(competition_payload.get('next_match') or {}, standings) or {}
    if not next_match:
        next_match = _enrich_next_match_payload_with_crests(
            load_preferred_next_match_payload(primary_team=primary_team) or get_next_match(primary_team, group, allow_external_fetch=False),
            standings,
        )
    # Si detectamos un próximo partido fiable, lo persistimos como Match para que nunca dependa de
    # ficheros locales ni de providers externos (Render / múltiples instancias).
    if _next_match_payload_is_reliable(next_match):
        try:
            _upsert_match_from_next_match_payload(primary_team, next_match)
        except Exception:
            pass
    convocation_next_match = _build_next_match_from_convocation(primary_team)
    # Product rule: Home prioritizes Convocatoria only when it provides a reliable scheduled match.
    if _next_match_payload_is_reliable(convocation_next_match):
        next_match = _enrich_next_match_payload_with_crests(convocation_next_match, standings)
    # Guardrail anti-mezcla: si el próximo rival NO viene de convocatoria manual y no existe en la
    # clasificación visible, evitamos mostrarlo (Senior vs Prebenjamín con IDs cruzados).
    try:
        if next_match and provider_key == WorkspaceCompetitionContext.PROVIDER_UNIVERSO and standings:
            source_key = str((next_match or {}).get('source') or '').strip().lower()
            opponent_name = _payload_opponent_name(next_match)
            if source_key not in {'convocation-manual'} and opponent_name and not _opponent_in_standings_rows(opponent_name, standings):
                next_match = None
                # Señal UX para que el admin corrija el Universo ID del grupo/competición.
                fix_url = reverse('club-onboarding')
                if _can_manage_workspace(request.user, workspace) or _can_access_platform(request.user):
                    fix_url = reverse('admin-page') + '?tab=teams'
                debug_payload = dict(debug_payload or {})
                debug_payload['next_match_guardrail'] = {
                    'reason': 'opponent_not_in_standings',
                    'opponent': opponent_name,
                }
                setup_banner = {
                    'setup_required': True,
                    'setup_url': fix_url,
                    'setup_message_title': 'Próximo rival no coincide con esta categoría',
                    'setup_message_body': (
                    'La app detectó que el rival proviene de una competición/grupo distinto al de la clasificación actual. '
                    'Revisa el “Universo ID de grupo” del equipo para evitar mezclar datos (Senior vs Prebenjamín).'
                    ),
                    'setup_action_label': 'Revisar configuración',
                }
    except Exception:
        pass
    # Evitar mostrar el "último partido" como si fuera el próximo rival.
    if not _next_match_payload_is_reliable(next_match):
        next_match = None
    team_metrics = compute_team_metrics(primary_team)
    player_metrics = compute_player_metrics(primary_team)
    player_cards = compute_player_cards(primary_team)
    player_cards_scope = {'type': 'global', 'label': 'Jugador · datos La Preferente'}
    competition_name = ''
    season_name = ''
    try:
        competition_name = str(getattr(getattr(getattr(group, 'season', None), 'competition', None), 'name', '') or '').strip()
        season_name = str(getattr(getattr(group, 'season', None), 'name', '') or '').strip()
    except Exception:
        competition_name = ''
        season_name = ''
    group_label = group.name
    if season_name and season_name.lower() not in str(group_label or '').lower():
        group_label = f'{season_name} · {group_label}'
    elif competition_name and competition_name.lower() not in str(group_label or '').lower():
        group_label = f'{competition_name} · {group_label}'
    corporate_parts = [competition_name, season_name, group.name]
    corporate_line = ' · '.join([part for part in corporate_parts if str(part or '').strip()])

    payload = {
        'team': {
            'name': primary_team.name,
            'category': str(getattr(primary_team, 'category', '') or '').strip(),
            'group': group_label,
            'competition': competition_name,
            'season': season_name,
            'corporate_line': corporate_line,
            'crest_url': resolve_team_crest_url(request, primary_team, sync=False),
        },
        'standings': standings,
        'next_match': next_match,
        'standings_meta': {
            'provider': provider_key,
            'last_updated': standings_last_updated.isoformat() if standings_last_updated else '',
            'group': str(getattr(standings_group, 'name', '') or ''),
            'season': str(getattr(getattr(standings_group, 'season', None), 'name', '') or ''),
        },
        'team_metrics': team_metrics,
        'player_metrics': player_metrics,
        'player_cards': player_cards,
        'player_cards_scope': player_cards_scope,
    }
    if isinstance(setup_banner, dict) and setup_banner and not payload.get('setup_required'):
        payload.update(setup_banner)
    # Checklist de activación (simplifica adopción del producto).
    try:
        active_match = get_active_match(primary_team)
    except Exception:
        active_match = None
    try:
        convocation_record = get_current_convocation_record(primary_team)
    except Exception:
        convocation_record = None
    setup_checklist = _build_team_setup_checklist(
        request,
        workspace,
        primary_team,
        match=active_match,
        convocation_record=convocation_record,
    ) if workspace and workspace.kind == Workspace.KIND_CLUB else []
    if isinstance(setup_checklist, list) and setup_checklist:
        payload['setup_checklist'] = setup_checklist
        try:
            required_pending = [
                item for item in setup_checklist
                if bool(item.get('required')) and not bool(item.get('ok'))
            ]
            if required_pending and not payload.get('setup_required'):
                payload['setup_required'] = True
                payload['setup_url'] = reverse('club-onboarding')
                payload['setup_message_title'] = 'Checklist de activación'
                payload['setup_message_body'] = 'Completa estos pasos para evitar mezclas de datos y activar KPIs/PDFs.'
                payload['setup_action_label'] = 'Abrir configuración'
        except Exception:
            pass
    if debug_payload:
        payload['debug'] = debug_payload
    cache.set(cache_key, payload, DASHBOARD_CACHE_SECONDS)
    response = JsonResponse(payload)
    if force_fresh:
        response['Cache-Control'] = 'no-store'
    return response


@ensure_csrf_cookie
def dashboard_page(request):
    host = str(request.get_host() or '').split(':', 1)[0].strip().lower()
    app_hosts = [
        h.strip().lower()
        for h in (os.getenv('APP_HOSTS') or 'app.segundajugada.es,app.segundajugada.com').split(',')
        if h.strip()
    ]
    landing_hosts = [
        h.strip().lower()
        for h in (os.getenv('LANDING_HOSTS') or 'segundajugada.es,www.segundajugada.es,segundajugada.com,www.segundajugada.com').split(',')
        if h.strip()
    ]
    # Separación de dominios:
    # - `segundajugada.es` muestra siempre la landing (aunque haya sesión iniciada)
    # - `app.segundajugada.es` entra a la app (si no hay sesión, manda al login)
    if host in landing_hosts:
        return product_landing_page(request)
    if not request.user.is_authenticated:
        if host in app_hosts or host.startswith('app.'):
            login_url = reverse('login')
            next_path = request.get_full_path() or '/'
            if next_path and next_path != '/':
                return redirect(f'{login_url}?next={quote(next_path)}')
            return redirect(login_url)
        # Dominio público (o Render): la home funciona como landing comercial cuando no hay sesión.
        return product_landing_page(request)
    current_role = _get_user_role(request.user)
    # Compatibilidad: usuarios legacy sin AppUserRole no deben caer como "player" por defecto,
    # porque suelen ser internos (staff) y eso rompe el acceso a la plataforma.
    if current_role is None:
        current_role = AppUserRole.ROLE_COACH
    # Product rule: si el usuario tiene acceso a Platform, la entrada por defecto en app.*
    # debe ser Platform (para elegir cliente/contexto). Se puede forzar el home club con `?home=club`.
    if _can_access_platform(request.user) and (host in app_hosts or host.startswith('app.')):
        forced_home = str(request.GET.get('home') or '').strip().lower()
        if forced_home != 'club':
            return redirect('platform-overview')
    if current_role == AppUserRole.ROLE_PLAYER:
        primary_team = _get_primary_team_for_request(request)
        current_player = _resolve_player_for_user(request.user, primary_team)
        if current_player:
            return redirect('player-detail', player_id=current_player.id)
        return redirect('player-dashboard')
    active_workspace_obj = _get_active_workspace(request)
    # Producto comercial: si el usuario tiene sesión pero no tiene club/workspace aún,
    # lo llevamos directamente a onboarding (creación del club desde la app).
    if request.user.is_authenticated and not _can_access_platform(request.user) and not active_workspace_obj:
        try:
            return redirect('club-onboarding')
        except Exception:
            return redirect('/onboarding/')
    if active_workspace_obj and not _can_access_platform(request.user):
        target_url = _workspace_entry_url(active_workspace_obj, user=request.user)
        target_path = str(target_url or '').split('?', 1)[0]
        if target_path != request.path:
            return redirect(target_url)

    sources = list(ScrapeSource.objects.filter(is_active=True))
    active_items = list(HomeCarouselImage.objects.filter(is_active=True).order_by('order', '-created_at', '-id'))
    all_items = list(HomeCarouselImage.objects.order_by('order', '-created_at', '-id'))
    candidates = active_items if active_items else all_items
    hero_image_candidates = [reverse('home-carousel-image-file', args=[item.id]) for item in candidates if item.image]
    role_labels = dict(AppUserRole.ROLE_CHOICES)
    can_access_admin = _is_admin_user(request.user)
    can_access_sessions = _can_access_sessions_workspace(request.user)
    can_access_platform = _can_access_platform(request.user)
    workspace_links = _workspace_links_for_user(request.user)
    active_workspace = _build_active_workspace_badge(request)
    demo_mode = False
    setup_mode = False
    setup_workspace_name = ''
    try:
        demo_mode = _is_demo_mode_for_request(request)
    except Exception:
        demo_mode = False
    try:
        setup_mode = bool(active_workspace_obj and _workspace_needs_setup(active_workspace_obj))
        if setup_mode:
            setup_workspace_name = str(getattr(active_workspace_obj, 'name', '') or '').strip()
    except Exception:
        setup_mode = False
        setup_workspace_name = ''
    if demo_mode:
        # Demo comercial: no usamos fotos reales ni carrusel.
        hero_image_candidates = []
    if setup_mode:
        # Onboarding: tampoco usar fotos reales (evita mostrar Benagalbón por defecto).
        hero_image_candidates = []
    dashboard_focus_items = []
    dashboard_pending_items = []
    dashboard_pending_cards = []
    dashboard_recent_activity = []
    primary_team = _get_primary_team_for_request(request)
    if primary_team and getattr(primary_team, 'cover_image', None):
        try:
            # Servimos la portada a través de la app para evitar 403 de S3 cuando el bucket no es público.
            updated_at = getattr(primary_team, 'cover_updated_at', None)
            version = str(int(updated_at.timestamp())) if updated_at else str(int(timezone.now().timestamp()))
            cover_url = f'{reverse("team-cover-image-file", args=[primary_team.id])}?v={version}'
            if not demo_mode:
                hero_image_candidates = [cover_url] + list(hero_image_candidates or [])
        except Exception:
            pass
    if primary_team and current_role not in {AppUserRole.ROLE_TASK_STUDIO, AppUserRole.ROLE_GUEST}:
        # Nota: la UI de dashboard carga el contenido principal por JS vía `/api/dashboard/`.
        # Evitamos calcular aquí KPIs/pending/recent (queries costosas) para prevenir timeouts/502.
        pass
    forbidden = _forbid_if_workspace_module_disabled(request, 'dashboard', label='dashboard')
    if forbidden:
        return forbidden
    return render(
        request,
        'football/dashboard.html',
        {
            'scrape_sources': sources,
            'hero_image_candidates': hero_image_candidates,
            'demo_mode': demo_mode,
            'setup_mode': setup_mode,
            'setup_workspace_name': setup_workspace_name,
            'current_role': current_role,
            'current_role_label': role_labels.get(current_role, 'Jugador'),
            'can_access_admin': can_access_admin,
            'can_access_sessions': can_access_sessions,
            'can_access_platform': can_access_platform,
            'workspace_links': workspace_links,
            'active_workspace': active_workspace,
            'dashboard_focus_items': dashboard_focus_items,
            'dashboard_pending_items': dashboard_pending_items,
            'dashboard_pending_cards': dashboard_pending_cards,
            'dashboard_recent_activity': dashboard_recent_activity,
        },
    )


def _public_signup_enabled() -> bool:
    return str(os.getenv('ENABLE_PUBLIC_SIGNUP', '0') or '').strip().lower() in {'1', 'true', 'yes', 'on'}


def _redirect_to_app_host_if_landing(request, *, path: str):
    host = str(getattr(request, 'get_host', lambda: '')() or '').split(':', 1)[0].strip().lower()
    landing_hosts = [
        h.strip().lower()
        for h in (os.getenv('LANDING_HOSTS') or 'segundajugada.es,www.segundajugada.es,segundajugada.com,www.segundajugada.com').split(',')
        if h.strip()
    ]
    if host not in landing_hosts:
        return None
    target_host = host[4:] if host.startswith('www.') else host
    app_url = f'https://app.{target_host}'
    return redirect(f'{app_url}{path}')


def public_signup_page(request):
    if not _public_signup_enabled():
        raise Http404('Signup deshabilitado')
    if request and getattr(request, 'user', None) and request.user.is_authenticated:
        return redirect('dashboard-home')
    redirect_response = _redirect_to_app_host_if_landing(request, path='/signup/')
    if redirect_response:
        return redirect_response

    error = ''
    form = {
        'club_name': (request.POST.get('club_name') or '').strip() if request.method == 'POST' else '',
        'email': (request.POST.get('email') or '').strip().lower() if request.method == 'POST' else '',
    }
    if request.method == 'POST':
        club_name = _sanitize_task_text((request.POST.get('club_name') or '').strip(), multiline=False, max_len=160)
        email = re.sub(r'\s+', '', str(request.POST.get('email') or '').strip()).lower()[:190]
        password = (request.POST.get('password') or '').strip()
        password_confirm = (request.POST.get('password_confirm') or '').strip()
        try:
            if not club_name:
                raise ValueError('El nombre del club es obligatorio.')
            if not email or '@' not in email:
                raise ValueError('Email inválido.')
            if not password or len(password) < 6:
                raise ValueError('La contraseña debe tener al menos 6 caracteres.')
            if password != password_confirm:
                raise ValueError('Las contraseñas no coinciden.')
            validate_password(password)
            username_seed = email.split('@', 1)[0]
            username = slugify(username_seed or '').replace('-', '.').strip('.')[:150] or 'club'
            base = username
            suffix = 2
            while User.objects.filter(username__iexact=username).exists():
                username = f'{base}{suffix}'
                suffix += 1
            with transaction.atomic():
                user = User.objects.create_user(
                    username=username,
                    email=email,
                    password=password,
                    is_active=True,
                )
                AppUserRole.objects.update_or_create(user=user, defaults={'role': AppUserRole.ROLE_COACH})
                modules = _workspace_default_modules(Workspace.KIND_CLUB)
                # Producto comercial: el cliente ve todos los módulos desde el día 0 (vacíos),
                # y construye su club desde la app.
                enabled_modules = {key: True for key in modules.keys()}
                workspace = Workspace.objects.create(
                    name=club_name,
                    slug=_unique_workspace_slug(club_name),
                    kind=Workspace.KIND_CLUB,
                    owner_user=user,
                    enabled_modules=enabled_modules,
                    subscription_status='trial',
                    trial_expires_at=_workspace_trial_expires_at_default(),
                    is_active=True,
                )
                WorkspaceMembership.objects.update_or_create(
                    workspace=workspace,
                    user=user,
                    defaults={'role': WorkspaceMembership.ROLE_OWNER},
                )
            try:
                backend = settings.AUTHENTICATION_BACKENDS[0] if getattr(settings, 'AUTHENTICATION_BACKENDS', None) else None
                if backend:
                    auth_login(request, user, backend=backend)
                else:
                    auth_login(request, user)
            except Exception:
                pass
            try:
                request.session['active_workspace_id'] = workspace.id
            except Exception:
                pass
            return redirect('club-onboarding')
        except ValueError as exc:
            error = str(exc)
        except DjangoValidationError as exc:
            error = ' '.join(exc.messages) or 'Datos inválidos.'
        except Exception:
            error = 'No se pudo crear la cuenta.'

    return render(
        request,
        'registration/signup.html',
        {
            'error': error,
            'form': form,
        },
    )


@login_required
def club_onboarding_page(request):
    redirect_response = _redirect_to_app_host_if_landing(request, path='/onboarding/')
    if redirect_response:
        return redirect_response
    workspace = _get_active_workspace(request)
    if not workspace:
        # Primer arranque: crear el club desde la app (sin Platform).
        workspace = None
    elif workspace.kind != Workspace.KIND_CLUB:
        return HttpResponse('El workspace activo no es de tipo club.', status=400)
    if workspace and not _can_manage_workspace(request.user, workspace):
        return HttpResponse('No tienes permisos para configurar este workspace.', status=403)

    primary_team = getattr(workspace, 'primary_team', None) if workspace else None
    competition_context = None
    if primary_team:
        competition_context = _bootstrap_workspace_competition_context(workspace, primary_team=primary_team)

    error = ''
    success = ''
    universo_candidates = []
    auto_notice_parts = []
    form = {
        'workspace_name': str(getattr(workspace, 'name', '') or '').strip() if workspace else '',
        'team_name': str(getattr(primary_team, 'name', '') or '').strip() if primary_team else (str(getattr(workspace, 'name', '') or '').strip() if workspace else ''),
        'preferente_url': str(getattr(primary_team, 'preferente_url', '') or '').strip() if primary_team else '',
        'provider': str(getattr(competition_context, 'provider', '') or WorkspaceCompetitionContext.PROVIDER_UNIVERSO).strip() if competition_context else WorkspaceCompetitionContext.PROVIDER_UNIVERSO,
        'external_group_key': str(getattr(competition_context, 'external_group_key', '') or '').strip() if competition_context else '',
        'external_source_url': str(getattr(competition_context, 'external_source_url', '') or '').strip() if competition_context else '',
        'replace_roster': False,
    }
    if request.method == 'POST':
        action = str(request.POST.get('action') or 'save_and_sync').strip().lower()
        workspace_name = _sanitize_task_text((request.POST.get('workspace_name') or '').strip(), multiline=False, max_len=160)
        team_name = _sanitize_task_text((request.POST.get('team_name') or '').strip(), multiline=False, max_len=150)
        preferente_url = str(request.POST.get('preferente_url') or '').strip()[:600]
        provider = str(request.POST.get('provider') or WorkspaceCompetitionContext.PROVIDER_UNIVERSO).strip()
        external_group_key = str(request.POST.get('external_group_key') or '').strip()
        external_source_url = str(request.POST.get('external_source_url') or '').strip()
        replace_roster = str(request.POST.get('replace_roster') or '').lower() in {'1', 'true', 'on', 'yes'}
        form.update(
            {
                'workspace_name': workspace_name,
                'team_name': team_name,
                'preferente_url': preferente_url,
                'provider': provider,
                'external_group_key': external_group_key,
                'external_source_url': external_source_url,
                'replace_roster': replace_roster,
            }
        )
        try:
            if not workspace_name:
                raise ValueError('El nombre del club es obligatorio.')
            if not team_name:
                raise ValueError('El nombre del equipo es obligatorio.')
            if provider not in {choice[0] for choice in WorkspaceCompetitionContext.PROVIDER_CHOICES}:
                provider = WorkspaceCompetitionContext.PROVIDER_UNIVERSO
            with transaction.atomic():
                if not workspace:
                    # Crear el club desde la app: owner + membresía owner + módulos completos.
                    enabled_modules = _workspace_default_modules(Workspace.KIND_CLUB)
                    workspace = Workspace.objects.create(
                        name=workspace_name,
                        slug=_unique_workspace_slug(workspace_name),
                        kind=Workspace.KIND_CLUB,
                        owner_user=request.user,
                        enabled_modules={key: True for key in enabled_modules.keys()},
                        subscription_status='trial',
                        trial_expires_at=_workspace_trial_expires_at_default(),
                        is_active=True,
                    )
                    WorkspaceMembership.objects.update_or_create(
                        workspace=workspace,
                        user=request.user,
                        defaults={'role': WorkspaceMembership.ROLE_OWNER},
                    )
                    try:
                        request.session['active_workspace_id'] = workspace.id
                    except Exception:
                        pass
                if str(getattr(workspace, 'name', '') or '').strip() != workspace_name:
                    workspace.name = workspace_name
                    workspace.save(update_fields=['name', 'updated_at'])
                # Backfill: si venía de un workspace antiguo sin trial, lo inicializamos.
                try:
                    if not getattr(workspace, 'trial_expires_at', None):
                        workspace.trial_expires_at = _workspace_trial_expires_at_default()
                    if not str(getattr(workspace, 'subscription_status', '') or '').strip():
                        workspace.subscription_status = 'trial'
                    workspace.save(update_fields=['trial_expires_at', 'subscription_status', 'updated_at'])
                except Exception:
                    pass
                primary_team = getattr(workspace, 'primary_team', None)
                if not primary_team:
                    primary_team = Team.objects.create(
                        name=team_name,
                        slug=_unique_team_slug(team_name),
                        short_name=team_name[:60],
                        is_primary=False,
                    )
                    workspace.primary_team = primary_team
                    workspace.save(update_fields=['primary_team', 'updated_at'])
                elif str(getattr(primary_team, 'name', '') or '').strip() != team_name:
                    primary_team.name = team_name
                    primary_team.short_name = team_name[:60]
                    primary_team.save(update_fields=['name', 'short_name'])

                if preferente_url and preferente_url != str(getattr(primary_team, 'preferente_url', '') or '').strip():
                    primary_team.preferente_url = preferente_url
                    primary_team.save(update_fields=['preferente_url'])

                WorkspaceTeam.objects.get_or_create(
                    workspace=workspace,
                    team=primary_team,
                    defaults={'is_default': True},
                )
                WorkspaceTeamAccess.objects.update_or_create(
                    workspace=workspace,
                    team=primary_team,
                    user=request.user,
                    defaults={'is_default': True},
                )

                external_team_key = ''
                if provider == WorkspaceCompetitionContext.PROVIDER_UNIVERSO and external_source_url:
                    external_team_key = _parse_universo_team_code_from_url(external_source_url)

                competition_context = _bootstrap_workspace_competition_context(
                    workspace,
                    primary_team=primary_team,
                    provider=provider,
                    external_group_key=external_group_key,
                    external_team_key=external_team_key,
                    external_team_name=str(team_name or '').strip(),
                    external_source_url=external_source_url,
                    auto_sync_enabled=True,
                )
                if competition_context:
                    competition_context.sync_status = WorkspaceCompetitionContext.STATUS_PENDING
                    competition_context.sync_error = ''
                    competition_context.save(update_fields=['sync_status', 'sync_error', 'updated_at'])

            # Autodetección "best effort" para reducir fricción:
            # - Si no se pegó URL de LaPreferente, intenta encontrarla por nombre.
            # - Si Universo tiene group_id pero falta external_team_key, intenta resolverlo desde la clasificación live.
            try:
                if primary_team and not str(getattr(primary_team, 'preferente_url', '') or '').strip():
                    guessed_url = find_preferente_team_url(str(getattr(primary_team, 'name', '') or team_name).strip())
                    if guessed_url:
                        primary_team.preferente_url = guessed_url
                        primary_team.save(update_fields=['preferente_url'])
                        form['preferente_url'] = guessed_url
                        auto_notice_parts.append('LaPreferente detectado automáticamente.')
            except Exception:
                pass
            try:
                group_key = str(external_group_key or '').strip()
                if (
                    competition_context
                    and provider == WorkspaceCompetitionContext.PROVIDER_UNIVERSO
                    and group_key
                    and not str(getattr(competition_context, 'external_team_key', '') or '').strip()
                ):
                    live = _fetch_universo_live_classification(group_key)
                    rows = _serialize_universo_live_classification(live) if isinstance(live, dict) else []
                    desired = _normalize_team_lookup_key(str(team_name or primary_team.name or '').strip())
                    best_code = ''
                    best_name = ''
                    if desired:
                        for row in rows:
                            if not isinstance(row, dict):
                                continue
                            candidate_name = str(row.get('full_name') or row.get('team') or '').strip()
                            candidate_code = str(row.get('team_code') or '').strip()
                            if not candidate_name or not candidate_code:
                                continue
                            cand_key = _normalize_team_lookup_key(candidate_name)
                            if cand_key == desired or (desired in cand_key) or (cand_key in desired):
                                best_code = candidate_code
                                best_name = candidate_name
                                break
                    if best_code:
                        competition_context.external_team_key = best_code
                        if best_name and not str(getattr(competition_context, 'external_team_name', '') or '').strip():
                            competition_context.external_team_name = best_name
                        competition_context.save(update_fields=['external_team_key', 'external_team_name', 'updated_at'])
                        auto_notice_parts.append('Código de equipo de Universo detectado automáticamente.')
            except Exception:
                pass

            # Auto-búsqueda Universo por nombre (sin pegar URLs/códigos).
            # Solo autoseleccionamos cuando hay UNA coincidencia clara; si hay varias, mostramos listado.
            if (
                provider == WorkspaceCompetitionContext.PROVIDER_UNIVERSO
                and action in {'save_and_sync', 'import_roster', 'save'}
                and not str(external_group_key or '').strip()
                and not str(external_source_url or '').strip()
                and competition_context
                and not str(getattr(competition_context, 'external_group_key', '') or '').strip()
            ):
                try:
                    candidates = _search_universo_competition_candidates(team_query=team_name)
                except Exception:
                    candidates = []
                if len(candidates) == 1 and isinstance(candidates[0], dict):
                    item = candidates[0]
                    candidate_group_key = str(item.get('external_group_key') or '').strip()
                    candidate_competition_key = str(item.get('external_competition_key') or '').strip()
                    candidate_team_key = str(item.get('external_team_key') or '').strip()
                    candidate_team_name = str(item.get('external_team_name') or item.get('team_name') or '').strip()
                    if candidate_group_key and candidate_team_key:
                        competition_context = _bootstrap_workspace_competition_context(
                            workspace,
                            primary_team=primary_team,
                            provider=WorkspaceCompetitionContext.PROVIDER_UNIVERSO,
                            external_competition_key=candidate_competition_key,
                            external_group_key=candidate_group_key,
                            external_team_key=candidate_team_key,
                            external_team_name=candidate_team_name or team_name,
                            external_source_url=form.get('external_source_url') or '',
                            auto_sync_enabled=True,
                        )
                        _ensure_universo_group_models_from_candidate(
                            group_key=candidate_group_key,
                            competition_name=str(item.get('competition_name') or '').strip(),
                            group_name=str(item.get('group_name') or '').strip(),
                            season_name=str(item.get('season_name') or '').strip(),
                            competition_code=candidate_competition_key,
                            primary_team=primary_team,
                            context=competition_context,
                        )
                        external_group_key = candidate_group_key
                        form['external_group_key'] = candidate_group_key
                        auto_notice_parts.append(f'Universo detectado automáticamente: {candidate_team_name or team_name}.')
                elif candidates:
                    universo_candidates = candidates
                    raise ValueError('Hay varias coincidencias en Universo. Selecciona una en la lista de abajo y vuelve a sincronizar/importar.')

            def _import_players_from_roster_rows(team_obj, roster_rows: list[dict], *, replace_existing: bool):
                if not team_obj:
                    return 0, 0, 0
                created_count = 0
                updated_count = 0
                kept_names = set()
                for row in roster_rows:
                    if not isinstance(row, dict):
                        continue
                    name = str(row.get('name') or '').strip()
                    if not name:
                        continue
                    if len(name) > 120:
                        name = name[:120].rstrip()
                    number_val = row.get('number')
                    if number_val is None:
                        number_val = row.get('dorsal')
                    try:
                        number_val = int(str(number_val).strip()) if str(number_val).strip() else None
                    except Exception:
                        number_val = None
                    position = str(row.get('position') or '').strip()[:60]
                    kept_names.add(name.lower())
                    obj, was_created = Player.objects.update_or_create(
                        team=team_obj,
                        name=name,
                        defaults={
                            'number': number_val,
                            'position': position,
                            'is_active': True,
                        },
                    )
                    if was_created:
                        created_count += 1
                    else:
                        updated_count += 1
                deactivated = 0
                if replace_existing and kept_names:
                    for player_obj in Player.objects.filter(team=team_obj, is_active=True).only('id', 'name'):
                        if str(getattr(player_obj, 'name', '') or '').strip().lower() not in kept_names:
                            Player.objects.filter(id=player_obj.id).update(is_active=False)
                            deactivated += 1
                return created_count, updated_count, deactivated

            def _parse_roster_excel(uploaded_file) -> list[dict]:
                if not uploaded_file:
                    return []
                try:
                    raw = uploaded_file.read()
                finally:
                    try:
                        uploaded_file.seek(0)
                    except Exception:
                        pass
                if not raw:
                    return []
                try:
                    from openpyxl import load_workbook
                except Exception as exc:
                    raise ValueError('No se pudo cargar openpyxl para leer el Excel.') from exc
                workbook = load_workbook(filename=io.BytesIO(raw), data_only=True)
                sheet = workbook.active
                rows = list(sheet.iter_rows(values_only=True))
                if not rows:
                    return []
                header = [str(cell or '').strip().lower() for cell in rows[0]]
                header_map = {}
                for idx, key in enumerate(header):
                    normalized = re.sub(r'[^a-z0-9]+', '_', key).strip('_')
                    if normalized:
                        header_map[normalized] = idx

                def _find_col(candidates):
                    for cand in candidates:
                        if cand in header_map:
                            return header_map[cand]
                    return None

                idx_name = _find_col(['name', 'nombre', 'jugador', 'player'])
                idx_number = _find_col(['dorsal', 'numero', 'n', 'number'])
                idx_position = _find_col(['posicion', 'posición', 'position', 'rol', 'puesto'])
                if idx_name is None:
                    raise ValueError('El Excel debe tener una columna de nombre (name/nombre/jugador).')
                parsed_rows: list[dict] = []
                for row in rows[1:]:
                    if not row or all(cell is None or str(cell).strip() == '' for cell in row):
                        continue
                    name = str(row[idx_name] or '').strip()
                    if not name:
                        continue
                    number_val = row[idx_number] if idx_number is not None and idx_number < len(row) else None
                    position = row[idx_position] if idx_position is not None and idx_position < len(row) else ''
                    parsed_rows.append(
                        {
                            'name': name,
                            'number': number_val,
                            'position': str(position or '').strip(),
                        }
                    )
                    if len(parsed_rows) >= 80:
                        break
                return parsed_rows

            if action == 'search_universo':
                # No requiere guardar nada; solo devuelve candidatos para seleccionar.
                # Si no hay token de Universo, la función usa el catálogo local (si existe).
                universo_candidates = _search_universo_competition_candidates(team_query=team_name)
                if universo_candidates:
                    success = f'Se encontraron {len(universo_candidates)} coincidencias en Universo.'
                else:
                    error = 'No se encontraron coincidencias en Universo con ese nombre.'
            elif action == 'apply_universo_candidate':
                candidate_group_key = str(request.POST.get('candidate_external_group_key') or '').strip()
                candidate_competition_key = str(request.POST.get('candidate_external_competition_key') or '').strip()
                candidate_team_key = str(request.POST.get('candidate_external_team_key') or '').strip()
                candidate_team_name = _sanitize_task_text((request.POST.get('candidate_external_team_name') or '').strip(), multiline=False, max_len=160)
                candidate_competition_name = _sanitize_task_text((request.POST.get('candidate_competition_name') or '').strip(), multiline=False, max_len=150)
                candidate_group_name = _sanitize_task_text((request.POST.get('candidate_group_name') or '').strip(), multiline=False, max_len=80)
                candidate_season_name = _sanitize_task_text((request.POST.get('candidate_season_name') or '').strip(), multiline=False, max_len=80)
                if not (candidate_group_key and candidate_team_key):
                    raise ValueError('Candidato inválido (faltan claves de grupo/equipo).')
                competition_context = _bootstrap_workspace_competition_context(
                    workspace,
                    primary_team=primary_team,
                    provider=WorkspaceCompetitionContext.PROVIDER_UNIVERSO,
                    external_competition_key=candidate_competition_key,
                    external_group_key=candidate_group_key,
                    external_team_key=candidate_team_key,
                    external_team_name=candidate_team_name or team_name,
                    external_source_url=form.get('external_source_url') or '',
                    auto_sync_enabled=True,
                )
                _ensure_universo_group_models_from_candidate(
                    group_key=candidate_group_key,
                    competition_name=candidate_competition_name,
                    group_name=candidate_group_name,
                    season_name=candidate_season_name,
                    competition_code=candidate_competition_key,
                    primary_team=primary_team,
                    context=competition_context,
                )
                form['provider'] = WorkspaceCompetitionContext.PROVIDER_UNIVERSO
                form['external_group_key'] = candidate_group_key
                success = f'Equipo de Universo seleccionado: {candidate_team_name or team_name}.'
            elif action == 'save_and_sync':
                synced_context, sync_error = _sync_workspace_competition_context(workspace, primary_team=primary_team)
                competition_context = synced_context or competition_context
                if sync_error:
                    raise ValueError(sync_error)
                success = 'Configuración guardada y sincronización completada.'
            elif action == 'import_roster':
                uploaded_excel = request.FILES.get('roster_excel')
                if uploaded_excel:
                    roster_rows = _parse_roster_excel(uploaded_excel)
                    created_players, updated_players, deactivated = _import_players_from_roster_rows(
                        primary_team,
                        roster_rows,
                        replace_existing=replace_roster,
                    )
                    success = (
                        'Plantilla importada desde Excel. '
                        f'Creados: {created_players}, actualizados: {updated_players}'
                        + (f', desactivados: {deactivated}.' if deactivated else '.')
                    )
                else:
                    roster_provider = None
                    roster_rows = []
                    roster_source_url = ''
                    roster_error = ''
                    team_code = str(getattr(competition_context, 'external_team_key', '') or '').strip() if competition_context else ''
                    if provider == WorkspaceCompetitionContext.PROVIDER_UNIVERSO and team_code:
                        try:
                            roster_rows = fetch_universo_team_roster(team_code)
                            roster_provider = TeamRosterSnapshot.PROVIDER_UNIVERSO
                        except Exception as exc:
                            roster_error = str(exc) or 'No se pudo consultar la plantilla en Universo.'
                    if not roster_rows:
                        team_url = str(getattr(primary_team, 'preferente_url', '') or '').strip()
                        if not team_url:
                            team_url = find_preferente_team_url(primary_team.name)
                            if team_url:
                                primary_team.preferente_url = team_url
                                primary_team.save(update_fields=['preferente_url'])
                        if team_url:
                            roster_source_url = team_url
                            try:
                                roster_rows = fetch_preferente_team_roster(team_url)
                                roster_provider = TeamRosterSnapshot.PROVIDER_PREFERENTE
                            except Exception as exc:
                                roster_error = str(exc) or 'No se pudo consultar La Preferente.'
                    if not roster_rows:
                        if roster_error:
                            raise ValueError(roster_error)
                        raise ValueError('No se pudo importar la plantilla: falta Excel, código de Universo o URL de La Preferente.')
                    created_players, updated_players, deactivated = _import_players_from_roster_rows(
                        primary_team,
                        roster_rows,
                        replace_existing=replace_roster,
                    )
                    if roster_provider:
                        TeamRosterSnapshot.objects.update_or_create(
                            team=primary_team,
                            provider=roster_provider,
                            defaults={
                                'roster_payload': roster_rows,
                                'source_url': roster_source_url,
                                'error': '',
                            },
                        )
                    success = (
                        'Plantilla importada. '
                        f'Creados: {created_players}, actualizados: {updated_players}'
                        + (f', desactivados: {deactivated}.' if deactivated else '.')
                    )
            elif action == 'seed_demo':
                created = _bootstrap_demo_club_workspace(workspace)
                success = (
                    'Datos demo cargados. '
                    f"Jugadores: {created.get('players', 0)}, "
                    f"partidos: {created.get('matches', 0)}, "
                    f"eventos: {created.get('events', 0)}, "
                    f"sesiones: {created.get('sessions', 0)}, "
                    f"tareas: {created.get('tasks', 0)}, "
                    f"estadísticas: {created.get('stats', 0)}."
                )
            else:
                success = 'Configuración guardada.'
        except ValueError as exc:
            error = str(exc)
        except Exception:
            error = 'No se pudo completar el onboarding.'

    if workspace and primary_team and not competition_context:
        competition_context = _bootstrap_workspace_competition_context(workspace, primary_team=primary_team)
    setup_checklist = []
    setup_progress = {'required_total': 0, 'required_done': 0}
    try:
        if workspace and primary_team:
            active_match = None
            try:
                active_match = get_active_match(primary_team)
            except Exception:
                active_match = None
            convocation_record = None
            try:
                convocation_record = get_current_convocation_record(primary_team)
            except Exception:
                convocation_record = None
            setup_checklist = _build_team_setup_checklist(
                request,
                workspace,
                primary_team,
                match=active_match,
                convocation_record=convocation_record,
            )
            if isinstance(setup_checklist, list) and setup_checklist:
                required_items = [item for item in setup_checklist if bool(item.get('required'))]
                setup_progress['required_total'] = len(required_items)
                setup_progress['required_done'] = len([item for item in required_items if bool(item.get('ok'))])
    except Exception:
        setup_checklist = []
    return render(
        request,
        'football/club_onboarding.html',
        {
            'workspace': workspace or SimpleNamespace(slug='(nuevo)'),
            'competition_context': competition_context,
            'provider_choices': WorkspaceCompetitionContext.PROVIDER_CHOICES,
            'universo_candidates': universo_candidates,
            'auto_notice': ' '.join([part for part in auto_notice_parts if part]).strip(),
            'form': form,
            'setup_checklist': setup_checklist or [],
            'setup_progress': setup_progress,
            'error': error,
            'success': success,
        },
    )


def _split_full_name(value):
    text = str(value or '').strip()
    if not text:
        return '', ''
    parts = [part for part in text.split() if part]
    if len(parts) == 1:
        return parts[0], ''
    return parts[0], ' '.join(parts[1:])

def _sanitize_username(value, *, max_len=150):
    """
    Sanitiza usernames sin aplicar "polish" lingüístico.

    Importante: `_sanitize_task_text()` inserta espacios tras puntuación como ".", lo que rompe
    usernames tipo `a.diaz`. Aquí eliminamos todos los espacios y normalizamos a lower.
    """
    raw = str(value or '').strip()
    if not raw:
        return ''
    raw = re.sub(r'\s+', '', raw)
    raw = raw.lower()
    if max_len:
        raw = raw[:int(max_len)]
    return raw


@login_required
def platform_overview_page(request):
    if not _can_access_platform(request.user):
        return HttpResponse('No tienes permisos para acceder a la plataforma.', status=403)
    valid_tabs = {'clients', 'users', 'documents', 'workspace-create', 'home-global'}
    active_tab = str(request.GET.get('tab') or 'clients').strip().lower()
    if active_tab not in valid_tabs:
        active_tab = 'clients'
    clients_query = _sanitize_task_text((request.GET.get('q_clients') or '').strip(), multiline=False, max_len=120)
    users_subtab = str(request.GET.get('subtab') or 'list').strip().lower()
    if users_subtab not in {'list', 'create'}:
        users_subtab = 'list'
    users_query = _sanitize_task_text((request.GET.get('q') or '').strip(), multiline=False, max_len=120)
    users_page_number = _parse_int(request.GET.get('page')) or 1
    if users_page_number < 1:
        users_page_number = 1
    edit_user_id = _parse_int(request.GET.get('edit')) if active_tab == 'users' and users_subtab == 'list' else None

    feedback = str(request.session.pop('platform_feedback', '') or '')
    error = ''
    user_message = ''
    user_error = ''
    invitation_links = []
    carousel_message = ''
    active_workspace = _build_active_workspace_badge(request)
    primary_team = Team.objects.filter(is_primary=True).first()
    workspace_form = {
        'workspace_name': '',
        'workspace_kind': Workspace.KIND_CLUB,
        'owner_username': '',
        'team_id': '',
        'team_new_name': '',
        'workspace_notes': '',
        'competition_provider': WorkspaceCompetitionContext.PROVIDER_MANUAL,
        'external_competition_key': '',
        'external_group_key': '',
        'external_team_key': '',
        'external_team_name': '',
        'competition_auto_sync': True,
        'seed_demo_data': False,
        'initial_admin_usernames': '',
        'initial_member_usernames': '',
        'module_preset': 'complete',
        'modules': _workspace_default_modules(Workspace.KIND_CLUB),
        'module_keys': [item['key'] for item in _workspace_module_catalog(Workspace.KIND_CLUB)],
        'deliverable_keys': _workspace_selected_deliverable_keys(
            Workspace.KIND_CLUB,
            _expand_workspace_module_selection(
                Workspace.KIND_CLUB,
                {item['key']: True for item in _workspace_module_catalog(Workspace.KIND_CLUB)},
            ),
        ),
    }
    user_form = {
        'full_name': '',
        'username': '',
        'email': '',
        'role': AppUserRole.ROLE_PLAYER,
        'assign_workspace_id': '',
        'assign_member_role': WorkspaceMembership.ROLE_MEMBER,
    }
    platform_auto_ensure_workspaces = str(os.getenv('PLATFORM_AUTO_ENSURE_WORKSPACES', '0') or '').strip().lower() in {
        '1',
        'true',
        'yes',
        'on',
    }
    # Evitar efectos colaterales en visitas a Platform (entornos de pruebas): por defecto NO creamos
    # workspaces al entrar en la vista.
    if platform_auto_ensure_workspaces:
        if primary_team:
            _ensure_club_workspace(primary_team)

    if request.method == 'POST':
        form_action = (request.POST.get('form_action') or 'workspace_create').strip().lower()
        if form_action == 'workspace_create':
            active_tab = 'workspace-create'
            workspace_name = _sanitize_task_text((request.POST.get('workspace_name') or '').strip(), multiline=False, max_len=160)
            # Task Studio deja de existir en el nuevo modelo: en Plataforma solo se crean clientes club.
            workspace_kind = Workspace.KIND_CLUB
            owner_username = _sanitize_username(request.POST.get('owner_username'), max_len=150)
            team_id = _parse_int(request.POST.get('team_id'))
            team_new_name = _sanitize_task_text((request.POST.get('team_new_name') or '').strip(), multiline=False, max_len=150)
            workspace_notes = _sanitize_task_text((request.POST.get('workspace_notes') or '').strip(), multiline=True, max_len=1200)
            competition_provider = str(request.POST.get('competition_provider') or WorkspaceCompetitionContext.PROVIDER_MANUAL).strip()
            external_competition_key = str(request.POST.get('external_competition_key') or '').strip()[:140]
            external_group_key = str(request.POST.get('external_group_key') or '').strip()[:140]
            external_team_key = str(request.POST.get('external_team_key') or '').strip()[:140]
            external_team_name = _sanitize_task_text((request.POST.get('external_team_name') or '').strip(), multiline=False, max_len=160)
            competition_auto_sync = str(request.POST.get('competition_auto_sync') or '').lower() in {'1', 'true', 'on', 'yes'}
            seed_demo_data = str(request.POST.get('seed_demo_data') or '').lower() in {'1', 'true', 'on', 'yes'}
            initial_admin_usernames = str(request.POST.get('initial_admin_usernames') or '')
            initial_member_usernames = str(request.POST.get('initial_member_usernames') or '')
            valid_providers = {choice[0] for choice in WorkspaceCompetitionContext.PROVIDER_CHOICES}
            if competition_provider not in valid_providers:
                competition_provider = WorkspaceCompetitionContext.PROVIDER_MANUAL
            module_catalog = _workspace_module_catalog(workspace_kind)
            module_preset = str(request.POST.get('module_preset') or '').strip().lower()
            if module_preset not in {'basic', 'complete', 'custom'}:
                module_preset = 'custom'
            if module_preset in {'basic', 'complete'}:
                if module_preset == 'basic':
                    defaults = _workspace_default_modules(workspace_kind)
                    default_keys = set(_workspace_selected_module_keys(workspace_kind, defaults))
                    selected_modules = {item['key']: item['key'] in default_keys for item in module_catalog}
                else:
                    selected_modules = {item['key']: True for item in module_catalog}
                selected_deliverables = {}
            else:
                selected_modules = {
                    item['key']: str(request.POST.get(f"module_{item['key']}") or '').lower() in {'1', 'true', 'on', 'yes'}
                    for item in module_catalog
                }
                selected_deliverables = {
                    _workspace_deliverable_flag(item['key'], deliverable['key']): (
                        str(request.POST.get(f"deliverable_{item['key']}__{deliverable['key']}") or '').lower() in {'1', 'true', 'on', 'yes'}
                    )
                    for item in module_catalog
                    for deliverable in item.get('deliverables', []) or []
                }
            if not any(selected_modules.values()):
                selected_modules = {item['key']: True for item in module_catalog}
            expanded_modules = _expand_workspace_module_selection(workspace_kind, selected_modules, selected_deliverables)
            workspace_form = {
                'workspace_name': workspace_name,
                'workspace_kind': workspace_kind,
                'owner_username': owner_username,
                'team_id': str(team_id or ''),
                'team_new_name': team_new_name,
                'workspace_notes': workspace_notes,
                'competition_provider': competition_provider,
                'external_competition_key': external_competition_key,
                'external_group_key': external_group_key,
                'external_team_key': external_team_key,
                'external_team_name': external_team_name,
                'competition_auto_sync': competition_auto_sync,
                'seed_demo_data': seed_demo_data,
                'initial_admin_usernames': initial_admin_usernames,
                'initial_member_usernames': initial_member_usernames,
                'module_preset': module_preset,
                'modules': expanded_modules,
                'module_keys': [key for key, enabled in selected_modules.items() if enabled],
                'deliverable_keys': [key for key, enabled in selected_deliverables.items() if enabled],
            }
            try:
                if not workspace_name:
                    raise ValueError('Indica un nombre para el workspace.')
                owner_user = User.objects.filter(username__iexact=owner_username).first() if owner_username else None
                if owner_username and not owner_user:
                    raise ValueError(f'No existe el usuario propietario "{owner_username}".')
                if workspace_kind == Workspace.KIND_TASK_STUDIO and not owner_user:
                    raise ValueError('Task Studio requiere un usuario propietario.')
                admin_users, missing_admin_users = _parse_workspace_usernames(initial_admin_usernames)
                member_users, missing_member_users = _parse_workspace_usernames(initial_member_usernames)
                if missing_admin_users:
                    raise ValueError(f'No existen estos administradores iniciales: {", ".join(missing_admin_users)}.')
                if missing_member_users:
                    raise ValueError(f'No existen estos miembros iniciales: {", ".join(missing_member_users)}.')
                primary_workspace_team = None
                if workspace_kind == Workspace.KIND_CLUB and team_new_name:
                    primary_workspace_team = _ensure_platform_team(team_new_name)
                if not primary_workspace_team and team_id:
                    primary_workspace_team = Team.objects.filter(id=team_id).first()
                workspace = Workspace.objects.create(
                    name=workspace_name,
                    slug=_unique_workspace_slug(workspace_name),
                    kind=workspace_kind,
                    owner_user=owner_user,
                    primary_team=primary_workspace_team if workspace_kind == Workspace.KIND_CLUB else None,
                    enabled_modules=expanded_modules,
                    notes=workspace_notes,
                )
                if workspace.kind == Workspace.KIND_CLUB:
                    _bootstrap_workspace_competition_context(
                        workspace,
                        primary_team=primary_workspace_team,
                        provider=competition_provider,
                        external_competition_key=external_competition_key,
                        external_group_key=external_group_key,
                        external_team_key=external_team_key,
                        external_team_name=external_team_name,
                        auto_sync_enabled=competition_auto_sync,
                    )
                    if competition_auto_sync:
                        _sync_workspace_competition_context(workspace, primary_team=primary_workspace_team)
                    if seed_demo_data and workspace.primary_team_id:
                        _bootstrap_demo_club_workspace(workspace)
                if owner_user:
                    WorkspaceMembership.objects.get_or_create(
                        workspace=workspace,
                        user=owner_user,
                        defaults={'role': WorkspaceMembership.ROLE_OWNER},
                    )
                for admin_user in admin_users:
                    if owner_user and admin_user.id == owner_user.id:
                        continue
                    WorkspaceMembership.objects.update_or_create(
                        workspace=workspace,
                        user=admin_user,
                        defaults={'role': WorkspaceMembership.ROLE_ADMIN},
                    )
                for member_user in member_users:
                    if owner_user and member_user.id == owner_user.id:
                        continue
                    if any(admin_user.id == member_user.id for admin_user in admin_users):
                        continue
                    WorkspaceMembership.objects.update_or_create(
                        workspace=workspace,
                        user=member_user,
                        defaults={'role': WorkspaceMembership.ROLE_MEMBER},
                    )
                feedback = f'Workspace creado: {workspace.name}.'
                workspace_form = {
                    'workspace_name': '',
                    'workspace_kind': Workspace.KIND_CLUB,
                    'owner_username': '',
                    'team_id': '',
                    'team_new_name': '',
                    'workspace_notes': '',
                    'competition_provider': WorkspaceCompetitionContext.PROVIDER_MANUAL,
                    'external_competition_key': '',
                    'external_group_key': '',
                    'external_team_key': '',
                    'external_team_name': '',
                    'competition_auto_sync': True,
                    'seed_demo_data': False,
                    'initial_admin_usernames': '',
                    'initial_member_usernames': '',
                    'module_preset': 'complete',
                    'modules': _workspace_default_modules(Workspace.KIND_CLUB),
                    'module_keys': [item['key'] for item in _workspace_module_catalog(Workspace.KIND_CLUB)],
                    'deliverable_keys': _workspace_selected_deliverable_keys(
                        Workspace.KIND_CLUB,
                        _expand_workspace_module_selection(
                            Workspace.KIND_CLUB,
                            {item['key']: True for item in _workspace_module_catalog(Workspace.KIND_CLUB)},
                        ),
                    ),
                }
            except ValueError as exc:
                error = str(exc)
            except Exception:
                error = 'No se pudo crear el workspace.'
        elif form_action == 'platform_user_create':
            active_tab = 'users'
            users_subtab = 'create'
            full_name = _sanitize_task_text((request.POST.get('full_name') or '').strip(), multiline=False, max_len=150)
            username = re.sub(r'\s+', '', str(request.POST.get('username') or '').strip()).lower()[:150]
            email = re.sub(r'\s+', '', str(request.POST.get('email') or '').strip()).lower()[:190]
            password = (request.POST.get('password') or '').strip()
            role_value = str(request.POST.get('role') or AppUserRole.ROLE_PLAYER).strip()
            assign_workspace_id = _parse_int(request.POST.get('assign_workspace_id'))
            assign_member_role = str(request.POST.get('assign_member_role') or WorkspaceMembership.ROLE_MEMBER).strip()
            role_choices = {choice[0] for choice in AppUserRole.ROLE_CHOICES}
            if role_value not in role_choices:
                role_value = AppUserRole.ROLE_PLAYER
            if assign_member_role not in {choice[0] for choice in WorkspaceMembership.ROLE_CHOICES}:
                assign_member_role = WorkspaceMembership.ROLE_MEMBER
            user_form = {
                'full_name': full_name,
                'username': username,
                'email': email,
                'role': role_value,
                'assign_workspace_id': str(assign_workspace_id or ''),
                'assign_member_role': assign_member_role,
            }
            try:
                if not username:
                    raise ValueError('El usuario es obligatorio.')
                if User.objects.filter(username__iexact=username).exists():
                    raise ValueError('Ese usuario ya existe.')
                if len(password) < 6:
                    raise ValueError('La contraseña debe tener al menos 6 caracteres.')
                first_name, last_name = _split_full_name(full_name)
                user = User.objects.create_user(
                    username=username,
                    email=email,
                    password=password,
                    first_name=first_name,
                    last_name=last_name,
                )
                if role_value == AppUserRole.ROLE_ADMIN:
                    user.is_staff = True
                    user.save(update_fields=['is_staff'])
                AppUserRole.objects.update_or_create(user=user, defaults={'role': role_value})
                assigned_workspace = None
                if assign_workspace_id:
                    assigned_workspace = Workspace.objects.filter(id=assign_workspace_id, is_active=True).first()
                    if not assigned_workspace:
                        raise ValueError('Workspace no encontrado para asignación.')
                    WorkspaceMembership.objects.update_or_create(
                        workspace=assigned_workspace,
                        user=user,
                        defaults={'role': assign_member_role},
                    )
                if assigned_workspace:
                    user_message = f'Usuario creado en Plataforma: {username}. Asignado a {assigned_workspace.name}.'
                else:
                    user_message = f'Usuario creado en Plataforma: {username}.'
                user_form = {
                    'full_name': '',
                    'username': '',
                    'email': '',
                    'role': AppUserRole.ROLE_PLAYER,
                    'assign_workspace_id': '',
                    'assign_member_role': WorkspaceMembership.ROLE_MEMBER,
                }
            except ValueError as exc:
                user_error = str(exc)
            except Exception:
                user_error = 'No se pudo crear el usuario global.'
        elif form_action == 'platform_user_invite_create':
            active_tab = 'users'
            users_subtab = 'list'
            user_id = _parse_int(request.POST.get('user_id'))
            validity_days = _parse_int(request.POST.get('valid_days')) or 7
            validity_days = max(1, min(validity_days, 30))
            user_obj = User.objects.filter(id=user_id).first() if user_id else None
            try:
                if not user_obj:
                    raise ValueError('Usuario no encontrado.')
                UserInvitation.objects.filter(user=user_obj, is_active=True, accepted_at__isnull=True).update(is_active=False)
                invitation = UserInvitation.objects.create(
                    user=user_obj,
                    token=UserInvitation.generate_token(),
                    email=(user_obj.email or '').strip(),
                    expires_at=timezone.now() + timedelta(days=validity_days),
                    created_by=request.user.get_username() if request.user.is_authenticated else '',
                    is_active=True,
                )
                invite_url = request.build_absolute_uri(
                    reverse('user-invite-accept', args=[invitation.token])
                )
                invitation_links.append(
                    {
                        'username': user_obj.username,
                        'url': invite_url,
                        'expires_at': invitation.expires_at,
                    }
                )
                user_message = f'Invitación generada en Plataforma para {user_obj.username}.'
            except ValueError as exc:
                user_error = str(exc)
            except Exception:
                user_error = 'No se pudo generar la invitación global.'
        elif form_action == 'platform_user_update':
            active_tab = 'users'
            users_subtab = 'list'
            user_id = _parse_int(request.POST.get('user_id'))
            full_name = _sanitize_task_text((request.POST.get('full_name') or '').strip(), multiline=False, max_len=150)
            email = re.sub(r'\s+', '', str(request.POST.get('email') or '').strip()).lower()[:190]
            password = (request.POST.get('password') or '').strip()
            role_value = str(request.POST.get('role') or AppUserRole.ROLE_PLAYER).strip()
            is_active = str(request.POST.get('is_active') or '').lower() in {'1', 'true', 'on', 'yes'}
            role_choices = {choice[0] for choice in AppUserRole.ROLE_CHOICES}
            if role_value not in role_choices:
                role_value = AppUserRole.ROLE_PLAYER
            user_obj = User.objects.filter(id=user_id).first() if user_id else None
            try:
                if not user_obj:
                    raise ValueError('Usuario no encontrado.')
                if password and len(password) < 6:
                    raise ValueError('La nueva contraseña debe tener al menos 6 caracteres.')
                first_name, last_name = _split_full_name(full_name)
                user_obj.first_name = first_name
                user_obj.last_name = last_name
                user_obj.email = email
                user_obj.is_active = is_active
                user_obj.is_staff = bool(is_active and role_value == AppUserRole.ROLE_ADMIN)
                if password:
                    user_obj.set_password(password)
                update_fields = ['first_name', 'last_name', 'email', 'is_active', 'is_staff']
                if password:
                    update_fields.append('password')
                user_obj.save(update_fields=update_fields)
                # Si el admin se cambia su propia contraseña desde este panel,
                # Django invalida la sesión (auth hash). Mantén la sesión activa.
                if password and request.user.is_authenticated and user_obj.id == request.user.id:
                    update_session_auth_hash(request, user_obj)
                AppUserRole.objects.update_or_create(user=user_obj, defaults={'role': role_value})
                user_message = f'Usuario actualizado: {user_obj.username}.'
            except ValueError as exc:
                user_error = str(exc)
            except Exception:
                user_error = 'No se pudo actualizar el usuario.'
        elif form_action == 'platform_user_toggle_active':
            active_tab = 'users'
            users_subtab = 'list'
            user_id = _parse_int(request.POST.get('user_id'))
            user_obj = User.objects.filter(id=user_id).first() if user_id else None
            try:
                if not user_obj:
                    raise ValueError('Usuario no encontrado.')
                user_obj.is_active = not bool(user_obj.is_active)
                role_value = _get_user_role(user_obj)
                if not user_obj.is_active and role_value == AppUserRole.ROLE_ADMIN:
                    user_obj.is_staff = False
                elif user_obj.is_active and role_value == AppUserRole.ROLE_ADMIN:
                    user_obj.is_staff = True
                user_obj.save(update_fields=['is_active', 'is_staff'])
                user_message = f'Usuario {"activado" if user_obj.is_active else "desactivado"}: {user_obj.username}.'
            except ValueError as exc:
                user_error = str(exc)
            except Exception:
                user_error = 'No se pudo cambiar el estado del usuario.'
        elif form_action == 'platform_user_delete':
            active_tab = 'users'
            users_subtab = 'list'
            user_id = _parse_int(request.POST.get('user_id'))
            user_obj = User.objects.filter(id=user_id).first() if user_id else None
            try:
                if not user_obj:
                    raise ValueError('Usuario no encontrado.')
                owned_club_workspace = Workspace.objects.filter(kind=Workspace.KIND_CLUB, owner_user=user_obj).first()
                if owned_club_workspace:
                    raise ValueError(f'No puedes borrar {user_obj.username} mientras sea propietario de {owned_club_workspace.name}.')
                WorkspaceMembership.objects.filter(user=user_obj).delete()
                UserInvitation.objects.filter(user=user_obj).update(is_active=False)
                username = user_obj.username
                user_obj.delete()
                user_message = f'Usuario eliminado: {username}.'
            except ValueError as exc:
                user_error = str(exc)
            except Exception:
                user_error = 'No se pudo eliminar el usuario.'
        elif form_action in {'carousel_upload', 'carousel_update', 'carousel_delete'}:
            active_tab = 'home-global'
            if _handle_home_carousel_post(request):
                carousel_message = 'Cambios guardados en Home global.'

    club_workspace_count = Workspace.objects.filter(kind=Workspace.KIND_CLUB).count()
    studio_workspace_count = 0
    linked_club_user_count = (
        WorkspaceMembership.objects
        .filter(workspace__kind=Workspace.KIND_CLUB)
        .values('user_id')
        .distinct()
        .count()
    )
    club_workspaces_without_team = Workspace.objects.filter(kind=Workspace.KIND_CLUB, primary_team__isnull=True).count()
    club_workspaces_without_members = (
        Workspace.objects
        .filter(kind=Workspace.KIND_CLUB)
        .annotate(member_count=Count('memberships', distinct=True))
        .filter(member_count__lte=0)
        .count()
    )
    platform_attention_items = []
    if club_workspaces_without_team:
        platform_attention_items.append(f'{club_workspaces_without_team} club(es) sin equipo principal vinculado.')
    if club_workspaces_without_members:
        platform_attention_items.append(f'{club_workspaces_without_members} club(es) sin miembros asignados.')
    if not platform_attention_items:
        platform_attention_items.append('La matriz no tiene alertas críticas de configuración.')

    # Carga condicional: sólo traemos datos pesados para la pestaña actual.
    club_workspaces = []
    studio_workspaces = []
    primary_workspace = None
    workspace_users = []
    platform_users = []
    platform_users_total = 0
    platform_users_has_next = False
    teams = []
    carousel_images = []
    recent_documents = []
    recent_audit_events = []

    if active_tab in {'clients'}:
        workspaces_qs = (
            Workspace.objects
            .select_related('owner_user', 'primary_team')
            .annotate(member_count=Count('memberships', distinct=True))
        )
        if active_tab == 'clients':
            if clients_query:
                club_filter = (
                    Q(name__icontains=clients_query)
                    | Q(slug__icontains=clients_query)
                    | Q(primary_team__name__icontains=clients_query)
                    | Q(primary_team__slug__icontains=clients_query)
                    | Q(primary_team__category__icontains=clients_query)
                )
                workspaces_qs = workspaces_qs.filter(club_filter)
            club_workspaces = list(
                workspaces_qs
                .filter(kind=Workspace.KIND_CLUB)
                .order_by('name', 'id')
            )
            for workspace in club_workspaces:
                workspace.active_module_count = len(
                    _workspace_selected_module_keys(workspace.kind, _workspace_enabled_modules(workspace))
                )
            workspace_ids = [int(ws.id) for ws in club_workspaces if getattr(ws, 'id', None)]
            team_links_map = {}
            if workspace_ids:
                try:
                    team_links = list(
                        WorkspaceTeam.objects
                        .filter(workspace_id__in=workspace_ids)
                        .select_related('team')
                        .order_by('workspace_id', '-is_default', 'team__category', 'team__name', 'id')
                    )
                except Exception:
                    team_links = []
                for link in team_links:
                    team = getattr(link, 'team', None)
                    if not team:
                        continue
                    category = str(getattr(team, 'category', '') or '').strip()
                    name = str(getattr(team, 'display_name', '') or getattr(team, 'name', '') or '').strip()
                    label = category or name or f'Equipo {team.id}'
                    team_links_map.setdefault(int(link.workspace_id), []).append(
                        {
                            'team_id': int(team.id),
                            'label': label,
                            'category': category,
                            'name': name,
                            'is_default': bool(getattr(link, 'is_default', False)),
                        }
                    )
            for workspace in club_workspaces:
                # Backfill UX: si el workspace tiene `primary_team` pero no hay vínculo (WorkspaceTeam),
                # lo mostramos igualmente para que Platform siempre tenga un "Entrar · <equipo>".
                links = list(team_links_map.get(int(workspace.id), []) or [])
                try:
                    primary_team = getattr(workspace, 'primary_team', None)
                    primary_team_id = int(getattr(primary_team, 'id', 0) or 0) if primary_team else 0
                    if primary_team_id and primary_team_id not in {int(item.get('team_id') or 0) for item in links}:
                        category = str(getattr(primary_team, 'category', '') or '').strip()
                        name = str(getattr(primary_team, 'display_name', '') or getattr(primary_team, 'name', '') or '').strip()
                        label = category or name or f'Equipo {primary_team_id}'
                        links.insert(
                            0,
                            {
                                'team_id': primary_team_id,
                                'label': label,
                                'category': category,
                                'name': name,
                                'is_default': True,
                            },
                        )
                except Exception:
                    pass
                # Orden: default primero, luego por categoría/nombre.
                try:
                    links = sorted(
                        links,
                        key=lambda item: (
                            0 if item.get('is_default') else 1,
                            str(item.get('category') or '').lower(),
                            str(item.get('name') or item.get('label') or '').lower(),
                            int(item.get('team_id') or 0),
                        ),
                    )
                except Exception:
                    pass
                workspace.team_links = links
                workspace.team_link_count = len(links)
            primary_workspace = next(
                (workspace for workspace in club_workspaces if workspace.primary_team_id),
                None,
            )

    if active_tab == 'workspace-create':
        teams = list(Team.objects.order_by('name')[:250])

    if active_tab == 'users' and users_subtab == 'list':
        workspace_users = list(
            WorkspaceMembership.objects
            .select_related('workspace', 'user')
            .filter(workspace__kind=Workspace.KIND_CLUB)
            .order_by('workspace__name', 'role', 'user__username')[:200]
        )
        user_qs = User.objects.order_by('username')
        if users_query:
            q = users_query
            user_qs = user_qs.filter(
                Q(username__icontains=q)
                | Q(email__icontains=q)
                | Q(first_name__icontains=q)
                | Q(last_name__icontains=q)
            )
        platform_users_total = user_qs.count()
        page_size = 50
        offset = (users_page_number - 1) * page_size
        users_slice = list(user_qs[offset: offset + page_size + 1])
        platform_users_has_next = len(users_slice) > page_size
        platform_users = users_slice[:page_size]
        user_ids = [item.id for item in platform_users]
        role_map = {
            item.user_id: item.role
            for item in AppUserRole.objects.filter(user_id__in=user_ids)
        }
        role_labels = dict(AppUserRole.ROLE_CHOICES)
        membership_counts = {
            row['user_id']: row['count']
            for row in (
                WorkspaceMembership.objects
                .filter(user_id__in=user_ids)
                .values('user_id')
                .annotate(count=Count('id'))
            )
        }
        for item in platform_users:
            role_value = role_map.get(item.id, AppUserRole.ROLE_PLAYER)
            item.role_value = role_value
            item.role_label = role_labels.get(role_value, 'Entrenador')
            item.full_name_display = item.get_full_name().strip() or item.username
            item.workspace_count = int(membership_counts.get(item.id, 0) or 0)
        if edit_user_id:
            edit_user_obj = next((u for u in platform_users if u.id == edit_user_id), None) or User.objects.filter(id=edit_user_id).first()
        else:
            edit_user_obj = None
        if edit_user_obj:
            try:
                role_value = AppUserRole.objects.filter(user=edit_user_obj).values_list('role', flat=True).first() or AppUserRole.ROLE_PLAYER
            except Exception:
                role_value = AppUserRole.ROLE_PLAYER
            edit_user_obj.role_value = role_value
            edit_user_obj.role_label = role_labels.get(role_value, 'Entrenador')
            edit_user_obj.full_name_display = edit_user_obj.get_full_name().strip() or edit_user_obj.username
            try:
                edit_user_obj.workspace_count = int(
                    WorkspaceMembership.objects.filter(user=edit_user_obj).count()
                )
            except Exception:
                edit_user_obj.workspace_count = 0
    else:
        edit_user_obj = None

    if active_tab == 'home-global':
        carousel_images = list(HomeCarouselImage.objects.order_by('order', '-created_at', '-id')[:24])

    if active_tab == 'documents':
        recent_documents = []
        recent_session_tasks = list(
            SessionTask.objects
            .select_related('session__microcycle__team')
            .order_by('-created_at', '-id')[:6]
        )
        recent_sessions = list(
            TrainingSession.objects
            .select_related('microcycle__team')
            .order_by('-created_at', '-id')[:5]
        )
        for item in recent_session_tasks:
            recent_documents.append(
                {
                    'type': 'Tarea club',
                    'title': str(item.title or 'Tarea').strip() or 'Tarea',
                    'source': str(getattr(item.session.microcycle.team, 'display_name', '') or getattr(item.session.microcycle.team, 'name', '')).strip() or 'Club',
                    'meta': f"{item.session.session_date:%d/%m/%Y} · {item.get_block_display()} · {item.duration_minutes or 0} min",
                    'uefa_url': reverse('session-task-pdf', args=[item.id]),
                    'club_url': f"{reverse('session-task-pdf', args=[item.id])}?style=club",
                    'created_at': item.created_at,
                }
            )
        for item in recent_sessions:
            recent_documents.append(
                {
                    'type': 'Sesión',
                    'title': str(item.focus or 'Sesión').strip() or 'Sesión',
                    'source': str(getattr(item.microcycle.team, 'display_name', '') or getattr(item.microcycle.team, 'name', '')).strip() or 'Club',
                    'meta': f"{item.session_date:%d/%m/%Y} · {item.duration_minutes or 0} min",
                    'uefa_url': reverse('session-plan-pdf', args=[item.id]),
                    'club_url': f"{reverse('session-plan-pdf', args=[item.id])}?style=club",
                    'created_at': item.created_at,
                }
            )
        recent_documents = sorted(
            recent_documents,
            key=lambda item: item.get('created_at') or timezone.now(),
            reverse=True,
        )[:14]
        recent_audit_events = list(
            AuditEvent.objects
            .select_related('workspace', 'actor_user')
            .order_by('-created_at', '-id')[:24]
        )

    assignable_club_workspaces = []
    if active_tab == 'users' and users_subtab == 'create':
        assignable_club_workspaces = list(
            Workspace.objects
            .filter(kind=Workspace.KIND_CLUB, is_active=True)
            .order_by('name', 'id')
            .only('id', 'name')[:250]
        )

    return render(
        request,
        'football/platform_overview.html',
        {
            'feedback': feedback,
            'error': error,
            'user_message': user_message,
            'user_error': user_error,
            'invitation_links': invitation_links,
            'carousel_message': carousel_message,
            'club_workspace_count': club_workspace_count,
            'primary_workspace': primary_workspace,
            'club_workspaces': club_workspaces,
            'workspace_users': workspace_users,
            'platform_users': platform_users,
            'platform_users_total': platform_users_total,
            'platform_users_has_next': platform_users_has_next,
            'platform_users_page': users_page_number,
            'platform_users_query': users_query,
            'clients_query': clients_query,
            'edit_user': edit_user_obj,
            'carousel_images': carousel_images,
            'teams': teams,
            'workspace_kind_choices': [(Workspace.KIND_CLUB, 'Club')],
            'workspace_module_catalog_club': _workspace_module_catalog_for_template(Workspace.KIND_CLUB),
            'workspace_form': workspace_form,
            'competition_provider_choices': WorkspaceCompetitionContext.PROVIDER_CHOICES,
            'user_form': user_form,
            'role_choices': AppUserRole.ROLE_CHOICES,
            'workspace_member_role_choices': WorkspaceMembership.ROLE_CHOICES,
            'assignable_club_workspaces': assignable_club_workspaces,
            'active_workspace': active_workspace,
            'active_tab': active_tab,
            'users_subtab': users_subtab,
            'linked_club_user_count': linked_club_user_count,
            'platform_user_count': platform_users_total or 0,
            'club_workspaces_without_team': club_workspaces_without_team,
            'club_workspaces_without_members': club_workspaces_without_members,
            'platform_attention_items': platform_attention_items,
            'recent_documents': recent_documents,
            'recent_audit_events': recent_audit_events,
        },
    )


@login_required
def platform_workspace_detail_page(request, workspace_id):
    workspace = (
        Workspace.objects
        .select_related('owner_user', 'primary_team')
        .annotate(member_count=Count('memberships', distinct=True))
        .filter(id=workspace_id)
        .first()
    )
    if not workspace:
        raise Http404('Workspace no encontrado')
    if not _can_view_workspace(request.user, workspace):
        return HttpResponse('No tienes permisos para acceder a este workspace.', status=403)
    if workspace.kind != Workspace.KIND_CLUB:
        raise Http404('Este tipo de workspace ya no está soportado.')
    feedback = str(request.session.pop('platform_feedback', '') or '')
    error = str(request.session.pop('platform_error', '') or '')
    can_manage_workspace = _can_manage_workspace(request.user, workspace)
    invite_link = ''
    competition_search_inputs = {
        'provider': WorkspaceCompetitionContext.PROVIDER_MANUAL,
        'team_query': str(getattr(workspace.primary_team, 'name', '') or '').strip(),
        'competition_query': str(getattr(getattr(getattr(getattr(workspace.primary_team, 'group', None), 'season', None), 'competition', None), 'name', '') or '').strip(),
        'group_query': str(getattr(getattr(workspace.primary_team, 'group', None), 'name', '') or '').strip(),
    }
    competition_search_results = []
    if request.method == 'POST':
        form_action = (request.POST.get('form_action') or '').strip().lower()
        if not can_manage_workspace:
            error = 'No tienes permisos para modificar este workspace.'
        elif form_action == 'split_workspace_categories':
            confirm_phrase = str(request.POST.get('confirm_phrase') or '').strip().upper()
            disable_source = str(request.POST.get('disable_source_workspace') or '').strip().lower() in {'1', 'true', 'on', 'yes'}
            if confirm_phrase != 'SEPARAR':
                error = 'Confirmación inválida. Escribe la palabra SEPARAR.'
            else:
                try:
                    from football.workspace_split import (
                        apply_split_workspace_plan,
                        build_split_workspace_plan,
                    )

                    plan_rows = build_split_workspace_plan(workspace)
                    if not plan_rows:
                        raise ValueError('Este club no tiene varias categorías que separar.')
                    created = apply_split_workspace_plan(
                        workspace,
                        plan_rows,
                        disable_source_workspace=disable_source,
                        include_primary=False,
                    )
                    created_ids = [int(ws.id) for ws in created if getattr(ws, 'id', None)]
                    created_slugs = [str(ws.slug or '').strip() for ws in created if str(getattr(ws, 'slug', '') or '').strip()]
                    request.session['platform_feedback'] = (
                        f'Separación completada. Clubs creados: {", ".join(created_slugs) if created_slugs else len(created_ids)}.'
                    )
                    _audit(
                        request,
                        'workspace_split',
                        workspace=workspace,
                        message='Separación de categorías ejecutada',
                        payload={'created_ids': created_ids, 'created_slugs': created_slugs, 'disable_source': disable_source},
                    )
                    return redirect('platform-overview')
                except ValueError as exc:
                    error = str(exc)
                except Exception:
                    error = 'No se pudo separar el club. Revisa el log.'
        elif form_action == 'update_workspace_identity':
            workspace_name = _sanitize_task_text((request.POST.get('workspace_name') or '').strip(), multiline=False, max_len=160)
            owner_username = _sanitize_username(request.POST.get('owner_username'), max_len=150)
            workspace_notes = _sanitize_task_text((request.POST.get('workspace_notes') or '').strip(), multiline=True, max_len=1200)
            team_id = _parse_int(request.POST.get('team_id'))
            is_active = str(request.POST.get('workspace_is_active') or '').lower() in {'1', 'true', 'on', 'yes'}
            try:
                if not workspace_name:
                    raise ValueError('Indica un nombre para el cliente.')
                owner_user = User.objects.filter(username__iexact=owner_username).first() if owner_username else None
                if owner_username and not owner_user:
                    raise ValueError(f'No existe el usuario propietario "{owner_username}".')
                if workspace.kind == Workspace.KIND_TASK_STUDIO and not owner_user:
                    raise ValueError('Task Studio requiere un usuario propietario.')
                if workspace.kind == Workspace.KIND_TASK_STUDIO and owner_user:
                    conflict = Workspace.objects.filter(kind=Workspace.KIND_TASK_STUDIO, owner_user=owner_user).exclude(id=workspace.id).first()
                    if conflict:
                        raise ValueError(f'El usuario {owner_user.username} ya tiene otro Task Studio.')
                old_owner = workspace.owner_user
                workspace.name = workspace_name
                workspace.owner_user = owner_user
                workspace.notes = workspace_notes
                workspace.is_active = is_active
                if workspace.kind == Workspace.KIND_CLUB:
                    workspace.primary_team = Team.objects.filter(id=team_id).first() if team_id else None
                workspace.save(update_fields=['name', 'owner_user', 'notes', 'is_active', 'primary_team', 'updated_at'])
                if workspace.kind == Workspace.KIND_CLUB and workspace.primary_team_id:
                    # Backfill seguro: garantiza que el equipo principal esté vinculado al workspace.
                    WorkspaceTeam.objects.get_or_create(
                        workspace_id=workspace.id,
                        team_id=workspace.primary_team_id,
                        defaults={'is_default': True},
                    )
                    if not WorkspaceTeam.objects.filter(workspace_id=workspace.id, is_default=True).exists():
                        first_link = WorkspaceTeam.objects.filter(workspace_id=workspace.id).order_by('id').first()
                        if first_link:
                            WorkspaceTeam.objects.filter(id=first_link.id).update(is_default=True)
                if owner_user:
                    WorkspaceMembership.objects.update_or_create(
                        workspace=workspace,
                        user=owner_user,
                        defaults={'role': WorkspaceMembership.ROLE_OWNER},
                    )
                if old_owner and (not owner_user or old_owner.id != owner_user.id):
                    old_membership = WorkspaceMembership.objects.filter(
                        workspace=workspace,
                        user=old_owner,
                        role=WorkspaceMembership.ROLE_OWNER,
                    ).first()
                    if old_membership:
                        old_membership.role = WorkspaceMembership.ROLE_ADMIN
                        old_membership.save(update_fields=['role'])
                if workspace.kind == Workspace.KIND_TASK_STUDIO:
                    if owner_user:
                        TaskStudioProfile.objects.update_or_create(
                            user=owner_user,
                            defaults={'workspace': workspace, 'is_enabled': True},
                        )
                    if old_owner and (not owner_user or old_owner.id != owner_user.id):
                        old_profile = TaskStudioProfile.objects.filter(user=old_owner, workspace=workspace).first()
                        if old_profile:
                            old_profile.workspace = None
                            old_profile.is_enabled = False
                            old_profile.save(update_fields=['workspace', 'is_enabled'])
                feedback = f'Cliente actualizado: {workspace.name}.'
            except ValueError as exc:
                error = str(exc)
            except Exception:
                error = 'No se pudo actualizar la configuración del club.'
        elif form_action == 'update_modules':
            module_catalog = _workspace_module_catalog(workspace.kind)
            selected_modules = {
                item['key']: str(request.POST.get(f"module_{item['key']}") or '').lower() in {'1', 'true', 'on', 'yes'}
                for item in module_catalog
            }
            selected_deliverables = {
                _workspace_deliverable_flag(item['key'], deliverable['key']): (
                    str(request.POST.get(f"deliverable_{item['key']}__{deliverable['key']}") or '').lower() in {'1', 'true', 'on', 'yes'}
                )
                for item in module_catalog
                for deliverable in item.get('deliverables', []) or []
            }
            enabled_modules = _expand_workspace_module_selection(workspace.kind, selected_modules, selected_deliverables)
            workspace.enabled_modules = enabled_modules
            workspace.save(update_fields=['enabled_modules', 'updated_at'])
            feedback = 'Módulos del workspace actualizados.'
        elif form_action == 'bootstrap_demo_data':
            if workspace.kind != Workspace.KIND_CLUB:
                error = 'Solo los clientes club pueden generar datos demo.'
            elif not workspace.primary_team_id:
                error = 'Asocia un equipo al workspace antes de generar datos demo.'
            else:
                try:
                    created = _bootstrap_demo_club_workspace(workspace)
                    feedback = (
                        'Datos demo generados. '
                        f"Jugadores: {created.get('players', 0)}, "
                        f"partidos: {created.get('matches', 0)}, "
                        f"eventos: {created.get('events', 0)}, "
                        f"sesiones: {created.get('sessions', 0)}, "
                        f"tareas: {created.get('tasks', 0)}, "
                        f"estadísticas: {created.get('stats', 0)}."
                    )
                except Exception:
                    error = 'No se pudieron generar los datos demo.'
        elif form_action == 'update_competition_context':
            if workspace.kind != Workspace.KIND_CLUB:
                error = 'Solo los clientes club tienen contexto competitivo.'
            else:
                provider = str(request.POST.get('competition_provider') or WorkspaceCompetitionContext.PROVIDER_MANUAL).strip()
                external_competition_key = str(request.POST.get('external_competition_key') or '').strip()[:140]
                external_group_key = str(request.POST.get('external_group_key') or '').strip()[:140]
                external_team_key = str(request.POST.get('external_team_key') or '').strip()[:140]
                external_team_name = _sanitize_task_text((request.POST.get('external_team_name') or '').strip(), multiline=False, max_len=160)
                auto_sync_enabled = str(request.POST.get('competition_auto_sync') or '').lower() in {'1', 'true', 'on', 'yes'}
                valid_providers = {choice[0] for choice in WorkspaceCompetitionContext.PROVIDER_CHOICES}
                if provider not in valid_providers:
                    provider = WorkspaceCompetitionContext.PROVIDER_MANUAL
                _bootstrap_workspace_competition_context(
                    workspace,
                    primary_team=workspace.primary_team,
                    provider=provider,
                    external_competition_key=external_competition_key,
                    external_group_key=external_group_key,
                    external_team_key=external_team_key,
                    external_team_name=external_team_name,
                    auto_sync_enabled=auto_sync_enabled,
                )
                if workspace.primary_team_id:
                    _invalidate_team_dashboard_caches(workspace.primary_team)
                feedback = 'Contexto competitivo actualizado.'
        elif form_action == 'sync_competition_context':
            if workspace.kind != Workspace.KIND_CLUB:
                error = 'Solo los clientes club se pueden sincronizar.'
            else:
                _, sync_error = _sync_workspace_competition_context(workspace, primary_team=workspace.primary_team)
                if sync_error:
                    error = sync_error
                else:
                    if workspace.primary_team_id:
                        _invalidate_team_dashboard_caches(workspace.primary_team)
                    feedback = 'Competición sincronizada para este club.'
        elif form_action == 'search_competition_context':
            if workspace.kind != Workspace.KIND_CLUB:
                error = 'Solo los clientes club tienen búsqueda competitiva.'
            else:
                competition_search_inputs = {
                    'provider': str(request.POST.get('competition_provider_search') or WorkspaceCompetitionContext.PROVIDER_MANUAL).strip(),
                    'team_query': _sanitize_task_text((request.POST.get('competition_team_query') or '').strip(), multiline=False, max_len=160),
                    'competition_query': _sanitize_task_text((request.POST.get('competition_competition_query') or '').strip(), multiline=False, max_len=160),
                    'group_query': _sanitize_task_text((request.POST.get('competition_group_query') or '').strip(), multiline=False, max_len=160),
                }
                valid_providers = {choice[0] for choice in WorkspaceCompetitionContext.PROVIDER_CHOICES}
                if competition_search_inputs['provider'] not in valid_providers:
                    competition_search_inputs['provider'] = WorkspaceCompetitionContext.PROVIDER_MANUAL
                if competition_search_inputs['provider'] == WorkspaceCompetitionContext.PROVIDER_UNIVERSO:
                    competition_search_results = _search_universo_competition_candidates(
                        team_query=competition_search_inputs['team_query'],
                        competition_query=competition_search_inputs['competition_query'],
                        group_query=competition_search_inputs['group_query'],
                    )
                else:
                    competition_search_results = _search_workspace_competition_candidates(
                        competition_search_inputs['provider'],
                        team_query=competition_search_inputs['team_query'],
                        competition_query=competition_search_inputs['competition_query'],
                        group_query=competition_search_inputs['group_query'],
                    )
                if competition_search_results:
                    feedback = f'Se encontraron {len(competition_search_results)} coincidencias para este club.'
                else:
                    error = 'No se encontraron coincidencias con los criterios indicados.'
        elif form_action == 'apply_competition_candidate':
            if workspace.kind != Workspace.KIND_CLUB:
                error = 'Solo los clientes club pueden vincular contexto competitivo.'
            else:
                candidate_team_id = _parse_int(request.POST.get('candidate_team_id'))
                candidate_team = (
                    Team.objects
                    .select_related('group__season__competition')
                    .filter(id=candidate_team_id)
                    .first()
                )
                provider = str(request.POST.get('candidate_provider') or WorkspaceCompetitionContext.PROVIDER_MANUAL).strip()
                valid_providers = {choice[0] for choice in WorkspaceCompetitionContext.PROVIDER_CHOICES}
                if provider not in valid_providers:
                    provider = WorkspaceCompetitionContext.PROVIDER_MANUAL
                auto_sync_enabled = str(request.POST.get('candidate_auto_sync') or '').lower() in {'1', 'true', 'on', 'yes'}
                external_competition_key = str(request.POST.get('candidate_external_competition_key') or '').strip()[:140]
                external_group_key = str(request.POST.get('candidate_external_group_key') or '').strip()[:140]
                external_team_key = str(request.POST.get('candidate_external_team_key') or '').strip()[:140]
                external_team_name = _sanitize_task_text((request.POST.get('candidate_external_team_name') or '').strip(), multiline=False, max_len=160)
                if not candidate_team and provider == WorkspaceCompetitionContext.PROVIDER_UNIVERSO:
                    candidate_team, import_error = _import_universo_competition_candidate(
                        competition_key=external_competition_key,
                        group_key=external_group_key,
                        team_key=external_team_key,
                        team_name=external_team_name,
                    )
                    if import_error:
                        error = import_error
                if error:
                    pass
                elif not candidate_team or not getattr(candidate_team, 'group', None):
                    error = 'La coincidencia seleccionada no es válida.'
                else:
                    workspace.primary_team = candidate_team
                    workspace.save(update_fields=['primary_team', 'updated_at'])
                    _bootstrap_workspace_competition_context(
                        workspace,
                        primary_team=candidate_team,
                        provider=provider,
                        external_competition_key=external_competition_key,
                        external_group_key=external_group_key,
                        external_team_key=external_team_key,
                        external_team_name=external_team_name,
                        auto_sync_enabled=auto_sync_enabled,
                    )
                    _, sync_error = _sync_workspace_competition_context(workspace, primary_team=candidate_team)
                    if sync_error:
                        error = sync_error
                    else:
                        feedback = f'Cliente vinculado a {candidate_team.name} y sincronizado.'
        elif form_action == 'add_member':
            username = _sanitize_username(request.POST.get('member_username'), max_len=150)
            member_role = str(request.POST.get('member_role') or WorkspaceMembership.ROLE_MEMBER).strip()
            target_user = User.objects.filter(username__iexact=username).first() if username else None
            if not target_user:
                error = 'Usuario no encontrado para añadir al workspace.'
            elif member_role not in {choice[0] for choice in WorkspaceMembership.ROLE_CHOICES}:
                error = 'Rol de workspace no válido.'
            else:
                WorkspaceMembership.objects.update_or_create(
                    workspace=workspace,
                    user=target_user,
                    defaults={'role': member_role},
                )
                feedback = f'Usuario {target_user.username} vinculado al workspace.'
                _audit(
                    request,
                    'workspace_member_add',
                    workspace=workspace,
                    message='Miembro añadido al workspace',
                    payload={'user': target_user.username, 'role': member_role},
                )
        elif form_action == 'invite_member':
            # Invitación + alta opcional de usuario (para que pueda poner su contraseña).
            username = _sanitize_username(request.POST.get('invite_username'), max_len=150)
            full_name = _sanitize_task_text((request.POST.get('invite_full_name') or '').strip(), multiline=False, max_len=150)
            email = re.sub(r'\s+', '', str(request.POST.get('invite_email') or '').strip()).lower()[:190]
            app_role = str(request.POST.get('invite_app_role') or AppUserRole.ROLE_GUEST).strip()
            member_role = str(request.POST.get('invite_member_role') or WorkspaceMembership.ROLE_VIEWER).strip()
            validity_days = _parse_int(request.POST.get('invite_valid_days')) or 7
            validity_days = max(1, min(validity_days, 30))
            if member_role not in {choice[0] for choice in WorkspaceMembership.ROLE_CHOICES}:
                member_role = WorkspaceMembership.ROLE_VIEWER
            allowed_roles = {
                AppUserRole.ROLE_PLAYER,
                AppUserRole.ROLE_GUEST,
                AppUserRole.ROLE_COACH,
                AppUserRole.ROLE_FITNESS,
                AppUserRole.ROLE_GOALKEEPER,
                AppUserRole.ROLE_ANALYST,
            }
            if app_role not in allowed_roles:
                app_role = AppUserRole.ROLE_GUEST
            try:
                if not username:
                    raise ValueError('Indica un username para invitar.')
                username = re.sub(r'\s+', '', username).lower()[:150]
                first_name, last_name = _split_full_name(full_name)
                user_obj = User.objects.filter(username__iexact=username).first()
                if not user_obj:
                    user_obj = User.objects.create_user(
                        username=username,
                        email=email,
                        password=None,
                        first_name=first_name,
                        last_name=last_name,
                        is_active=False,
                    )
                else:
                    # Actualiza datos básicos si se proporcionan.
                    changed = False
                    if email and (user_obj.email or '').strip().lower() != email:
                        user_obj.email = email
                        changed = True
                    if full_name:
                        user_obj.first_name = first_name
                        user_obj.last_name = last_name
                        changed = True
                    if changed:
                        user_obj.save(update_fields=['email', 'first_name', 'last_name'])
                AppUserRole.objects.update_or_create(user=user_obj, defaults={'role': app_role})
                WorkspaceMembership.objects.update_or_create(
                    workspace=workspace,
                    user=user_obj,
                    defaults={'role': member_role},
                )
                # Reemplaza invitaciones previas no usadas.
                UserInvitation.objects.filter(user=user_obj, is_active=True, accepted_at__isnull=True).update(is_active=False)
                invitation = UserInvitation.objects.create(
                    user=user_obj,
                    token=UserInvitation.generate_token(),
                    email=(user_obj.email or '').strip(),
                    expires_at=timezone.now() + timedelta(days=validity_days),
                    created_by=request.user.get_username() if request.user.is_authenticated else '',
                    is_active=True,
                )
                invite_link = request.build_absolute_uri(reverse('user-invite-accept', args=[invitation.token]))
                feedback = f'Invitación generada para {user_obj.username}.'
                _audit(
                    request,
                    'workspace_invite',
                    workspace=workspace,
                    message='Invitación generada',
                    payload={'user': user_obj.username, 'app_role': app_role, 'member_role': member_role, 'days': validity_days},
                )
            except ValueError as exc:
                error = str(exc)
            except Exception:
                error = 'No se pudo generar la invitación.'
        elif form_action == 'update_member_role':
            membership_id = _parse_int(request.POST.get('membership_id'))
            member_role = str(request.POST.get('member_role') or WorkspaceMembership.ROLE_MEMBER).strip()
            membership = WorkspaceMembership.objects.filter(id=membership_id, workspace=workspace).select_related('user').first()
            if not membership:
                error = 'Miembro no encontrado.'
            elif member_role not in {choice[0] for choice in WorkspaceMembership.ROLE_CHOICES}:
                error = 'Rol de workspace no válido.'
            else:
                membership.role = member_role
                membership.save(update_fields=['role'])
                feedback = f'Rol actualizado para {membership.user.username}.'
                _audit(
                    request,
                    'workspace_member_role',
                    workspace=workspace,
                    message='Rol de miembro actualizado',
                    payload={'user': membership.user.username, 'role': member_role},
                )
        elif form_action == 'update_member_modules':
            membership_id = _parse_int(request.POST.get('membership_id'))
            membership = WorkspaceMembership.objects.filter(id=membership_id, workspace=workspace).select_related('user').first()
            if not membership:
                error = 'Miembro no encontrado.'
            else:
                catalog = _workspace_access_module_catalog(workspace.kind)
                module_access = {}
                for entry in catalog:
                    key = entry.get('key')
                    if not key:
                        continue
                    # Si el módulo no está activo en el workspace, no lo guardamos.
                    if not bool(_workspace_enabled_modules(workspace).get(key, False)):
                        continue
                    checked = str(request.POST.get(f"member_module_{key}") or '').lower() in {'1', 'true', 'on', 'yes'}
                    if not checked:
                        module_access[key] = False
                membership.module_access = module_access
                membership.save(update_fields=['module_access'])
                feedback = f'Permisos por módulo actualizados para {membership.user.username}.'
                _audit(
                    request,
                    'workspace_member_modules',
                    workspace=workspace,
                    message='Permisos por módulo actualizados',
                    payload={'user': membership.user.username, 'denied': sorted([k for k, v in module_access.items() if v is False])[:40]},
                )
        elif form_action == 'reset_member_modules':
            membership_id = _parse_int(request.POST.get('membership_id'))
            membership = WorkspaceMembership.objects.filter(id=membership_id, workspace=workspace).select_related('user').first()
            if not membership:
                error = 'Miembro no encontrado.'
            else:
                membership.module_access = {}
                membership.save(update_fields=['module_access'])
                feedback = f'Permisos por módulo restablecidos para {membership.user.username}.'
                _audit(
                    request,
                    'workspace_member_modules_reset',
                    workspace=workspace,
                    message='Permisos por módulo restablecidos',
                    payload={'user': membership.user.username},
                )
        elif form_action == 'remove_member':
            membership_id = _parse_int(request.POST.get('membership_id'))
            membership = WorkspaceMembership.objects.filter(id=membership_id, workspace=workspace).select_related('user').first()
            if not membership:
                error = 'Miembro no encontrado.'
            else:
                removed_username = membership.user.username
                membership.delete()
                feedback = f'Usuario {removed_username} eliminado del workspace.'
                _audit(
                    request,
                    'workspace_member_remove',
                    workspace=workspace,
                    message='Miembro eliminado del workspace',
                    payload={'user': removed_username},
                )
    club_player_count = Player.objects.filter(team=workspace.primary_team).count() if workspace.primary_team_id else 0
    memberships = list(
        WorkspaceMembership.objects
        .select_related('user')
        .filter(workspace=workspace)
        .order_by('role', 'user__username')
    )
    enabled_modules = _workspace_enabled_modules(workspace)
    module_catalog = _workspace_module_catalog_for_template(workspace.kind, enabled_modules)
    access_module_catalog = _workspace_access_module_catalog(workspace.kind)
    # Prepara filas de permisos por miembro para la plantilla (evita lookups dinámicos en template).
    for membership in memberships:
        raw_access = getattr(membership, 'module_access', None)
        if not isinstance(raw_access, dict):
            raw_access = {}
        membership_role = str(getattr(membership, 'role', '') or '')
        is_privileged = membership_role in {WorkspaceMembership.ROLE_OWNER, WorkspaceMembership.ROLE_ADMIN}
        rows = []
        for entry in access_module_catalog:
            key = entry.get('key')
            label = entry.get('label') or key
            ws_enabled = bool(enabled_modules.get(key, False)) if key else False
            allowed = ws_enabled and (is_privileged or (raw_access.get(key, True) is not False))
            rows.append({'key': key, 'label': label, 'workspace_enabled': ws_enabled, 'allowed': allowed})
        membership.access_module_rows = rows
    competition_context = None
    competition_snapshot = None
    competition_summary = None
    if workspace.kind == Workspace.KIND_CLUB:
        if not competition_search_results:
            competition_search_inputs = {
                'provider': WorkspaceCompetitionContext.PROVIDER_MANUAL,
                'team_query': str(getattr(workspace.primary_team, 'name', '') or '').strip(),
                'competition_query': str(getattr(getattr(getattr(getattr(workspace.primary_team, 'group', None), 'season', None), 'competition', None), 'name', '') or '').strip(),
                'group_query': str(getattr(getattr(workspace.primary_team, 'group', None), 'name', '') or '').strip(),
            }
        if workspace.primary_team_id:
            competition_context = _bootstrap_workspace_competition_context(workspace, primary_team=workspace.primary_team)
        if competition_context:
            competition_search_inputs['provider'] = getattr(competition_context, 'provider', WorkspaceCompetitionContext.PROVIDER_MANUAL)
            competition_snapshot = (
                WorkspaceCompetitionSnapshot.objects
                .filter(context=competition_context)
                .first()
            )
            # Importante: no ejecutar sincronizaciones externas en GET (puede bloquear Platform).
            # La sincronización se ejecuta explícitamente via POST `form_action=sync_competition_context`.
        snapshot_standings = competition_snapshot.standings_payload if competition_snapshot and isinstance(competition_snapshot.standings_payload, list) else []
        snapshot_next = competition_snapshot.next_match_payload if competition_snapshot and isinstance(competition_snapshot.next_match_payload, dict) else {}
        competition_summary = {
            'standings_count': len(snapshot_standings),
            'next_match_opponent': _payload_opponent_name(snapshot_next) or '',
            'next_match_round': str(snapshot_next.get('round') or '').strip() if isinstance(snapshot_next, dict) else '',
            'last_sync_at': competition_context.last_sync_at if competition_context else None,
        }
    module_cards = [
        {'title': 'Portada', 'description': 'Home, clasificación, próximo partido y contexto visual del cliente.', 'url': reverse('dashboard-home')},
        {'title': 'Estadísticas', 'description': 'KPIs de temporada, seguimiento individual y métricas manuales.', 'url': reverse('coach-role-trainer')},
        {'title': 'Cuerpo técnico', 'description': 'Hub del staff, plantilla técnica y áreas operativas del cliente.', 'url': reverse('coach-cards')},
        {'title': 'Partido', 'description': 'Convocatoria, 11 inicial y registro de acciones de matchday.', 'url': reverse('convocation')},
        {'title': 'Entrenamiento', 'description': 'Microciclos, sesiones, tareas, porteros, físico y ABP.', 'url': reverse('sessions')},
        {'title': 'Análisis', 'description': 'Rival, informes, scouting y lectura táctica del cliente seleccionado.', 'url': reverse('analysis')},
    ]
    workspace_team_links = list(
        WorkspaceTeam.objects
        .filter(workspace=workspace)
        .select_related('team')
        .order_by('-is_default', 'id')
    )
    is_multi_team_workspace = len(workspace_team_links) > 1
    split_plan_rows = []
    if is_multi_team_workspace:
        try:
            from football.workspace_split import build_split_workspace_plan  # lazy import

            split_plan_rows = build_split_workspace_plan(workspace)
        except Exception:
            split_plan_rows = []
    return render(
        request,
        'football/platform_workspace_detail.html',
        {
            'workspace': workspace,
            'active_workspace': _build_active_workspace_badge(request),
            'feedback': feedback,
            'error': error,
            'can_manage_workspace': can_manage_workspace,
            'club_player_count': club_player_count,
            'module_cards': module_cards,
            'memberships': memberships,
            'module_catalog': module_catalog,
            'enabled_modules': enabled_modules,
            'access_module_catalog': access_module_catalog,
            'workspace_role_choices': WorkspaceMembership.ROLE_CHOICES,
            'teams': list(Team.objects.order_by('name')[:200]),
            'competition_context': competition_context,
            'competition_snapshot': competition_snapshot,
            'competition_summary': competition_summary,
            'competition_provider_choices': WorkspaceCompetitionContext.PROVIDER_CHOICES,
            'competition_search_inputs': competition_search_inputs,
            'competition_search_results': competition_search_results,
            'invite_link': invite_link,
            'workspace_team_links': workspace_team_links,
            'is_multi_team_workspace': is_multi_team_workspace,
            'split_plan_rows': split_plan_rows,
        },
    )


@login_required
@require_POST
def platform_workspace_delete_page(request, workspace_id):
    workspace = Workspace.objects.select_related('owner_user', 'primary_team').filter(id=workspace_id).first()
    if not workspace:
        raise Http404('Workspace no encontrado')
    if not _can_manage_workspace(request.user, workspace):
        return HttpResponse('No tienes permisos para eliminar este workspace.', status=403)
    workspace_name = workspace.name
    workspace_id_value = workspace.id

    if workspace.kind == Workspace.KIND_TASK_STUDIO:
        owner_user = workspace.owner_user
        if owner_user:
            TaskStudioProfile.objects.update_or_create(
                user=owner_user,
                defaults={'workspace': None, 'is_enabled': False},
            )
        TaskStudioTask.objects.filter(workspace=workspace).delete()
        TaskStudioRosterPlayer.objects.filter(workspace=workspace).delete()
        TaskStudioProfile.objects.filter(workspace=workspace).exclude(user=owner_user).delete()
        WorkspaceMembership.objects.filter(workspace=workspace).delete()
        workspace.delete()
        if int(request.session.get('active_workspace_id') or 0) == int(workspace_id_value):
            request.session.pop('active_workspace_id', None)
        request.session['platform_feedback'] = f'Task Studio eliminado: {workspace_name}.'
        return redirect('platform-overview')

    if workspace.kind == Workspace.KIND_CLUB:
        confirm_slug = str(request.POST.get('confirm_slug') or '').strip()
        confirm_phrase = str(request.POST.get('confirm_phrase') or '').strip().upper()
        if confirm_slug != str(workspace.slug or '').strip() or confirm_phrase != 'ELIMINAR':
            request.session['platform_error'] = 'Confirmación inválida. Escribe el slug y la palabra ELIMINAR.'
            return redirect('platform-workspace-detail', workspace_id=workspace.id)
        primary_team = workspace.primary_team
        if primary_team and bool(getattr(primary_team, 'is_primary', False)):
            request.session['platform_error'] = 'No se puede eliminar el club principal desde Platform.'
            return redirect('platform-workspace-detail', workspace_id=workspace.id)
        workspace.delete()
        if int(request.session.get('active_workspace_id') or 0) == int(workspace_id_value):
            request.session.pop('active_workspace_id', None)
        mapping = request.session.get('active_team_by_workspace')
        if isinstance(mapping, dict):
            mapping.pop(str(workspace_id_value), None)
            mapping.pop(workspace_id_value, None)
            request.session['active_team_by_workspace'] = mapping
        request.session['platform_feedback'] = f'Club eliminado: {workspace_name}.'
        return redirect('platform-overview')

    return HttpResponse('Tipo de workspace no eliminable desde esta acción.', status=403)


@login_required
def platform_workspace_enter_page(request, workspace_id):
    workspace = Workspace.objects.select_related('owner_user', 'primary_team').filter(id=workspace_id, is_active=True).first()
    if not workspace:
        raise Http404('Workspace no encontrado')
    if not _can_view_workspace(request.user, workspace):
        return HttpResponse('No tienes permisos para acceder a este workspace.', status=403)
    request.session['active_workspace_id'] = workspace.id
    desired_team_id = _parse_int(request.GET.get('team'))
    if desired_team_id and workspace.kind == Workspace.KIND_CLUB:
        try:
            links = _workspace_team_links_for_user(workspace, request.user)
            allowed_team_ids = {int(getattr(link, 'team_id', 0) or 0) for link in links if getattr(link, 'team_id', None)}
            if int(desired_team_id) in allowed_team_ids and hasattr(request, 'session'):
                mapping = request.session.get('active_team_by_workspace')
                if not isinstance(mapping, dict):
                    mapping = {}
                mapping[str(workspace.id)] = int(desired_team_id)
                request.session['active_team_by_workspace'] = mapping
        except Exception:
            pass
    target_url = _workspace_entry_url(workspace, user=request.user)
    # En `app.*`, usuarios con acceso a Platform redirigen por defecto a Platform desde `/`.
    # Al entrar explícitamente en un cliente desde Platform, forzamos la home del club.
    try:
        dashboard_url = reverse('dashboard-home')
        if _can_access_platform(request.user) and str(target_url).split('?', 1)[0] == dashboard_url:
            target_url = f'{dashboard_url}?home=club'
    except Exception:
        pass
    return redirect(target_url)


@login_required
def platform_workspace_clear_page(request):
    if not _can_access_platform(request.user):
        return HttpResponse('No tienes permisos para acceder a la plataforma.', status=403)
    request.session.pop('active_workspace_id', None)
    return redirect('platform-overview')


def _handle_home_carousel_post(request):
    form_action = (request.POST.get('form_action') or '').strip().lower()

    if form_action == 'carousel_upload':
        uploaded = request.FILES.get('carousel_image')
        if uploaded:
            title = (request.POST.get('carousel_title') or '').strip()
            order = _parse_int(request.POST.get('carousel_order')) or 0
            is_active = str(request.POST.get('carousel_is_active') or '').lower() in {'1', 'true', 'on', 'yes'}
            HomeCarouselImage.objects.create(
                title=title,
                image=uploaded,
                order=order,
                is_active=is_active,
            )
        return True

    if form_action == 'carousel_update':
        image_id = _parse_int(request.POST.get('carousel_id'))
        item = HomeCarouselImage.objects.filter(id=image_id).first()
        if item:
            item.title = (request.POST.get('carousel_title') or '').strip()
            item.order = _parse_int(request.POST.get('carousel_order')) or 0
            item.is_active = str(request.POST.get('carousel_is_active') or '').lower() in {'1', 'true', 'on', 'yes'}
            item.save(update_fields=['title', 'order', 'is_active'])
        return True

    if form_action == 'carousel_delete':
        image_id = _parse_int(request.POST.get('carousel_id'))
        item = HomeCarouselImage.objects.filter(id=image_id).first()
        if item:
            if item.image:
                try:
                    item.image.delete(save=False)
                except Exception:
                    pass
            item.delete()
        return True
    return False


@login_required
@ensure_csrf_cookie
def admin_page(request):
    primary_team = _get_primary_team_for_request(request)
    workspace = _get_active_workspace(request)
    current_role = AppUserRole.objects.filter(user=request.user).values_list('role', flat=True).first()
    is_admin_user = bool(request.user.is_staff or current_role == AppUserRole.ROLE_ADMIN)
    # Platform admins pueden entrar sin workspace activo; si hay un único club, lo usamos como fallback.
    if not workspace and primary_team:
        try:
            workspace = Workspace.objects.filter(kind=Workspace.KIND_CLUB, is_active=True, primary_team=primary_team).first()
            if workspace and hasattr(request, 'session'):
                request.session['active_workspace_id'] = workspace.id
        except Exception:
            workspace = workspace
    can_manage_workspace = bool(_can_manage_workspace(request.user, workspace)) if workspace else False
    roster_message = ''
    roster_error = ''
    actions_message = ''
    actions_error = ''
    teams_message = ''
    teams_error = ''
    active_tab = (request.GET.get('tab') or request.POST.get('active_tab') or 'roster').strip().lower()
    if active_tab in {'carousel', 'users'}:
        target_anchor = '#home-global' if active_tab == 'carousel' else '#usuarios-club'
        return redirect(f"{reverse('platform-overview')}{target_anchor}")
    if active_tab not in {'roster', 'actions', 'teams'}:
        active_tab = 'roster'

    if request.method == 'POST':
        form_action = (request.POST.get('form_action') or '').strip()
        if form_action in {
            'carousel_upload',
            'carousel_update',
            'carousel_delete',
            'user_create',
            'user_update',
            'user_invite_create',
            'user_update_role',
            'user_toggle_active',
        }:
            target_anchor = '#home-global' if form_action.startswith('carousel_') else '#usuarios-club'
            return redirect(f"{reverse('platform-overview')}{target_anchor}")
        if form_action in {'roster_add_or_update', 'roster_deactivate', 'roster_reactivate', 'crest_import_zip'} and primary_team:
            active_tab = 'roster'
            if form_action == 'crest_import_zip':
                if not is_admin_user:
                    roster_error = 'Solo administradores pueden subir escudos.'
                else:
                    uploaded_zip = request.FILES.get('crest_zip')
                    if not uploaded_zip:
                        roster_error = 'Sube un ZIP con los escudos (png/jpg/webp).'
                    else:
                        allowed_ext = {'.png', '.jpg', '.jpeg', '.webp'}
                        group_teams = list(
                            Team.objects
                            .filter(group=primary_team.group)
                            .only('id', 'name', 'slug', 'short_name', 'external_id', 'crest_url', 'crest_image')
                        )

                        def _team_keys(team_obj):
                            candidates = set()
                            for raw in (
                                getattr(team_obj, 'slug', ''),
                                getattr(team_obj, 'external_id', ''),
                                getattr(team_obj, 'name', ''),
                                getattr(team_obj, 'short_name', ''),
                                getattr(team_obj, 'display_name', ''),
                            ):
                                val = str(raw or '').strip()
                                if not val:
                                    continue
                                candidates.add(val.lower())
                                candidates.add(normalize_label(val))
                                candidates.add(_normalize_team_lookup_key(val))
                            return {key for key in candidates if key}

                        lookup = {}
                        for team in group_teams:
                            for key in _team_keys(team):
                                lookup.setdefault(key, team)

                        imported = 0
                        unknown = []
                        skipped = 0

                        def _match_team(filename):
                            stem = Path(filename).stem
                            base = str(stem or '').strip()
                            if not base:
                                return None
                            candidates = [
                                base.lower(),
                                normalize_label(base),
                                _normalize_team_lookup_key(base),
                            ]
                            for key in candidates:
                                if key and lookup.get(key):
                                    return lookup[key]
                            # Fuzzy: por inclusión (evita casos como "C.D. CANTORIA 2017 F.C.")
                            base_key = _normalize_team_lookup_key(base)
                            if base_key:
                                for key, team_obj in lookup.items():
                                    if key and (base_key in key or key in base_key):
                                        return team_obj
                            return None

                        try:
                            uploaded_zip.seek(0)
                            with zipfile.ZipFile(uploaded_zip) as zf:
                                for info in zf.infolist():
                                    if info.is_dir():
                                        continue
                                    inner_name = Path(info.filename).name
                                    ext = Path(inner_name).suffix.lower()
                                    if ext not in allowed_ext:
                                        skipped += 1
                                        continue
                                    if info.file_size and info.file_size > 5 * 1024 * 1024:
                                        skipped += 1
                                        continue
                                    team_obj = _match_team(inner_name)
                                    if not team_obj:
                                        unknown.append(inner_name)
                                        continue
                                    try:
                                        blob = zf.read(info)
                                    except Exception:
                                        skipped += 1
                                        continue
                                    if not blob:
                                        skipped += 1
                                        continue
                                    content = ContentFile(blob)
                                    content.name = inner_name
                                    # Guardar en MEDIA (S3 si está activo).
                                    try:
                                        team_obj.crest_image.save(f'{team_obj.slug}{ext}', content, save=True)
                                        if team_obj.crest_url:
                                            team_obj.crest_url = ''
                                            team_obj.save(update_fields=['crest_url'])
                                        _invalidate_team_dashboard_caches(team_obj)
                                        imported += 1
                                    except Exception:
                                        skipped += 1
                        except zipfile.BadZipFile:
                            roster_error = 'El archivo no es un ZIP válido.'
                        except Exception:
                            roster_error = 'No se pudieron importar los escudos.'

                        if not roster_error:
                            roster_message = f'Escudos importados: {imported}.'
                            if skipped:
                                roster_message += f' Saltados: {skipped}.'
                            if unknown:
                                unknown_preview = ', '.join(unknown[:6])
                                roster_message += f' Sin equipo asociado: {unknown_preview}'
                                if len(unknown) > 6:
                                    roster_message += f' (+{len(unknown) - 6}).'
                roster_players = list(Player.objects.filter(team=primary_team).order_by('name'))
                return render(
                    request,
                    'football/admin.html',
                    {
                        'primary_team': primary_team,
                        'team_name': getattr(primary_team, 'display_name', None) or getattr(primary_team, 'name', ''),
                        'is_admin_user': is_admin_user,
                        'active_tab': active_tab,
                        'roster_message': roster_message,
                        'roster_error': roster_error,
                        'roster_players': roster_players,
                        'actions_message': actions_message,
                        'actions_error': actions_error,
                    },
                )
            player_id = _parse_int(request.POST.get('player_id'))
            name = (request.POST.get('name') or '').strip()
            number_raw = (request.POST.get('number') or '').strip()
            position = (request.POST.get('position') or '').strip()
            is_active = str(request.POST.get('is_active') or '1').strip().lower() in {'1', 'true', 'on', 'yes'}
            try:
                if form_action in {'roster_deactivate', 'roster_reactivate'}:
                    if not player_id:
                        raise ValueError('Jugador no válido.')
                    player = Player.objects.filter(id=player_id, team=primary_team).first()
                    if not player:
                        raise ValueError('Jugador no encontrado.')
                    player.is_active = form_action == 'roster_reactivate'
                    player.save(update_fields=['is_active'])
                    roster_message = (
                        f'{player.name} reactivado correctamente.'
                        if player.is_active
                        else f'{player.name} marcado como inactivo.'
                    )
                else:
                    if not name:
                        raise ValueError('El nombre es obligatorio.')
                    number = _parse_int(number_raw) if number_raw else None
                    player = (
                        Player.objects.filter(team=primary_team, name__iexact=name)
                        .order_by('id')
                        .first()
                    )
                    if player:
                        player.number = number
                        player.position = position
                        player.is_active = is_active
                        player.save(update_fields=['number', 'position', 'is_active'])
                        roster_message = f'Jugador actualizado: {player.name}.'
                    else:
                        Player.objects.create(
                            team=primary_team,
                            name=name,
                            number=number,
                            position=position,
                            is_active=is_active,
                        )
                        roster_message = f'Jugador añadido: {name}.'
            except ValueError as exc:
                roster_error = str(exc)
            except Exception:
                roster_error = 'No se pudo guardar la plantilla.'
        elif form_action in {'team_create', 'team_update', 'team_set_default', 'team_unlink', 'team_split_workspace'}:
            active_tab = 'teams'
            if not workspace or workspace.kind != Workspace.KIND_CLUB:
                teams_error = 'No hay cliente club activo.'
            elif not can_manage_workspace:
                teams_error = 'No tienes permisos para gestionar este club.'
            else:
                def _unique_group_slug(season_obj, base_value):
                    base_slug = slugify(base_value)[:80] or 'grupo'
                    candidate = base_slug
                    suffix = 2
                    while Group.objects.filter(season=season_obj, slug=candidate).exists():
                        candidate = f'{base_slug}-{suffix}'
                        suffix += 1
                    return candidate

                try:
                    if form_action == 'team_set_default':
                        link_id = _parse_int(request.POST.get('workspace_team_id'))
                        link = WorkspaceTeam.objects.filter(id=link_id, workspace=workspace).first() if link_id else None
                        if not link:
                            raise ValueError('Categoría no válida.')
                        WorkspaceTeam.objects.filter(workspace=workspace, is_default=True).exclude(id=link.id).update(is_default=False)
                        if not link.is_default:
                            link.is_default = True
                            link.save(update_fields=['is_default'])
                        teams_message = 'Categoría predeterminada actualizada.'
                    elif form_action == 'team_split_workspace':
                        link_id = _parse_int(request.POST.get('workspace_team_id'))
                        link = (
                            WorkspaceTeam.objects
                            .filter(id=link_id, workspace=workspace)
                            .select_related('team')
                            .first()
                            if link_id else None
                        )
                        if not link or not link.team:
                            raise ValueError('Categoría no válida.')
                        if link.is_default:
                            raise ValueError('No puedes separar la categoría predeterminada. Elige otra antes.')
                        team_obj = link.team
                        if Workspace.objects.filter(kind=Workspace.KIND_CLUB, primary_team=team_obj).exists():
                            raise ValueError('Ese equipo ya está vinculado a otro club. No se puede separar dos veces.')

                        category_label = str(getattr(team_obj, 'category', '') or '').strip() or str(getattr(team_obj, 'display_name', '') or getattr(team_obj, 'name', '') or '').strip()
                        new_workspace_name = f'{str(getattr(workspace, "name", "") or "").strip()} · {category_label}'.strip(' ·')
                        new_workspace_name = _sanitize_task_text(new_workspace_name, multiline=False, max_len=160)
                        if not new_workspace_name:
                            new_workspace_name = f'Club {team_obj.id}'
                        new_slug = _unique_workspace_slug(new_workspace_name)

                        with transaction.atomic():
                            new_workspace = Workspace.objects.create(
                                name=new_workspace_name,
                                slug=new_slug,
                                kind=Workspace.KIND_CLUB,
                                primary_team=team_obj,
                                owner_user=workspace.owner_user,
                                enabled_modules=dict(getattr(workspace, 'enabled_modules', None) or {}),
                                trial_expires_at=getattr(workspace, 'trial_expires_at', None),
                                subscription_status=str(getattr(workspace, 'subscription_status', '') or 'trial').strip() or 'trial',
                                plan_key=str(getattr(workspace, 'plan_key', '') or '').strip(),
                                is_active=bool(getattr(workspace, 'is_active', True)),
                                notes=f'Separado automáticamente desde {workspace.name}.',
                            )
                            memberships = list(
                                WorkspaceMembership.objects
                                .select_related('user')
                                .filter(workspace=workspace)
                            )
                            for membership in memberships:
                                if not membership.user_id:
                                    continue
                                WorkspaceMembership.objects.update_or_create(
                                    workspace=new_workspace,
                                    user=membership.user,
                                    defaults={'role': membership.role},
                                )
                            if new_workspace.owner_user_id:
                                WorkspaceMembership.objects.update_or_create(
                                    workspace=new_workspace,
                                    user_id=new_workspace.owner_user_id,
                                    defaults={'role': WorkspaceMembership.ROLE_OWNER},
                                )

                            WorkspaceTeam.objects.get_or_create(
                                workspace=new_workspace,
                                team=team_obj,
                                defaults={'is_default': True},
                            )
                            if new_workspace.owner_user_id:
                                WorkspaceTeamAccess.objects.update_or_create(
                                    workspace=new_workspace,
                                    team=team_obj,
                                    user_id=new_workspace.owner_user_id,
                                    defaults={'is_default': True},
                                )

                            # Mover contexto/snapshot competitivo de esta categoría al nuevo club (si existe).
                            try:
                                ctx = WorkspaceCompetitionContext.objects.filter(workspace=workspace, team=team_obj).first()
                            except Exception:
                                ctx = None
                            if ctx:
                                ctx.workspace = new_workspace
                                ctx.save(update_fields=['workspace', 'updated_at'])
                                snap = getattr(ctx, 'snapshot', None)
                                if snap:
                                    snap.workspace = new_workspace
                                    snap.save(update_fields=['workspace', 'updated_at'])

                            WorkspaceTeamAccess.objects.filter(workspace=workspace, team=team_obj).delete()
                            link.delete()

                        teams_message = f'Categoría separada como club independiente: {new_workspace.name}.'
                    elif form_action == 'team_unlink':
                        link_id = _parse_int(request.POST.get('workspace_team_id'))
                        link = WorkspaceTeam.objects.filter(id=link_id, workspace=workspace).select_related('team').first() if link_id else None
                        if not link:
                            raise ValueError('Categoría no válida.')
                        if link.is_default:
                            raise ValueError('No puedes eliminar la categoría predeterminada. Elige otra antes.')
                        link.delete()
                        teams_message = 'Equipo desvinculado del club.'
                    elif form_action == 'team_update':
                        link_id = _parse_int(request.POST.get('workspace_team_id'))
                        link = WorkspaceTeam.objects.filter(id=link_id, workspace=workspace).select_related('team').first() if link_id else None
                        if not link or not link.team:
                            raise ValueError('Categoría no válida.')
                        team_obj = link.team
                        category = str(request.POST.get('category') or '').strip()[:24]
                        game_format = str(request.POST.get('game_format') or Team.GAME_FORMAT_F11).strip().lower()
                        group_external_id = str(request.POST.get('group_external_id') or '').strip()[:80]
                        competition_name = str(request.POST.get('competition_name') or '').strip()[:150]
                        season_name = str(request.POST.get('season_name') or '').strip()[:80]
                        group_name = str(request.POST.get('group_name') or '').strip()[:80]
                        universo_url = str(request.POST.get('universo_url') or '').strip()
                        universo_competition_key = ''
                        # Si se pega URL de Universo, intentamos resolver el grupo correcto (evita mezclar categorías).
                        if universo_url:
                            # 1) Fallback mínimo: querystring (?group=, ?competition=, etc.).
                            try:
                                parsed = urlparse(universo_url)
                                qs = parse_qs(parsed.query or '')
                                url_group = str((qs.get('group') or [''])[0] or '').strip()
                                url_comp = str((qs.get('competition') or [''])[0] or '').strip()
                                # Resultados: el ID de competición a veces viene en el path.
                                match = re.search(r'/competitions/(?:results|classification)/(\d+)', parsed.path or '')
                                if match and not url_comp:
                                    url_comp = str(match.group(1) or '').strip()
                                if url_group:
                                    group_external_id = url_group[:80]
                                if url_comp and not universo_competition_key:
                                    universo_competition_key = url_comp
                            except Exception:
                                pass
                            # 2) Autodetección: usa competition/delegation/season de la URL para buscar un grupo
                            # cuya clasificación corresponda a la categoría (prebenjamín, etc).
                            try:
                                resolved = _universo_find_group_for_team_from_url(
                                    universo_url=universo_url,
                                    category=category,
                                    team_name=str(getattr(team_obj, 'name', '') or '').strip(),
                                )
                            except Exception:
                                resolved = {}
                            if isinstance(resolved, dict) and resolved.get('group_id'):
                                group_external_id = str(resolved.get('group_id') or '').strip()[:80]
                                resolved_competition = str(resolved.get('competition_name') or '').strip()
                                resolved_group = str(resolved.get('group_name') or '').strip()
                                universo_competition_key = str(resolved.get('competition_code') or '').strip()
                                if resolved_competition:
                                    competition_name = resolved_competition[:150]
                                if resolved_group:
                                    group_name = resolved_group[:80]
                        update_fields = []
                        uploaded_cover = None
                        try:
                            uploaded_cover = request.FILES.get('cover_image')
                        except Exception:
                            uploaded_cover = None
                        if category != str(getattr(team_obj, 'category', '') or '').strip():
                            team_obj.category = category
                            update_fields.append('category')
                        if game_format in {Team.GAME_FORMAT_F7, Team.GAME_FORMAT_F11} and game_format != team_obj.game_format:
                            team_obj.game_format = game_format
                            update_fields.append('game_format')
                        if uploaded_cover:
                            try:
                                existing_cover = getattr(team_obj, 'cover_image', None)
                                if existing_cover:
                                    existing_cover.delete(save=False)
                            except Exception:
                                pass
                            team_obj.cover_image = uploaded_cover
                            try:
                                team_obj.cover_updated_at = timezone.now()
                                update_fields.append('cover_updated_at')
                            except Exception:
                                pass
                            update_fields.append('cover_image')
                        # Si el usuario define (o corrige) la liga/grupo, re-vinculamos el team a un Group propio.
                        should_rebind_group = bool(competition_name or season_name or group_name or group_external_id or universo_url)
                        if should_rebind_group:
                            # Defaults si faltan:
                            # - Si se está usando Universo (group_external_id/url), NO heredamos valores del grupo previo
                            #   (evita que Prebenjamín quede "enganchado" a Senior).
                            # - En caso contrario, mantenemos el fallback legacy al grupo actual.
                            is_universo_binding = bool(group_external_id or universo_url)
                            if is_universo_binding:
                                # Autocompletar desde Universo para evitar errores típicos:
                                # el formulario viene precargado con la competición/grupo del Senior y,
                                # si el admin solo pega el ID del grupo, acaba mezclando categorías.
                                if group_external_id:
                                    try:
                                        resolved_from_url = False
                                        live = _fetch_universo_live_classification(group_external_id)
                                        if isinstance(live, dict):
                                            # Si el grupo no corresponde a la categoría (p.ej. Prebenjamín),
                                            # intentamos resolverlo desde la URL si está disponible.
                                            if universo_url and not _universo_payload_matches_category(live, category):
                                                try:
                                                    resolved = _universo_find_group_for_team_from_url(
                                                        universo_url=universo_url,
                                                        category=category,
                                                        team_name=str(getattr(team_obj, 'name', '') or '').strip(),
                                                    )
                                                except Exception:
                                                    resolved = {}
                                                if isinstance(resolved, dict) and resolved.get('group_id'):
                                                    group_external_id = str(resolved.get('group_id') or '').strip()[:80]
                                                    live = _fetch_universo_live_classification(group_external_id)
                                                    resolved_from_url = True
                                            resolved_competition = str(live.get('competicion') or '').strip()
                                            resolved_group = str(live.get('grupo') or '').strip()
                                            universo_competition_key = str(live.get('codigo_competicion') or '').strip()
                                            # Si Universo nos devuelve valores, los usamos SIEMPRE como fuente de verdad.
                                            # Esto evita que se queden los del Senior por venir precargados en el form.
                                            # Guardrail: si no se pudo resolver y sigue sin cuadrar por categoría,
                                            # no pisamos los campos del formulario (evita mezclar Senior/Prebenjamín).
                                            allow_override = True
                                            if universo_url and not resolved_from_url and not _universo_payload_matches_category(live, category):
                                                allow_override = False
                                            if allow_override and resolved_competition:
                                                competition_name = resolved_competition[:150]
                                            if allow_override and resolved_group:
                                                group_name = resolved_group[:80]
                                    except Exception:
                                        pass
                                if group_external_id and not group_name:
                                    group_name = f'Grupo {group_external_id}'[:80]
                                if not group_name:
                                    group_name = 'Grupo 1'
                                if not competition_name:
                                    competition_name = 'Universo RFAF'
                                if not season_name:
                                    try:
                                        if workspace and getattr(getattr(getattr(workspace, 'primary_team', None), 'group', None), 'season', None):
                                            season_name = str(workspace.primary_team.group.season.name or '').strip()[:80]
                                    except Exception:
                                        season_name = ''
                            else:
                                if not season_name and getattr(getattr(team_obj.group, 'season', None), 'name', None):
                                    season_name = str(team_obj.group.season.name or '').strip()[:80]
                                if not group_name and getattr(team_obj.group, 'name', None):
                                    group_name = str(team_obj.group.name or '').strip()[:80]
                                if not competition_name and getattr(getattr(getattr(team_obj.group, 'season', None), 'competition', None), 'name', None):
                                    competition_name = str(team_obj.group.season.competition.name or '').strip()[:150]
                            competition_name = competition_name or 'Liga'
                            season_name = season_name or f'{timezone.localdate().year}/{timezone.localdate().year + 1}'
                            group_name = group_name or 'Grupo 1'
                            comp_slug = slugify(competition_name)[:150] or 'liga'
                            competition_obj, _ = Competition.objects.get_or_create(
                                name=competition_name,
                                region='',
                                defaults={'slug': comp_slug},
                            )
                            season_obj, _ = Season.objects.get_or_create(
                                competition=competition_obj,
                                name=season_name,
                                defaults={'is_current': True},
                            )
                            target_group = None
                            if group_external_id:
                                target_group = Group.objects.filter(season=season_obj, external_id=group_external_id).first()
                            if not target_group:
                                target_group = Group.objects.filter(season=season_obj, name__iexact=group_name).first() if not group_external_id else None
                            if not target_group:
                                group_slug = _unique_group_slug(season_obj, f'{group_name}-{group_external_id}' if group_external_id else group_name)
                                group_defaults = {'name': group_name}
                                if group_external_id:
                                    group_defaults['external_id'] = group_external_id
                                target_group, _ = Group.objects.get_or_create(
                                    season=season_obj,
                                    slug=group_slug,
                                    defaults=group_defaults,
                                )
                            if group_external_id and target_group and str(getattr(target_group, 'external_id', '') or '').strip() != group_external_id:
                                target_group.external_id = group_external_id
                                target_group.save(update_fields=['external_id'])
                            if target_group and team_obj.group_id != target_group.id:
                                team_obj.group = target_group
                                update_fields.append('group')
                        group_changed = 'group' in update_fields
                        if update_fields:
                            team_obj.save(update_fields=update_fields)
                        if group_changed:
                            # Si cambia el group, borramos snapshot/contexto previo para forzar resync
                            # y evitar mezclar clasificaciones entre categorías.
                            try:
                                WorkspaceCompetitionSnapshot.objects.filter(context__workspace=workspace, context__team=team_obj).delete()
                            except Exception:
                                pass
                            try:
                                WorkspaceCompetitionContext.objects.filter(workspace=workspace, team=team_obj).update(
                                    sync_status=WorkspaceCompetitionContext.STATUS_PENDING,
                                    sync_error='',
                                )
                            except Exception:
                                pass
                        # Si el admin está vinculando un ID de grupo de Universo RFAF, forzamos el
                        # contexto competitivo del equipo a Universo y guardamos el group_key.
                        universo_group_id = str(group_external_id or '').strip()
                        if universo_group_id:
                            try:
                                contexto = _bootstrap_workspace_competition_context(
                                    workspace,
                                    primary_team=team_obj,
                                    provider=WorkspaceCompetitionContext.PROVIDER_UNIVERSO,
                                    external_competition_key=universo_competition_key or None,
                                    external_group_key=universo_group_id,
                                    external_team_name=str(getattr(team_obj, 'name', '') or '').strip(),
                                    external_source_url=universo_url or None,
                                    auto_sync_enabled=True,
                                )
                                if contexto:
                                    # Forzamos un refresh limpio para evitar que se quede la clasificación del Senior.
                                    WorkspaceCompetitionSnapshot.objects.filter(context=contexto).delete()
                                    contexto.sync_status = WorkspaceCompetitionContext.STATUS_PENDING
                                    contexto.sync_error = ''
                                    contexto.save(update_fields=['sync_status', 'sync_error', 'updated_at'])
                            except Exception:
                                pass
                        elif universo_url:
                            # Aunque no tengamos ID de grupo, persistimos la URL para que quede guardada en Admin.
                            try:
                                contexto = _bootstrap_workspace_competition_context(
                                    workspace,
                                    primary_team=team_obj,
                                    external_source_url=universo_url,
                                )
                                if contexto:
                                    contexto.external_source_url = universo_url
                                    contexto.save(update_fields=['external_source_url', 'updated_at'])
                            except Exception:
                                pass
                        # Invalidar cachés del equipo por si cambia su contexto o se corrige la clasificación.
                        try:
                            _invalidate_team_dashboard_caches(team_obj)
                        except Exception:
                            pass
                        teams_message = 'Categoría actualizada.'
                    else:  # team_create
                        category = str(request.POST.get('category') or '').strip()
                        if not category:
                            raise ValueError('La categoría es obligatoria (ej. Prebenjamín, Cadete, Senior).')
                        category = category[:24]
                        game_format = str(request.POST.get('game_format') or Team.GAME_FORMAT_F11).strip().lower()
                        if game_format not in {Team.GAME_FORMAT_F7, Team.GAME_FORMAT_F11}:
                            game_format = Team.GAME_FORMAT_F11
                        team_base_name = str(request.POST.get('team_name') or '').strip()[:150]
                        if not team_base_name and workspace.primary_team_id:
                            team_base_name = str(getattr(workspace.primary_team, 'name', '') or '').strip()[:150]
                        if not team_base_name:
                            raise ValueError('El nombre del club/equipo es obligatorio.')
                        competition_name = str(request.POST.get('competition_name') or '').strip()[:150]
                        season_name = str(request.POST.get('season_name') or '').strip()[:80]
                        group_name = str(request.POST.get('group_name') or '').strip()[:80]
                        group_external_id = str(request.POST.get('group_external_id') or '').strip()[:80]
                        universo_url = str(request.POST.get('universo_url') or '').strip()
                        universo_competition_key = ''
                        if universo_url:
                            # 1) Fallback mínimo: querystring (?group=, ?competition=, etc.).
                            try:
                                parsed = urlparse(universo_url)
                                qs = parse_qs(parsed.query or '')
                                url_group = str((qs.get('group') or [''])[0] or '').strip()
                                url_comp = str((qs.get('competition') or [''])[0] or '').strip()
                                match = re.search(r'/competitions/(?:results|classification)/(\d+)', parsed.path or '')
                                if match and not url_comp:
                                    url_comp = str(match.group(1) or '').strip()
                                if url_group:
                                    group_external_id = url_group[:80]
                                if url_comp and not universo_competition_key:
                                    universo_competition_key = url_comp
                            except Exception:
                                pass
                            # 2) Autodetección por categoría desde la URL (competition/delegation/season)
                            try:
                                resolved = _universo_find_group_for_team_from_url(
                                    universo_url=universo_url,
                                    category=category,
                                    team_name=team_base_name,
                                )
                            except Exception:
                                resolved = {}
                            if isinstance(resolved, dict) and resolved.get('group_id'):
                                group_external_id = str(resolved.get('group_id') or '').strip()[:80]
                                resolved_competition = str(resolved.get('competition_name') or '').strip()
                                resolved_group = str(resolved.get('group_name') or '').strip()
                                universo_competition_key = str(resolved.get('competition_code') or '').strip()
                                if resolved_competition:
                                    competition_name = resolved_competition[:150]
                                if resolved_group:
                                    group_name = resolved_group[:80]
                        if group_external_id:
                            # Autocompletar nombres desde Universo si el token está disponible.
                            try:
                                resolved_from_url = False
                                live = _fetch_universo_live_classification(group_external_id)
                                if isinstance(live, dict):
                                    # Si el grupo no corresponde a la categoría, intentamos resolverlo desde la URL.
                                    if universo_url and not _universo_payload_matches_category(live, category):
                                        try:
                                            resolved = _universo_find_group_for_team_from_url(
                                                universo_url=universo_url,
                                                category=category,
                                                team_name=team_base_name,
                                            )
                                        except Exception:
                                            resolved = {}
                                        if isinstance(resolved, dict) and resolved.get('group_id'):
                                            group_external_id = str(resolved.get('group_id') or '').strip()[:80]
                                            live = _fetch_universo_live_classification(group_external_id)
                                            resolved_from_url = True
                                    universo_competition_key = str(live.get('codigo_competicion') or '').strip()
                                    resolved_competition = str(live.get('competicion') or '').strip()
                                    resolved_group = str(live.get('grupo') or '').strip()
                                    # En creación, si Universo devuelve valores, los usamos como fuente de verdad.
                                    allow_override = True
                                    if universo_url and not resolved_from_url and not _universo_payload_matches_category(live, category):
                                        allow_override = False
                                    if allow_override and resolved_competition:
                                        competition_name = resolved_competition[:150]
                                    if allow_override and resolved_group:
                                        group_name = resolved_group[:80]
                            except Exception:
                                pass

                        # No heredamos liga/grupo del Senior por defecto.
                        # Si no hay datos de contexto competitivo, creamos la categoría sin `group`
                        # y el usuario puede configurarlo después.
                        has_competition_context = bool(
                            competition_name
                            or season_name
                            or group_name
                            or group_external_id
                            or universo_url
                        )
                        group_obj = None
                        if has_competition_context:
                            # Defaults razonables si el usuario no rellena estos campos.
                            if group_external_id and not group_name:
                                group_name = f'Grupo {group_external_id}'[:80]
                            if group_external_id and not competition_name:
                                competition_name = 'Universo RFAF'
                            competition_name = (competition_name or 'Liga')[:150]
                            season_name = (season_name or f'{timezone.localdate().year}/{timezone.localdate().year + 1}')[:80]
                            group_name = (group_name or 'Grupo 1')[:80]

                            comp_slug = slugify(competition_name)[:150] or 'liga'
                            competition_obj, _ = Competition.objects.get_or_create(
                                name=competition_name,
                                region='',
                                defaults={'slug': comp_slug},
                            )
                            season_obj, _ = Season.objects.get_or_create(
                                competition=competition_obj,
                                name=season_name,
                                defaults={'is_current': True},
                            )
                            if group_external_id:
                                group_obj = Group.objects.filter(season=season_obj, external_id=group_external_id).first()
                            if not group_obj and not group_external_id:
                                group_obj = Group.objects.filter(season=season_obj, name__iexact=group_name).first()
                            if not group_obj:
                                group_slug = _unique_group_slug(
                                    season_obj,
                                    f'{group_name}-{group_external_id}' if group_external_id else group_name,
                                )
                                group_defaults = {'name': group_name}
                                if group_external_id:
                                    group_defaults['external_id'] = group_external_id
                                group_obj, _ = Group.objects.get_or_create(
                                    season=season_obj,
                                    slug=group_slug,
                                    defaults=group_defaults,
                                )
                            if group_external_id and group_obj and not str(getattr(group_obj, 'external_id', '') or '').strip():
                                group_obj.external_id = group_external_id
                                group_obj.save(update_fields=['external_id'])

                        base_slug = _unique_team_slug(f'{team_base_name} {category}')
                        with transaction.atomic():
                            team_obj = Team.objects.create(
                                name=team_base_name,
                                slug=base_slug,
                                short_name=str(team_base_name)[:60],
                                group=group_obj,
                                is_primary=False,
                                category=category,
                                game_format=game_format,
                            )
                            # Nuevo modelo (unificado): cada categoría se crea como un club independiente (workspace).
                            # Esto evita mezclar datos dentro del mismo cliente y elimina el selector de categorías.
                            category_label = category or str(getattr(team_obj, 'display_name', '') or getattr(team_obj, 'name', '') or '').strip()
                            new_workspace_name = f'{str(getattr(workspace, "name", "") or "").strip()} · {category_label}'.strip(' ·')
                            new_workspace_name = _sanitize_task_text(new_workspace_name, multiline=False, max_len=160)
                            if not new_workspace_name:
                                new_workspace_name = f'Club {team_obj.id}'
                            new_slug = _unique_workspace_slug(new_workspace_name)

                            new_workspace = Workspace.objects.create(
                                name=new_workspace_name,
                                slug=new_slug,
                                kind=Workspace.KIND_CLUB,
                                primary_team=team_obj,
                                owner_user=workspace.owner_user,
                                enabled_modules=dict(getattr(workspace, 'enabled_modules', None) or {}),
                                trial_expires_at=getattr(workspace, 'trial_expires_at', None),
                                subscription_status=str(getattr(workspace, 'subscription_status', '') or 'trial').strip() or 'trial',
                                plan_key=str(getattr(workspace, 'plan_key', '') or '').strip(),
                                is_active=bool(getattr(workspace, 'is_active', True)),
                                notes=f'Creado automáticamente desde {workspace.name}.',
                            )

                            # Permisos: copiamos solo roles privilegiados + el creador actual.
                            base_memberships = list(
                                WorkspaceMembership.objects
                                .select_related('user')
                                .filter(
                                    workspace=workspace,
                                    role__in={WorkspaceMembership.ROLE_OWNER, WorkspaceMembership.ROLE_ADMIN},
                                )
                            )
                            for membership in base_memberships:
                                if not membership.user_id:
                                    continue
                                WorkspaceMembership.objects.update_or_create(
                                    workspace=new_workspace,
                                    user=membership.user,
                                    defaults={'role': membership.role},
                                )
                            creator_membership = WorkspaceMembership.objects.filter(workspace=workspace, user=request.user).first()
                            WorkspaceMembership.objects.update_or_create(
                                workspace=new_workspace,
                                user=request.user,
                                defaults={'role': getattr(creator_membership, 'role', None) or WorkspaceMembership.ROLE_ADMIN},
                            )
                            if new_workspace.owner_user_id:
                                WorkspaceMembership.objects.update_or_create(
                                    workspace=new_workspace,
                                    user_id=new_workspace.owner_user_id,
                                    defaults={'role': WorkspaceMembership.ROLE_OWNER},
                                )

                            WorkspaceTeam.objects.get_or_create(
                                workspace=new_workspace,
                                team=team_obj,
                                defaults={'is_default': True},
                            )
                            WorkspaceTeamAccess.objects.update_or_create(
                                workspace=new_workspace,
                                team=team_obj,
                                user=request.user,
                                defaults={'is_default': True},
                            )
                            if new_workspace.owner_user_id:
                                WorkspaceTeamAccess.objects.update_or_create(
                                    workspace=new_workspace,
                                    team=team_obj,
                                    user_id=new_workspace.owner_user_id,
                                    defaults={'is_default': True},
                                )

                            # Si se proporciona ID/URL de Universo, dejamos preparado el contexto competitivo por equipo.
                            universo_group_id = str(group_external_id or '').strip()
                            if universo_group_id:
                                try:
                                    _bootstrap_workspace_competition_context(
                                        new_workspace,
                                        primary_team=team_obj,
                                        provider=WorkspaceCompetitionContext.PROVIDER_UNIVERSO,
                                        external_competition_key=universo_competition_key or None,
                                        external_group_key=universo_group_id,
                                        external_team_name=str(getattr(team_obj, 'name', '') or '').strip(),
                                        external_source_url=universo_url or None,
                                        auto_sync_enabled=True,
                                    )
                                except Exception:
                                    pass
                            elif universo_url:
                                try:
                                    _bootstrap_workspace_competition_context(
                                        new_workspace,
                                        primary_team=team_obj,
                                        external_source_url=universo_url,
                                    )
                                except Exception:
                                    pass
                        # Comparte escudo con el equipo principal del cliente (si existe).
                        try:
                            if workspace.primary_team_id and workspace.primary_team:
                                if workspace.primary_team.crest_image and not team_obj.crest_image:
                                    team_obj.crest_image = workspace.primary_team.crest_image
                                    team_obj.save(update_fields=['crest_image'])
                                elif workspace.primary_team.crest_url and not team_obj.crest_url:
                                    team_obj.crest_url = workspace.primary_team.crest_url
                                    team_obj.save(update_fields=['crest_url'])
                        except Exception:
                            pass
                        teams_message = f'Club creado: {new_workspace.name}.'
                except ValueError as exc:
                    teams_error = str(exc)
                except Exception:
                    teams_error = 'No se pudo guardar la categoría.'
        elif form_action in {'team_access_add', 'team_access_remove', 'team_access_set_default'}:
            active_tab = 'teams'
            if not workspace or workspace.kind != Workspace.KIND_CLUB:
                teams_error = 'No hay cliente club activo.'
            elif not can_manage_workspace:
                teams_error = 'No tienes permisos para gestionar este club.'
            else:
                link_id = _parse_int(request.POST.get('workspace_team_id'))
                target_user_id = _parse_int(request.POST.get('user_id'))
                link = (
                    WorkspaceTeam.objects
                    .filter(id=link_id, workspace=workspace)
                    .select_related('team')
                    .first()
                    if link_id else None
                )
                try:
                    if not link or not link.team:
                        raise ValueError('Categoría no válida.')
                    target_user = User.objects.filter(id=target_user_id).first() if target_user_id else None
                    if not target_user:
                        raise ValueError('Usuario no válido.')
                    if not WorkspaceMembership.objects.filter(workspace=workspace, user=target_user).exists() and int(getattr(workspace, 'owner_user_id', 0) or 0) != int(target_user.id):
                        raise ValueError('Ese usuario no pertenece al cliente.')

                    if form_action == 'team_access_remove':
                        WorkspaceTeamAccess.objects.filter(workspace=workspace, team=link.team, user=target_user).delete()
                        teams_message = 'Acceso eliminado.'
                    elif form_action == 'team_access_set_default':
                        # Un usuario puede tener varias categorías; solo una default.
                        WorkspaceTeamAccess.objects.filter(workspace=workspace, user=target_user, is_default=True).update(is_default=False)
                        obj, _ = WorkspaceTeamAccess.objects.get_or_create(
                            workspace=workspace,
                            team=link.team,
                            user=target_user,
                            defaults={'is_default': True},
                        )
                        if not obj.is_default:
                            obj.is_default = True
                            obj.save(update_fields=['is_default'])
                        teams_message = 'Categoría predeterminada del usuario actualizada.'
                    else:  # team_access_add
                        set_as_default = str(request.POST.get('set_default') or '').lower() in {'1', 'true', 'on', 'yes'}
                        if set_as_default:
                            WorkspaceTeamAccess.objects.filter(workspace=workspace, user=target_user, is_default=True).update(is_default=False)
                        obj, created = WorkspaceTeamAccess.objects.get_or_create(
                            workspace=workspace,
                            team=link.team,
                            user=target_user,
                            defaults={'is_default': bool(set_as_default)},
                        )
                        if not created and set_as_default and not obj.is_default:
                            obj.is_default = True
                            obj.save(update_fields=['is_default'])
                        teams_message = 'Acceso asignado.'
                except ValueError as exc:
                    teams_error = str(exc)
                except Exception:
                    teams_error = 'No se pudo gestionar el acceso.'
        elif form_action in {'admin_match_save', 'admin_action_bulk_add'}:
            active_tab = 'actions'
            if not is_admin_user:
                actions_error = 'Solo administradores pueden editar partidos y acciones.'
            elif not primary_team:
                actions_error = 'No hay equipo principal configurado.'
            elif form_action == 'admin_match_save':
                match_id = _parse_int(request.POST.get('match_id'))
                opponent_name = (request.POST.get('opponent_name') or '').strip()
                round_value = (request.POST.get('round') or '').strip()
                location = (request.POST.get('location') or '').strip()
                date_raw = (request.POST.get('match_date') or '').strip()
                time_raw = (request.POST.get('match_time') or '').strip()
                if not opponent_name:
                    actions_error = 'El rival es obligatorio.'
                else:
                    match_date = None
                    for fmt in ('%Y-%m-%d', '%d/%m/%Y'):
                        try:
                            match_date = datetime.strptime(date_raw, fmt).date() if date_raw else None
                            break
                        except ValueError:
                            continue
                    match_time = None
                    if time_raw:
                        try:
                            match_time = datetime.strptime(time_raw, '%H:%M').time()
                        except ValueError:
                            actions_error = 'Hora inválida. Usa HH:MM.'
                    if not actions_error:
                        rival_team = Team.objects.filter(name__iexact=opponent_name).first()
                        if not rival_team:
                            rival_team = Team.objects.create(
                                slug=_unique_team_slug(opponent_name),
                                name=opponent_name,
                                short_name=opponent_name[:24],
                                group=primary_team.group,
                            )
                        match_dt = None
                        if match_date:
                            match_dt = timezone.make_aware(
                                datetime.combine(match_date, match_time or time(hour=0, minute=0)),
                                timezone.get_current_timezone(),
                            )
                        match_obj = Match.objects.filter(id=match_id).first() if match_id else None
                        if not match_obj:
                            match_obj = Match.objects.create(
                                home_team=primary_team,
                                away_team=rival_team,
                                date=match_date,
                                kickoff_time=match_time,
                                round=round_value,
                                location=location,
                            )
                        else:
                            match_obj.away_team = rival_team
                            match_obj.date = match_date
                            match_obj.kickoff_time = match_time
                            match_obj.round = round_value
                            match_obj.location = location
                            match_obj.save(update_fields=['away_team', 'date', 'kickoff_time', 'round', 'location'])
                        actions_message = f'Partido guardado (ID {match_obj.id}).'
            elif form_action == 'admin_action_bulk_add':
                match_id = _parse_int(request.POST.get('match_id'))
                player_id = _parse_int(request.POST.get('player_id'))
                action_type = (request.POST.get('action_type') or '').strip()
                result = (request.POST.get('result') or '').strip()
                zone = (request.POST.get('zone') or '').strip()
                quantity = _parse_int(request.POST.get('quantity')) or 1
                if quantity < 1:
                    quantity = 1
                if quantity > 500:
                    quantity = 500
                match_obj = Match.objects.filter(id=match_id).first() if match_id else None
                player_obj = Player.objects.filter(id=player_id, team=primary_team).first() if player_id else None
                if not match_obj:
                    actions_error = 'Selecciona un partido válido.'
                elif not player_obj:
                    actions_error = 'Selecciona un jugador válido.'
                elif not action_type:
                    actions_error = 'Selecciona una acción.'
                elif not result:
                    actions_error = 'Selecciona un resultado.'
                else:
                    tercio = zone_to_tercio(zone)
                    base_minute = 1
                    try:
                        last_min = (
                            MatchEvent.objects.filter(match=match_obj)
                            .exclude(minute__isnull=True)
                            .order_by('-minute')
                            .values_list('minute', flat=True)
                            .first()
                        )
                        if isinstance(last_min, int):
                            base_minute = max(1, min(120, last_min))
                    except Exception:
                        pass
                    events = []
                    for idx in range(quantity):
                        minute_value = min(120, base_minute + (idx % 5))
                        events.append(
                            MatchEvent(
                                match=match_obj,
                                player=player_obj,
                                minute=minute_value,
                                period=1 if minute_value <= _half_minutes_for_team(primary_team) else 2,
                                event_type=action_type,
                                result=result,
                                zone=zone,
                                tercio=tercio,
                                observation='Carga manual admin',
                                source_file='admin-manual',
                                system='touch-field-final',
                            )
                        )
                    MatchEvent.objects.bulk_create(events, batch_size=200)
                    actions_message = (
                        f'Se añadieron {quantity} acciones a {player_obj.name} '
                        f'en partido ID {match_obj.id}.'
                    )
    roster_players = []
    admin_matches = []
    selected_admin_match = None
    admin_players = []
    admin_action_choices = []
    admin_result_choices = []
    admin_zone_choices = []

    workspace_team_links = []
    workspace_members = []
    workspace_team_access_map = {}
    team_warnings = []
    if active_tab == 'teams' and workspace and workspace.kind == Workspace.KIND_CLUB:
        workspace_team_links = _workspace_team_links(workspace)
        # Contexto competitivo por categoría para mostrar IDs externos (p.ej. Universo group id)
        # y detectar mezclas Senior/Prebenjamín.
        competition_context_map = {}
        try:
            team_ids = [
                int(getattr(link, 'team_id', 0) or 0)
                for link in workspace_team_links
                if getattr(link, 'team_id', None)
            ]
            if team_ids:
                contexts = list(
                    WorkspaceCompetitionContext.objects
                    .filter(workspace=workspace, team_id__in=team_ids)
                    .select_related('group', 'season')
                )
                competition_context_map = {
                    int(getattr(ctx, 'team_id', 0) or 0): ctx
                    for ctx in contexts
                    if getattr(ctx, 'team_id', None)
                }
        except Exception:
            competition_context_map = {}
        for link in workspace_team_links:
            try:
                team_id = int(getattr(link, 'team_id', 0) or 0)
                link.competition_context = competition_context_map.get(team_id)
            except Exception:
                link.competition_context = None
        try:
            workspace_members = list(
                WorkspaceMembership.objects
                .select_related('user')
                .filter(workspace=workspace)
                .order_by('user__username')
            )
        except Exception:
            workspace_members = []
        try:
            access_rows = list(
                WorkspaceTeamAccess.objects
                .filter(workspace=workspace)
                .select_related('user', 'team')
            )
        except Exception:
            access_rows = []
        for row in access_rows:
            workspace_team_access_map.setdefault(int(row.team_id), []).append(row)
        for link in workspace_team_links:
            team_id = int(getattr(link, 'team_id', 0) or 0)
            try:
                link.access_rows = workspace_team_access_map.get(team_id, [])
            except Exception:
                link.access_rows = []
        # Diagnóstico: detectar categorías que comparten el mismo grupo/competición
        # (suele indicar que se ha clonado Senior y se ha dejado el grupo heredado).
        try:
            group_key_map = {}
            team_id_map = {}
            for link in workspace_team_links:
                team = getattr(link, 'team', None)
                if not team:
                    continue
                team_id_val = int(getattr(team, 'id', 0) or 0)
                team_id_map.setdefault(team_id_val, []).append(link)
                group = getattr(team, 'group', None)
                # Prioridad: external_group_key del contexto competitivo (Universo) > group.external_id > group.id
                group_key = ''
                try:
                    ctx = getattr(link, 'competition_context', None)
                    group_key = str(getattr(ctx, 'external_group_key', '') or '').strip()
                except Exception:
                    group_key = ''
                if not group_key and group:
                    group_key = str(getattr(group, 'external_id', '') or getattr(group, 'id', '') or '').strip()
                if group_key:
                    group_key_map.setdefault(group_key, []).append(link)
            dup_group = {k: v for (k, v) in group_key_map.items() if len(v) > 1}
            dup_team = {k: v for (k, v) in team_id_map.items() if len(v) > 1}
            if dup_group:
                for key, links in dup_group.items():
                    labels = []
                    for item in links:
                        t = getattr(item, 'team', None)
                        if not t:
                            continue
                        labels.append(f"{str(getattr(t, 'category', '') or '').strip() or 'Sin categoría'}")
                    team_warnings.append(
                        f"Hay categorías que comparten el mismo grupo ({key}): {', '.join(sorted(set(labels)))}. "
                        "Cada categoría debe tener su propio grupo/competición para no mezclar home, clasificación y rival."
                    )
            if dup_team:
                for team_id_val, links in dup_team.items():
                    labels = []
                    for item in links:
                        t = getattr(item, 'team', None)
                        if not t:
                            continue
                        labels.append(f"{str(getattr(t, 'category', '') or '').strip() or 'Sin categoría'}")
                    team_warnings.append(
                        f"Hay categorías que apuntan al mismo equipo (Team ID {team_id_val}): {', '.join(sorted(set(labels)))}. "
                        "Eso provoca que se mezclen jugadores/fotos y la home."
                    )
        except Exception:
            team_warnings = []

    if active_tab == 'roster':
        roster_players = (
            list(Player.objects.filter(team=primary_team).order_by('-is_active', 'number', 'name'))
            if primary_team
            else []
        )

    if active_tab == 'actions' and is_admin_user:
        admin_match_qs = _team_match_queryset(primary_team) if primary_team else Match.objects.none()
        # En Admin necesitamos ver también partidos importados aunque lleguen con
        # vínculos incompletos al equipo principal. Por eso unimos:
        # 1) partidos asociados al primer equipo (query normal)
        # 2) partidos del grupo/temporada del primer equipo (fallback importador)
        # y deduplicamos por id.
        admin_map = {}
        for match in admin_match_qs.select_related('home_team', 'away_team').order_by('-date', '-id')[:500]:
            admin_map[int(match.id)] = match
        if primary_team:
            fallback_q = Q()
            if getattr(primary_team, 'group_id', None):
                fallback_q |= Q(group_id=primary_team.group_id)
                season_id = getattr(getattr(primary_team, 'group', None), 'season_id', None)
                if season_id:
                    fallback_q |= Q(season_id=season_id)
            if fallback_q:
                fallback_rows = (
                    Match.objects
                    .filter(fallback_q)
                    .select_related('home_team', 'away_team')
                    .order_by('-date', '-id')[:700]
                )
                for match in fallback_rows:
                    admin_map[int(match.id)] = match
        admin_matches = sorted(
            list(admin_map.values()),
            key=lambda item: (item.date or date.min, int(item.id or 0)),
            reverse=True,
        )
        selected_admin_match_id = _parse_int(request.GET.get('match_id') or request.POST.get('match_id'))
        selected_admin_match = (
            next((m for m in admin_matches if m.id == selected_admin_match_id), None)
            if selected_admin_match_id
            else (admin_matches[0] if admin_matches else None)
        )
        admin_players = (
            list(Player.objects.filter(team=primary_team).order_by('number', 'name'))
            if primary_team
            else []
        )
        admin_action_choices = load_match_actions()
        admin_result_choices = load_match_results()
        seen_zone_labels = set()
        for zone_def in FIELD_ZONES:
            label = str(zone_def.get('label') or '').strip()
            if not label or label in seen_zone_labels:
                continue
            seen_zone_labels.add(label)
            admin_zone_choices.append(label)
    return render(
        request,
        'football/admin.html',
        {
            'workspace': workspace,
            'can_manage_workspace': can_manage_workspace,
            'roster_players': roster_players,
            'roster_message': roster_message,
            'roster_error': roster_error,
            'active_tab': active_tab,
            'team_name': primary_team.display_name if primary_team else '',
            'primary_team_id': primary_team.id if primary_team else None,
            'is_admin_user': is_admin_user,
            'workspace_team_links': workspace_team_links,
            'teams_message': teams_message,
            'teams_error': teams_error,
            'workspace_members': workspace_members,
            # (debug/plantilla) el acceso ya va anexado en cada link.access_rows
            'workspace_team_access_map': workspace_team_access_map,
            'team_warnings': team_warnings,
            'admin_matches': admin_matches,
            'selected_admin_match': selected_admin_match,
            'admin_players': admin_players,
            'admin_action_choices': admin_action_choices,
            'admin_result_choices': admin_result_choices,
            'admin_zone_choices': admin_zone_choices,
            'actions_message': actions_message,
            'actions_error': actions_error,
        },
    )


@ensure_csrf_cookie
def invitation_accept_page(request, token):
    invitation = (
        UserInvitation.objects
        .select_related('user')
        .filter(token=token, is_active=True)
        .order_by('-created_at')
        .first()
    )
    now = timezone.now()
    if not invitation:
        return render(
            request,
            'football/invitation_accept.html',
            {'status': 'invalid'},
            status=404,
        )
    if invitation.accepted_at:
        return render(
            request,
            'football/invitation_accept.html',
            {'status': 'used', 'username': invitation.user.username},
            status=410,
        )
    if invitation.is_expired(now=now):
        invitation.is_active = False
        invitation.save(update_fields=['is_active'])
        return render(
            request,
            'football/invitation_accept.html',
            {'status': 'expired', 'username': invitation.user.username},
            status=410,
        )
    error = ''
    success = ''
    if request.method == 'POST':
        password = (request.POST.get('password') or '').strip()
        password_confirm = (request.POST.get('password_confirm') or '').strip()
        if not password:
            error = 'La contraseña es obligatoria.'
        elif password != password_confirm:
            error = 'Las contraseñas no coinciden.'
        else:
            try:
                validate_password(password, user=invitation.user)
                invitation.user.set_password(password)
                invitation.user.is_active = True
                invitation.user.save(update_fields=['password', 'is_active'])
                try:
                    AppUserRole.objects.get_or_create(
                        user=invitation.user,
                        defaults={'role': AppUserRole.ROLE_PLAYER},
                    )
                except Exception:
                    pass
                invitation.accepted_at = timezone.now()
                invitation.is_active = False
                invitation.save(update_fields=['accepted_at', 'is_active'])
                UserInvitation.objects.filter(
                    user=invitation.user,
                    is_active=True,
                    accepted_at__isnull=True,
                ).exclude(id=invitation.id).update(is_active=False)
                try:
                    backend = getattr(invitation.user, 'backend', None)
                    if not backend:
                        backend = (
                            settings.AUTHENTICATION_BACKENDS[0]
                            if getattr(settings, 'AUTHENTICATION_BACKENDS', None)
                            else None
                        )
                    if backend:
                        auth_login(request, invitation.user, backend=backend)
                    else:
                        auth_login(request, invitation.user)
                    return redirect('dashboard-home')
                except Exception:
                    success = 'Invitación aceptada. Ya puedes iniciar sesión.'
            except DjangoValidationError as exc:
                error = ' '.join(exc.messages) or 'Contraseña inválida.'
            except Exception:
                error = 'No se pudo completar la invitación.'
    return render(
        request,
        'football/invitation_accept.html',
        {
            'status': 'ok',
            'username': invitation.user.username,
            'expires_at': invitation.expires_at,
            'error': error,
            'success': success,
        },
    )


def _file_field_as_data_url(file_field):
    if not file_field:
        return ''
    try:
        file_field.open('rb')
        raw = file_field.read()
        file_field.close()
    except Exception:
        return ''
    if not raw:
        return ''
    ext = Path(getattr(file_field, 'name', '') or '').suffix.lower()
    mime = {
        '.png': 'image/png',
        '.jpg': 'image/jpeg',
        '.jpeg': 'image/jpeg',
        '.webp': 'image/webp',
        '.gif': 'image/gif',
    }.get(ext, 'image/jpeg')
    return f"data:{mime};base64,{base64.b64encode(raw).decode('utf-8')}"


def _client_ip(request):
    if not request:
        return ''
    forwarded = str(request.META.get('HTTP_X_FORWARDED_FOR') or '').split(',')[0].strip()
    return forwarded or str(request.META.get('REMOTE_ADDR') or '').strip()


def _audit(request, action, *, workspace=None, message='', payload=None):
    try:
        if payload is None:
            payload = {}
        actor_user = request.user if request and getattr(request, 'user', None) and request.user.is_authenticated else None
        actor = ''
        if actor_user:
            actor = actor_user.get_username()
            full_name = actor_user.get_full_name().strip() if hasattr(actor_user, 'get_full_name') else ''
            if full_name:
                actor = f'{actor} · {full_name}'
        AuditEvent.objects.create(
            workspace=workspace,
            actor_user=actor_user,
            actor=actor[:150],
            action=str(action or '')[:80],
            message=str(message or '')[:220],
            payload=payload if isinstance(payload, dict) else {},
            ip=_client_ip(request)[:60],
        )
    except Exception:
        pass


@login_required
@require_POST
def share_task_pdf_create(request):
    """
    Crea un enlace público (token) para imprimir/abrir el PDF de una tarea.
    """
    task_kind = str(request.POST.get('task_kind') or '').strip().lower()
    task_id = _parse_int(request.POST.get('task_id'))
    style = (request.POST.get('style') or 'uefa').strip().lower()
    if style not in {'uefa', 'club'}:
        style = 'uefa'
    validity_days = _parse_int(request.POST.get('valid_days')) or 14
    validity_days = max(1, min(validity_days, 60))
    password = (request.POST.get('password') or '').strip()
    try:
        if task_kind != 'session':
            raise ValueError('Tipo de tarea no válido.')
        if not task_id:
            raise ValueError('Tarea no válida.')
        if not _can_access_sessions_workspace(request.user):
            return JsonResponse({'error': 'No tienes permisos para acceder a sesiones.'}, status=403)
        forbidden = _forbid_if_workspace_module_disabled(request, 'sessions', label='sesiones')
        if forbidden:
            return JsonResponse({'error': 'El módulo sesiones no está disponible.'}, status=403)
        task = (
            SessionTask.objects
            .select_related('session__microcycle__team')
            .filter(id=task_id, deleted_at__isnull=True)
            .first()
        )
        if not task:
            raise ValueError('Tarea no encontrada.')
        ws = _get_active_workspace(request)
        if not _can_access_platform(request.user) and ws and ws.kind == Workspace.KIND_CLUB and ws.primary_team_id:
            if int(ws.primary_team_id) != int(task.session.microcycle.team_id):
                return JsonResponse({'error': 'No tienes permisos para compartir esta tarea.'}, status=403)

        ShareLink.objects.filter(
            is_active=True,
            kind=ShareLink.KIND_TASK_PDF,
            payload__task_kind=task_kind,
            payload__task_id=task_id,
            payload__style=style,
        ).update(is_active=False)
        link = ShareLink.objects.create(
            token=ShareLink.generate_token(),
            kind=ShareLink.KIND_TASK_PDF,
            payload={'task_kind': task_kind, 'task_id': task_id, 'style': style},
            password_hash=make_password(password) if password else '',
            expires_at=timezone.now() + timedelta(days=validity_days),
            created_by=request.user.get_username() if request.user.is_authenticated else '',
            created_by_user=request.user if request.user.is_authenticated else None,
            is_active=True,
        )
        url = request.build_absolute_uri(reverse('share-task-pdf', args=[link.token]))
        _audit(
            request,
            'share_link_create',
            workspace=_get_active_workspace(request),
            message='Enlace compartido creado',
            payload={'kind': 'task_pdf', 'task_kind': task_kind, 'task_id': task_id, 'style': style, 'expires_days': validity_days, 'password': bool(password)},
        )
        return JsonResponse({'ok': True, 'url': url, 'expires_at': link.expires_at})
    except ValueError as exc:
        return JsonResponse({'error': str(exc)}, status=400)
    except Exception:
        return JsonResponse({'error': 'No se pudo crear el enlace.'}, status=500)


@login_required
@require_POST
def share_task_simulation_create(request):
    """
    Crea un enlace público (token) para abrir una simulación (pasos) sin login.
    El payload se genera en cliente (Task Builder) y se guarda en ShareLink.payload.
    """
    validity_days = _parse_int(request.POST.get('valid_days')) or 14
    validity_days = max(1, min(validity_days, 60))
    password = (request.POST.get('password') or '').strip()
    raw = (request.POST.get('payload') or '').strip()
    try:
        payload = json.loads(raw) if raw else {}
    except Exception:
        return JsonResponse({'error': 'Payload no válido.'}, status=400)
    if not isinstance(payload, dict):
        return JsonResponse({'error': 'Payload no válido.'}, status=400)

    title = str(payload.get('title') or '').strip()[:180] or 'Simulación'
    steps = payload.get('steps')
    pitch_svg = str(payload.get('pitch_svg') or '').strip()
    task_kind = str(payload.get('task_kind') or '').strip().lower()
    task_id = _parse_int(payload.get('task_id'))
    if task_kind != 'session':
        task_kind = ''
        task_id = None

    if not isinstance(steps, list) or not steps:
        return JsonResponse({'error': 'No hay pasos de simulación.'}, status=400)
    if len(steps) > 40:
        steps = steps[:40]
    if pitch_svg and len(pitch_svg) > 420_000:
        return JsonResponse({'error': 'La simulación es demasiado grande para compartir.'}, status=413)

    cleaned_steps = []
    for index, step in enumerate(steps):
        if not isinstance(step, dict):
            continue
        state = step.get('canvas_state')
        if not isinstance(state, dict):
            continue
        duration = _parse_int(step.get('duration')) or 3
        cleaned_steps.append({
            'title': str(step.get('title') or f'Paso {index + 1}')[:120],
            'duration': max(1, min(duration, 20)),
            'canvas_state': state,
            'canvas_width': _parse_int(step.get('canvas_width')) or 0,
            'canvas_height': _parse_int(step.get('canvas_height')) or 0,
            'moves': step.get('moves') if isinstance(step.get('moves'), list) else [],
        })
    if not cleaned_steps:
        return JsonResponse({'error': 'No se pudieron leer los pasos de simulación.'}, status=400)

    # Si viene asociada a una tarea concreta, invalida enlaces previos de esa tarea.
    if task_kind == 'session' and task_id:
        ShareLink.objects.filter(
            is_active=True,
            kind=ShareLink.KIND_TASK_SIMULATION,
            payload__task_kind=task_kind,
            payload__task_id=int(task_id),
        ).update(is_active=False)

    link = ShareLink.objects.create(
        token=ShareLink.generate_token(),
        kind=ShareLink.KIND_TASK_SIMULATION,
        payload={
            'title': title,
            'pitch_svg': pitch_svg,
            'steps': cleaned_steps,
            'task_kind': task_kind,
            'task_id': int(task_id) if task_id else None,
        },
        password_hash=make_password(password) if password else '',
        expires_at=timezone.now() + timedelta(days=validity_days),
        created_by=request.user.get_username() if request.user.is_authenticated else '',
        created_by_user=request.user if request.user.is_authenticated else None,
        is_active=True,
    )
    url = request.build_absolute_uri(reverse('share-task-simulation', args=[link.token]))
    _audit(
        request,
        'share_link_create',
        workspace=_get_active_workspace(request),
        message='Enlace de simulación creado',
        payload={'kind': 'task_simulation', 'task_kind': task_kind, 'task_id': task_id, 'expires_days': validity_days, 'password': bool(password)},
    )
    return JsonResponse({'ok': True, 'url': url, 'expires_at': link.expires_at})


@login_required
@require_POST
def share_convocation_pdf_create(request):
    """
    Crea un enlace público (token) para abrir/descargar el PDF de convocatoria sin login.
    Guarda el `ConvocationRecord` actual para que el enlace sea estable aunque cambie la convocatoria.
    """
    validity_days = _parse_int(request.POST.get('valid_days')) or 14
    validity_days = max(1, min(validity_days, 60))
    password = (request.POST.get('password') or '').strip()
    try:
        forbidden = _forbid_if_workspace_module_disabled(request, 'convocation', label='convocatoria')
        if forbidden:
            return JsonResponse({'error': 'El módulo convocatoria no está disponible.'}, status=403)
        primary_team = _get_primary_team_for_request(request)
        if not primary_team:
            return JsonResponse({'error': 'Equipo principal no configurado.'}, status=400)
        convocation_record = get_current_convocation_record(primary_team)
        if not convocation_record:
            return JsonResponse({'error': 'No hay convocatoria guardada.'}, status=400)
        players = list(convocation_record.players.all()[:1])
        if not players:
            return JsonResponse({'error': 'No hay jugadores convocados.'}, status=400)

        ShareLink.objects.filter(
            is_active=True,
            kind=ShareLink.KIND_CONVOCATION_PDF,
            payload__record_id=int(convocation_record.id),
        ).update(is_active=False)

        link = ShareLink.objects.create(
            token=ShareLink.generate_token(),
            kind=ShareLink.KIND_CONVOCATION_PDF,
            payload={'team_id': int(primary_team.id), 'record_id': int(convocation_record.id)},
            password_hash=make_password(password) if password else '',
            expires_at=timezone.now() + timedelta(days=validity_days),
            created_by=request.user.get_username() if request.user.is_authenticated else '',
            created_by_user=request.user if request.user.is_authenticated else None,
            is_active=True,
        )
        url = request.build_absolute_uri(reverse('share-convocation-pdf', args=[link.token]))
        _audit(
            request,
            'share_link_create',
            workspace=_get_active_workspace(request),
            message='Enlace compartido creado',
            payload={'kind': 'convocation_pdf', 'team_id': int(primary_team.id), 'record_id': int(convocation_record.id), 'expires_days': validity_days, 'password': bool(password)},
        )
        return JsonResponse({'ok': True, 'url': url, 'expires_at': link.expires_at})
    except Exception:
        return JsonResponse({'error': 'No se pudo crear el enlace.'}, status=500)


def share_convocation_pdf_page(request, token):
    """
    Endpoint público para el PDF de convocatoria compartido por token.
    """
    token = str(token or '').strip()
    link = (
        ShareLink.objects
        .filter(token=token, is_active=True, kind=ShareLink.KIND_CONVOCATION_PDF)
        .order_by('-created_at')
        .first()
    )
    now = timezone.now()
    if not link or not link.can_be_used(now=now):
        raise Http404('Enlace no disponible')
    if (link.password_hash or '').strip():
        if request.method != 'POST':
            return render(
                request,
                'football/share_link_gate.html',
                {'error': '', 'expires_at': link.expires_at},
                status=200,
            )
        supplied = (request.POST.get('password') or '').strip()
        if not supplied or not check_password(supplied, link.password_hash):
            return render(
                request,
                'football/share_link_gate.html',
                {'error': 'Contraseña incorrecta.', 'expires_at': link.expires_at},
                status=403,
            )

    payload = link.payload if isinstance(link.payload, dict) else {}
    record_id = _parse_int(payload.get('record_id'))
    team_id = _parse_int(payload.get('team_id'))
    if not record_id or not team_id:
        raise Http404('Enlace no válido')

    primary_team = Team.objects.filter(id=team_id).first()
    if not primary_team:
        raise Http404('Equipo no encontrado')

    convocation_record = (
        ConvocationRecord.objects
        .select_related('match', 'team')
        .filter(id=record_id, team_id=team_id)
        .first()
    )
    if not convocation_record:
        raise Http404('Convocatoria no encontrada')

    players = list(convocation_record.players.order_by('number', 'name'))
    if not players:
        raise Http404('Convocatoria vacía')

    def _sort_player_key(player):
        number = player.number if player.number is not None else 999
        return (number, (player.name or '').lower())

    ordered_players = sorted(players, key=_sort_player_key)

    static_base_dir = Path(settings.BASE_DIR) / 'static'

    include_player_photos = str(os.getenv('CONVOCATION_PDF_PLAYER_PHOTOS', '1')).strip().lower() in {
        '1',
        'true',
        'yes',
        'on',
    }

    storage = storages['default']
    if isinstance(storage, FileSystemStorage):
        storage = FileSystemStorage(location=getattr(settings, 'MEDIA_ROOT', None), base_url=getattr(settings, 'MEDIA_URL', '/media/'))

    def _person_initials(label):
        text = ' '.join(str(label or '').split()).strip()
        if not text:
            return '??'
        tokens = [tok for tok in re.split(r'[^A-Za-zÀ-ÿ0-9]+', text) if tok]
        if not tokens:
            return (text[:2] if len(text) >= 2 else text).upper()
        if len(tokens) == 1:
            return (tokens[0][:2] if len(tokens[0]) >= 2 else tokens[0]).upper()
        return (tokens[0][0] + tokens[-1][0]).upper()

    def _svg_data_uri(svg_text):
        try:
            raw = svg_text.encode('utf-8')
        except Exception:
            raw = bytes(svg_text or '', 'utf-8', errors='ignore')
        encoded = base64.b64encode(raw).decode('ascii')
        return f'data:image/svg+xml;base64,{encoded}'

    def _team_fallback_crest_svg(team_label, hue=142):
        initials = _team_initials(team_label)
        svg = f"""<svg xmlns="http://www.w3.org/2000/svg" width="160" height="160" viewBox="0 0 160 160">
  <defs>
    <linearGradient id="g" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0%" stop-color="hsl({hue}, 70%, 42%)"/>
      <stop offset="100%" stop-color="hsl({(hue + 35) % 360}, 74%, 36%)"/>
    </linearGradient>
  </defs>
  <rect x="0" y="0" width="160" height="160" rx="32" fill="url(#g)"/>
  <rect x="10" y="10" width="140" height="140" rx="28" fill="rgba(2, 6, 23, 0.25)" stroke="rgba(255,255,255,0.26)" stroke-width="2"/>
  <text x="80" y="92" text-anchor="middle" font-family="system-ui, -apple-system, Segoe UI, Roboto, Arial" font-size="56" font-weight="800" fill="rgba(255,255,255,0.92)" letter-spacing="2">{html.escape(initials)}</text>
</svg>"""
        return _svg_data_uri(svg)

    def _team_crest_data_uri(team_obj, fallback_label=''):
        if team_obj and getattr(team_obj, 'crest_image', None):
            try:
                file_name = str(getattr(team_obj.crest_image, 'name', '') or '')
                ext = Path(file_name).suffix.lower()
                mime = {'.png': 'image/png', '.jpg': 'image/jpeg', '.jpeg': 'image/jpeg', '.webp': 'image/webp'}.get(ext, 'image/png')
                team_obj.crest_image.open('rb')
                raw = team_obj.crest_image.read() or b''
                try:
                    team_obj.crest_image.close()
                except Exception:
                    pass
                if raw:
                    return _image_bytes_as_small_data_uri(raw_bytes=raw, mime_type=mime, max_width=220, max_height=220, quality=72)
            except Exception:
                pass
        if team_obj and _is_benagalbon_team(team_obj):
            local_primary = static_base_dir / 'football' / 'images' / 'cdb-benagalbon-crest.png'
            data_uri = _image_file_as_small_data_uri(local_primary, max_width=220, max_height=220, quality=72)
            if data_uri:
                return data_uri
        label = (getattr(team_obj, 'display_name', '') if team_obj else '') or (getattr(team_obj, 'name', '') if team_obj else '') or fallback_label
        hue = _team_color_seed(team_obj) if team_obj else (sum(ord(ch) for ch in str(label or '')) % 360)
        return _team_fallback_crest_svg(label or 'Equipo', hue=hue)

    def _read_storage_bytes(storage_name):
        if not storage_name:
            return b''
        try:
            with storage.open(storage_name, 'rb') as fp:
                return fp.read() or b''
        except Exception:
            return b''

    def _player_photo_data_uri(player_obj):
        if not include_player_photos:
            return ''
        storage_name = ''
        for candidate in _player_photo_storage_candidates(player_obj):
            try:
                if storage.exists(candidate):
                    storage_name = candidate
                    break
            except Exception:
                continue
        if storage_name:
            ext = Path(storage_name).suffix.lower()
            mime = {'.png': 'image/png', '.jpg': 'image/jpeg', '.jpeg': 'image/jpeg', '.webp': 'image/webp'}.get(ext, 'image/png')
            raw = _read_storage_bytes(storage_name)
            if raw:
                return _image_bytes_as_small_data_uri(raw_bytes=raw, mime_type=mime, max_width=280, max_height=280, quality=68)
        player_static_rel = resolve_player_photo_static_path(player_obj)
        if player_static_rel:
            return _image_file_as_small_data_uri(static_base_dir / player_static_rel, max_width=280, max_height=280, quality=68)
        return ''

    player_rows = []
    for player in ordered_players:
        player_rows.append(
            {
                'number': player.number,
                'name': player.name,
                'initials': _person_initials(player.name),
                'photo_data_uri': _player_photo_data_uri(player),
            }
        )

    date_label = convocation_record.match_date.strftime('%d/%m/%Y') if convocation_record.match_date else '--'
    time_label = convocation_record.match_time.strftime('%H:%M') if convocation_record.match_time else '--:--'
    location_label = convocation_record.location or (convocation_record.match.location if convocation_record.match else '')
    rival_label = convocation_record.opponent_name
    if not rival_label and convocation_record.match:
        opponent = (
            convocation_record.match.away_team
            if convocation_record.match.home_team_id == primary_team.id
            else convocation_record.match.home_team
        )
        rival_label = opponent.name if opponent else ''

    rival_name = (rival_label or '').strip() or 'Rival por confirmar'
    preferred_next = load_preferred_next_match_payload(primary_team=primary_team)
    preferred_opponent = preferred_next.get('opponent') if isinstance(preferred_next, dict) else None
    rival_full_name, rival_crest_url = _resolve_rival_identity(rival_name, preferred_opponent=preferred_opponent)
    rival_crest_url = _sanitize_universo_external_image(_absolute_universo_url(rival_crest_url))

    opponent_team = None
    try:
        if convocation_record.match:
            is_home = bool(convocation_record.match.home_team_id == primary_team.id)
            opponent_team = convocation_record.match.away_team if is_home else convocation_record.match.home_team
    except Exception:
        opponent_team = None

    team_crest_src = _team_crest_data_uri(primary_team, fallback_label=primary_team.display_name)
    rival_crest_src = _team_crest_data_uri(opponent_team, fallback_label=rival_full_name or rival_name)

    competition_name = ''
    season_name = ''
    group_name = ''
    try:
        group = getattr(primary_team, 'group', None)
        if group and getattr(group, 'season', None) and getattr(group.season, 'competition', None):
            competition_name = str(group.season.competition.name or '').strip()
            season_name = str(group.season.name or '').strip()
            group_name = str(group.name or '').strip()
    except Exception:
        competition_name = ''
        season_name = ''
        group_name = ''

    team_photo_data_uri = ''
    try:
        cover_field = getattr(primary_team, 'cover_image', None)
        if cover_field:
            file_name = str(getattr(cover_field, 'name', '') or '')
            ext = Path(file_name).suffix.lower()
            mime = {'.png': 'image/png', '.jpg': 'image/jpeg', '.jpeg': 'image/jpeg', '.webp': 'image/webp'}.get(ext, 'image/jpeg')
            cover_field.open('rb')
            raw = cover_field.read() or b''
            try:
                cover_field.close()
            except Exception:
                pass
            if raw:
                team_photo_data_uri = _image_bytes_as_small_data_uri(raw_bytes=raw, mime_type=mime, max_width=1400, max_height=900, quality=72)
    except Exception:
        team_photo_data_uri = ''
    if not team_photo_data_uri:
        default_cover = static_base_dir / 'football' / 'images' / 'team-01.jpg'
        team_photo_data_uri = _image_file_as_small_data_uri(default_cover, max_width=1400, max_height=900, quality=72)

    context = {
        **_build_pdf_nav_urls(request),
        'team_name': primary_team.display_name,
        'team_full_name': primary_team.name,
        'round_label': convocation_record.round or 'Jornada por confirmar',
        'date_label': date_label,
        'time_label': time_label,
        'location_label': location_label or 'Campo por confirmar',
        'rival_full_name': rival_full_name,
        'team_crest_src': team_crest_src,
        'rival_crest_src': rival_crest_src,
        'players': player_rows,
        'club_hashtag': os.getenv('TEAM_HASHTAG', '#VamosVerdes'),
        'competition_name': competition_name or 'Competición',
        'season_name': season_name,
        'group_name': group_name,
        'team_photo_data_uri': team_photo_data_uri,
        'generated_at': timezone.localtime(),
    }

    html = render_to_string('football/convocation_pdf.html', context)
    filename = slugify(f'convocatoria-{primary_team.display_name}-{convocation_record.match_date or timezone.localdate()}') or f'convocatoria-{convocation_record.id}'
    try:
        ShareLink.objects.filter(id=link.id).update(access_count=(link.access_count or 0) + 1, last_accessed_at=timezone.now())
    except Exception:
        pass
    # En enlace público preferimos inline para que abra directo en móvil/desktop.
    return _build_pdf_response_or_html_fallback(request, html, filename, inline=True, force_pdf=True)


