@login_required
def coach_roster_page(request):
    forbidden = _forbid_if_no_coach_access(request.user)
    if forbidden:
        return forbidden
    forbidden = _forbid_if_workspace_module_disabled(request, 'players', label='plantilla técnica')
    if forbidden:
        return forbidden
    workspace = _get_active_workspace(request)
    if not workspace or getattr(workspace, 'kind', None) != Workspace.KIND_CLUB:
        return HttpResponse('Selecciona un club (workspace) antes de editar la plantilla.', status=400)
    primary_team = _get_primary_team_for_request(request)
    if not primary_team:
        raise Http404('Equipo principal no configurado')

    can_edit = bool(_can_manage_workspace(request.user, workspace) or _can_access_platform(request.user) or _is_admin_user(request.user))
    active_tab = str(request.GET.get('tab') or '').strip().lower() or 'stats'
    if active_tab not in {'stats', 'manage'}:
        active_tab = 'stats'
    message = ''
    error = ''
    if request.method == 'POST':
        if not can_edit:
            return HttpResponse('No tienes permisos para editar la plantilla.', status=403)
        action = (request.POST.get('action') or 'add').strip()
        player_id = _parse_int(request.POST.get('player_id'))
        name = (request.POST.get('name') or '').strip()
        number_raw = (request.POST.get('number') or '').strip()
        position = (request.POST.get('position') or '').strip()
        is_active = (request.POST.get('is_active') or '1').strip() in {'1', 'true', 'on', 'yes'}

        try:
            if action == 'deactivate':
                if not player_id:
                    raise ValueError('Jugador no válido para desactivar.')
                player = Player.objects.filter(id=player_id, team=primary_team).first()
                if not player:
                    raise ValueError('Jugador no encontrado.')
                player.is_active = False
                player.save(update_fields=['is_active'])
                message = f'{player.name} marcado como inactivo.'
            else:
                if not name:
                    raise ValueError('El nombre es obligatorio.')
                number = _parse_int(number_raw) if number_raw else None
                player = (
                    Player.objects.filter(team=primary_team, name__iexact=name)
                    .order_by('id')
                    .first()
                )
                if player:
                    player.number = number
                    player.position = position
                    player.is_active = is_active
                    player.save(update_fields=['number', 'position', 'is_active'])
                    message = f'Jugador actualizado: {player.name}.'
                else:
                    Player.objects.create(
                        team=primary_team,
                        name=name,
                        number=number,
                        position=position,
                        is_active=is_active,
                    )
                    message = f'Jugador añadido: {name}.'
        except ValueError as exc:
            error = str(exc)
        except Exception:
            error = 'No se pudo guardar el jugador. Revisa los datos.'

    players = Player.objects.filter(team=primary_team).order_by('is_active', 'number', 'name')
    player_cards = []
    if active_tab == 'stats':
        try:
            player_cards = compute_player_cards(primary_team)
        except Exception:
            player_cards = []
    def _tab_link(tab_name):
        params = request.GET.copy()
        params['tab'] = tab_name
        encoded = params.urlencode()
        return f'?{encoded}' if encoded else ''
    return render(
        request,
        'football/coach_roster.html',
        {
            'team_name': primary_team.display_name,
            'players': players,
            'player_cards': player_cards,
            'active_tab': active_tab,
            'tab_link_stats': _tab_link('stats'),
            'tab_link_manage': _tab_link('manage'),
            'message': message,
            'error': error,
        },
    )


def initial_eleven_page(request):
    forbidden = _forbid_if_workspace_module_disabled(request, 'convocation', label='11 inicial')
    if forbidden:
        return forbidden
    workspace = _get_active_workspace(request)
    primary_team = _get_primary_team_for_request(request)
    if not primary_team:
        # UX: no devolver 404 "Not Found" (parece que la app está rota). Guiar a configuración.
        try:
            if workspace and _workspace_needs_setup(workspace):
                if _can_access_platform(request.user):
                    return redirect('platform-workspace-detail', workspace_id=workspace.id)
                return redirect('club-onboarding')
        except Exception:
            pass
        if _can_access_platform(request.user) and workspace:
            return redirect('platform-workspace-detail', workspace_id=workspace.id)
        return HttpResponse('Este club no tiene equipo/configuración. Completa el onboarding primero.', status=400)
    starters_limit = _required_starters_for_team(primary_team)
    convocation_record = get_current_convocation_record(
        primary_team,
        match=get_active_match(primary_team),
        fallback_to_latest=True,
    )
    convocation_players = list(convocation_record.players.order_by('number', 'name')) if convocation_record else []
    for player in convocation_players:
        player.photo_url = resolve_player_photo_url(request, player)

    lineup_seed = {'starters': [], 'bench': []}
    has_pending_lineup = False
    has_pending_convocation = bool(convocation_record and not convocation_players)
    if convocation_record:
        stored = convocation_record.lineup_data if isinstance(convocation_record.lineup_data, dict) else {}
        normalized = _normalize_lineup_payload_with_limit(stored, convocation_players, starters_limit=starters_limit)
        if normalized['starters'] or normalized['bench']:
            lineup_seed = normalized
        else:
            has_pending_lineup = bool(convocation_players)

    return render(
        request,
        'football/coach_initial_eleven.html',
        {
            'team_name': primary_team.display_name,
            'starters_limit': starters_limit,
            'team_crest_url': resolve_team_crest_url(request, primary_team, sync=True),
            'rival_crest_url': _absolute_universo_url(
                _resolve_rival_identity(
                    getattr(convocation_record, 'opponent_name', '') or 'Rival por confirmar'
                )[1]
            ) if convocation_record else '',
            'convocation_record': convocation_record,
            'convocation_players': convocation_players,
            'lineup_seed_json': json.dumps(lineup_seed, ensure_ascii=False),
            'has_pending_convocation': has_pending_convocation,
            'has_pending_lineup': has_pending_lineup,
        },
    )


@login_required
def coach_rival_page(request):
    """
    Preparación rápida del rival (plantilla + convocatoria + 11 inicial) para el partido activo.

    - Lee la plantilla desde TeamRosterSnapshot (sin depender de scraping en vivo).
    - Guarda la selección en RivalConvocationRecord para reutilizarla en acta/cierre.
    """
    if not _can_edit_match_actions(request.user):
        return HttpResponse('Solo el cuerpo técnico puede preparar el rival.', status=403)
    forbidden = _forbid_if_workspace_module_disabled(request, 'match_actions', label='rival')
    if forbidden:
        return forbidden

    primary_team = _get_primary_team_for_request(request)
    if not primary_team:
        raise Http404('Equipo principal no configurado')

    match = get_requested_match(request, primary_team) or get_latest_live_match(primary_team) or get_active_match(primary_team)
    if not match:
        return HttpResponse('No hay partido activo. Crea/selecciona un partido antes de preparar el rival.', status=400)

    provider = (request.GET.get('provider') or request.POST.get('provider') or TeamRosterSnapshot.PROVIDER_UNIVERSO).strip()
    if provider not in {TeamRosterSnapshot.PROVIDER_UNIVERSO, TeamRosterSnapshot.PROVIDER_PREFERENTE}:
        provider = TeamRosterSnapshot.PROVIDER_UNIVERSO

    # Lista de rivales (por defecto el grupo del equipo principal, si existe).
    rivals_qs = Team.objects.filter(is_primary=False)
    try:
        workspace = _get_active_workspace(request)
        if workspace and workspace.kind == Workspace.KIND_CLUB:
            workspace_team_ids = set(
                WorkspaceTeam.objects.filter(workspace=workspace).values_list('team_id', flat=True)
            )
            if workspace_team_ids:
                rivals_qs = rivals_qs.exclude(id__in=workspace_team_ids)
    except Exception:
        pass
    if primary_team.group_id:
        rivals_qs = rivals_qs.filter(group_id=primary_team.group_id)
    rivals = list(rivals_qs.order_by('name'))

    selected_rival_id = _parse_int(request.GET.get('rival_team_id') or request.POST.get('rival_team_id'))
    rival_record = RivalConvocationRecord.objects.filter(team=primary_team, match=match).select_related('rival_team').first()
    if not selected_rival_id and rival_record and rival_record.rival_team_id:
        selected_rival_id = rival_record.rival_team_id
    if not selected_rival_id:
        opponent_team = match.away_team if match.home_team_id == primary_team.id else match.home_team
        if opponent_team and opponent_team.id != primary_team.id:
            selected_rival_id = opponent_team.id

    selected_rival = Team.objects.filter(id=selected_rival_id).first() if selected_rival_id else None
    if selected_rival and selected_rival.is_primary:
        selected_rival = None

    message = ''
    error = ''

    snapshot = None
    roster_payload = []
    if selected_rival:
        snapshot = (
            TeamRosterSnapshot.objects
            .filter(team=selected_rival, provider=provider)
            .order_by('-updated_at')
            .first()
        )
        if snapshot and isinstance(snapshot.roster_payload, list):
            roster_payload = snapshot.roster_payload

    # Map por código (Universo -> code). Si no hay code, usamos índice estable.
    roster_map = {}
    normalized_rows = []
    for idx, row in enumerate(roster_payload):
        if not isinstance(row, dict):
            continue
        name = (row.get('name') or row.get('player') or row.get('full_name') or '').strip()
        if not name:
            continue
        code = str(row.get('code') or row.get('player_code') or row.get('id') or '').strip()
        if not code:
            code = f'row-{idx}'
        number = row.get('number') or row.get('dorsal') or row.get('shirt_number') or ''
        try:
            number_int = int(str(number).strip() or 0)
        except Exception:
            number_int = 0
        position = (row.get('position') or row.get('pos') or '').strip()
        entry = {
            'code': code,
            'name': name,
            'number': number_int if number_int else None,
            'position': position,
        }
        roster_map[code] = entry
        normalized_rows.append(entry)

    if request.method == 'POST' and (request.POST.get('action') or '').strip() == 'save':
        if not selected_rival:
            error = 'Selecciona un rival.'
        elif not roster_map:
            error = 'No hay plantilla cargada para este rival. Ejecuta el sync de plantillas.'
        else:
            starters_limit = _required_starters_for_team(primary_team)
            convoked_codes = {str(v).strip() for v in request.POST.getlist('convoked_codes') if str(v).strip()}
            starter_codes = [str(v).strip() for v in request.POST.getlist('starter_codes') if str(v).strip()]
            # Titular implica convocado.
            convoked_codes.update(starter_codes)
            # Filtra solo códigos válidos.
            convoked_codes = {code for code in convoked_codes if code in roster_map}
            starter_codes = [code for code in starter_codes if code in roster_map]
            # Máx titulares según formato (F7/F11).
            if len(starter_codes) > starters_limit:
                starter_codes = starter_codes[:starters_limit]

            convoked_rows = [roster_map[code] for code in convoked_codes]
            convoked_rows.sort(key=lambda item: ((item.get('number') or 999), (item.get('name') or '').lower()))
            starter_rows = [roster_map[code] for code in starter_codes]
            starter_rows.sort(key=lambda item: ((item.get('number') or 999), (item.get('name') or '').lower()))
            starter_codes_set = {row['code'] for row in starter_rows}
            bench_rows = [row for row in convoked_rows if row['code'] not in starter_codes_set]

            lineup_data = {'starters': starter_rows, 'bench': bench_rows}
            try:
                RivalConvocationRecord.objects.update_or_create(
                    team=primary_team,
                    match=match,
                    defaults={
                        'rival_team': selected_rival,
                        'provider': provider,
                        'convocation_data': convoked_rows,
                        'lineup_data': lineup_data,
                    },
                )
                message = 'Convocatoria/Alineación del rival guardada.'
                # refresca record para pintar estado
                rival_record = RivalConvocationRecord.objects.filter(team=primary_team, match=match).select_related('rival_team').first()
            except Exception:
                error = 'No se pudo guardar la preparación del rival.'

    # Estado seleccionado (pre-check) desde DB.
    selected_convoked = set()
    selected_starters = set()
    if rival_record and isinstance(rival_record.convocation_data, list):
        for row in rival_record.convocation_data:
            if isinstance(row, dict) and row.get('code'):
                selected_convoked.add(str(row.get('code')))
    if rival_record and isinstance(rival_record.lineup_data, dict):
        for row in (rival_record.lineup_data.get('starters') or []):
            if isinstance(row, dict) and row.get('code'):
                selected_starters.add(str(row.get('code')))

    roster_rows = []
    for row in normalized_rows:
        code = row['code']
        roster_rows.append(
            {
                **row,
                'is_convoked': code in selected_convoked,
                'is_starter': code in selected_starters,
            }
        )
    roster_rows.sort(key=lambda item: ((item.get('number') or 999), (item.get('name') or '').lower()))

    team_crest_url = resolve_team_crest_url(request, primary_team, sync=True)
    return render(
        request,
        'football/coach_rival_prep.html',
        {
            'team_name': primary_team.display_name,
            'team_crest_url': team_crest_url,
            'match': match,
            'provider': provider,
            'providers': [
                {'value': TeamRosterSnapshot.PROVIDER_UNIVERSO, 'label': 'Universo RFAF'},
                {'value': TeamRosterSnapshot.PROVIDER_PREFERENTE, 'label': 'La Preferente'},
            ],
            'rivals': rivals,
            'selected_rival': selected_rival,
            'snapshot': snapshot,
            'roster_rows': roster_rows,
            'selected_convoked_count': len(selected_convoked),
            'selected_starters_count': len(selected_starters),
            'message': message,
            'error': error,
        },
    )


def _extract_pdf_text(pdf_file, max_chars=12000):
    if PdfReader is None:
        raise ValueError('Falta dependencia de lectura PDF. Instala `pypdf`.')

    def _ocr_text_from_image_bytes(raw_bytes):
        if not raw_bytes or Image is None or pytesseract is None:
            return ''
        try:
            with Image.open(io.BytesIO(raw_bytes)) as img:
                rgb = img.convert('RGB')
                # OCR bilingual by default to improve mixed ES/EN task sheets.
                return (pytesseract.image_to_string(rgb, lang='spa+eng') or '').strip()
        except Exception:
            return ''

    def _needs_ocr_boost(parsed_text):
        compact_hits = re.findall(r'\b[A-ZÁÉÍÓÚÜÑ]{10,}\b', str(parsed_text or ''))
        joined_hits = 0
        for token in compact_hits[:120]:
            repaired = _split_joined_upper_token(token)
            if repaired == token:
                joined_hits += 1
        return len(str(parsed_text or '')) < 500 or joined_hits >= 2

    def _ocr_pdf_pages_with_pdftoppm(local_pdf_file, max_pages=4):
        if pytesseract is None or Image is None:
            return ''
        pdftoppm_bin = shutil.which('pdftoppm')
        if not pdftoppm_bin:
            return ''
        try:
            if hasattr(local_pdf_file, 'seek'):
                local_pdf_file.seek(0)
            pdf_bytes = local_pdf_file.read()
            if not pdf_bytes:
                return ''
            with tempfile.TemporaryDirectory(prefix='task-ocr-') as tmpdir:
                tmp_path = Path(tmpdir)
                source_pdf = tmp_path / 'source.pdf'
                source_pdf.write_bytes(pdf_bytes)
                ocr_chunks = []
                page_limit = max(1, int(max_pages or 1))
                for page_no in range(1, page_limit + 1):
                    out_base = tmp_path / f'page-{page_no}'
                    subprocess.run(
                        [
                            pdftoppm_bin,
                            '-jpeg',
                            '-r',
                            '170',
                            '-f',
                            str(page_no),
                            '-singlefile',
                            str(source_pdf),
                            str(out_base),
                        ],
                        check=True,
                        capture_output=True,
                        timeout=35,
                    )
                    page_img = tmp_path / f'page-{page_no}.jpg'
                    if not page_img.exists():
                        continue
                    raw = page_img.read_bytes()
                    ocr_text = _ocr_text_from_image_bytes(raw)
                    if ocr_text:
                        ocr_chunks.append(ocr_text)
                    if sum(len(c) for c in ocr_chunks) >= 9000:
                        break
                return '\n'.join(ocr_chunks).strip()
        except Exception:
            return ''

    try:
        if hasattr(pdf_file, 'seek'):
            pdf_file.seek(0)
        reader = PdfReader(pdf_file)
        chunks = []
        for page in reader.pages:
            chunks.append((page.extract_text() or '').strip())
        text = '\n'.join([item for item in chunks if item]).strip()
        text = re.sub(r'\n{3,}', '\n\n', text)
        if len(text) < 180:
            ocr_chunks = []
            for page in reader.pages[:5]:
                images = getattr(page, 'images', []) or []
                for image in images[:3]:
                    image_bytes = getattr(image, 'data', b'') or b''
                    ocr_text = _ocr_text_from_image_bytes(image_bytes)
                    if ocr_text:
                        ocr_chunks.append(ocr_text)
                if sum(len(c) for c in ocr_chunks) >= 5000:
                    break
            if ocr_chunks:
                text = '\n'.join([text, '\n'.join(ocr_chunks)]).strip() if text else '\n'.join(ocr_chunks)
                text = re.sub(r'\n{3,}', '\n\n', text)
        if _needs_ocr_boost(text):
            ocr_rendered = _ocr_pdf_pages_with_pdftoppm(pdf_file, max_pages=5)
            if ocr_rendered:
                merged = '\n'.join([text, ocr_rendered]).strip() if text else ocr_rendered
                text = re.sub(r'\n{3,}', '\n\n', merged)
        text = _polish_spanish_text(_repair_joined_words_text(text), multiline=True)
        return text[:max_chars]
    except Exception:
        raise ValueError('No se pudo leer el PDF. Verifica que no esté protegido o corrupto.')


def _analyze_preview_image_bytes(raw_bytes):
    if Image is None or not raw_bytes:
        return None
    try:
        with Image.open(io.BytesIO(raw_bytes)) as img:
            rgb = img.convert('RGB')
            width, height = rgb.size
            if width <= 0 or height <= 0:
                return None
            sample = rgb.copy()
            sample.thumbnail((128, 128))
            pixels = list(sample.getdata())
            total = max(1, len(pixels))
            greenish = 0
            whitish = 0
            darkish = 0
            colorful = 0
            for r, g, b in pixels:
                if g > 70 and g > (r + 14) and g > (b + 10):
                    greenish += 1
                if r > 232 and g > 232 and b > 232:
                    whitish += 1
                if r < 30 and g < 30 and b < 30:
                    darkish += 1
                if (max(r, g, b) - min(r, g, b)) >= 24:
                    colorful += 1
            green_ratio = greenish / total
            white_ratio = whitish / total
            dark_ratio = darkish / total
            color_ratio = colorful / total
            area = width * height
            aspect = width / max(1.0, float(height))

            score = 0.0
            score += min(area / float(1280 * 720), 2.6) * 28.0
            score += green_ratio * 46.0
            score += color_ratio * 16.0
            if 0.95 <= aspect <= 2.35:
                score += 8.0
            if 1.15 <= aspect <= 2.05:
                score += 6.0
            score -= white_ratio * 44.0
            if min(width, height) < 210:
                score -= 26.0
            if white_ratio > 0.78 and green_ratio < 0.06:
                score -= 48.0
            if dark_ratio > 0.88:
                score -= 20.0

            return {
                'width': int(width),
                'height': int(height),
                'area': int(area),
                'aspect': float(aspect),
                'green_ratio': float(green_ratio),
                'white_ratio': float(white_ratio),
                'dark_ratio': float(dark_ratio),
                'score': float(score),
            }
    except Exception:
        return None


def _is_preview_quality_low(raw_bytes):
    metrics = _analyze_preview_image_bytes(raw_bytes)
    if not metrics:
        return False
    score = float(metrics.get('score') or 0.0)
    area = int(metrics.get('area') or 0)
    white_ratio = float(metrics.get('white_ratio') or 0.0)
    green_ratio = float(metrics.get('green_ratio') or 0.0)
    # Typical bad previews: tiny crops, white text snippets, or non-graphic chunks.
    if area < 260 * 170:
        return True
    if score < 10.0:
        return True
    if white_ratio > 0.72 and green_ratio < 0.08:
        return True
    return False


def _extract_preview_images_from_pdf(pdf_file, max_images=8, prefer_render=False):
    if pdf_file is None:
        return []
    if prefer_render:
        # Render via pdftoppm tends to be much sharper than embedded images
        # (many PDFs embed ~800px thumbnails). Also support multi-task PDFs by
        # returning up to `max_images`.
        rendered_payloads = _render_pdf_previews_with_pdftoppm(
            pdf_file,
            max_images=max_images,
            max_pages=10,
            scale_to=2400,
        )
        if rendered_payloads:
            return rendered_payloads
    payloads = []
    candidates = []
    if PdfReader is not None:
        try:
            if hasattr(pdf_file, 'seek'):
                pdf_file.seek(0)
            reader = PdfReader(pdf_file)
            seq = 0
            for page_idx, page in enumerate(reader.pages):
                images = getattr(page, 'images', []) or []
                for image in images:
                    seq += 1
                    raw = getattr(image, 'data', b'') or b''
                    if not raw:
                        continue
                    ext = str(getattr(image, 'name', 'img.bin') or 'img.bin').rsplit('.', 1)[-1].lower()
                    if ext not in {'png', 'jpg', 'jpeg', 'webp'}:
                        ext = 'png'
                    metrics = _analyze_preview_image_bytes(raw)
                    score = float(metrics.get('score') or 0.0) if metrics else 0.0
                    candidates.append(
                        {
                            'raw': raw,
                            'ext': ext,
                            'score': score,
                            'page_idx': page_idx,
                            'seq': seq,
                        }
                    )
        except Exception:
            candidates = []
    if candidates:
        max_count = max(1, int(max_images or 1))
        good_candidates = [item for item in candidates if float(item.get('score') or 0.0) >= 12.0]
        if good_candidates:
            # Keep original document order for multi-task PDFs once quality threshold is met.
            selected = sorted(good_candidates, key=lambda item: (int(item.get('page_idx') or 0), int(item.get('seq') or 0)))
        else:
            # If every embedded image is poor, still try top-scored ones before falling back.
            selected = sorted(candidates, key=lambda item: float(item.get('score') or 0.0), reverse=True)
        for item in selected[:max_count]:
            ext = str(item.get('ext') or 'jpg')
            filename = f'task-preview-{uuid.uuid4().hex[:10]}.{ext}'
            payloads.append((filename, ContentFile(item.get('raw') or b'')))
        if payloads:
            return payloads
    if payloads:
        return payloads

    # Fallback: render first page when PDF uses vector drawings (no embedded images).
    fallback_payloads = _render_pdf_previews_with_pdftoppm(pdf_file, max_images=max_images)
    if fallback_payloads:
        return fallback_payloads

    # Last fallback: generic field image so old tasks never stay without thumbnail.
    default_payload = _default_task_preview_payload()
    if default_payload:
        return [default_payload]
    return payloads


def _extract_preview_image_from_pdf(pdf_file, prefer_render=False):
    payloads = _extract_preview_images_from_pdf(pdf_file, max_images=1, prefer_render=prefer_render)
    return payloads[0] if payloads else None


def _extract_pdf_graphic_assets_from_pdf(pdf_file, max_assets=60):
    """
    Extrae imágenes embebidas en un PDF (no renderiza páginas).

    Útil para "rescatar" iconos (balones, conos, etc.) de PDFs de terceros y
    reutilizarlos como recursos de pizarra dentro del sistema.
    """
    if PdfReader is None or pdf_file is None:
        return []
    try:
        limit = max(1, min(int(max_assets or 1), 240))
    except Exception:
        limit = 60
    if hasattr(pdf_file, 'seek'):
        try:
            pdf_file.seek(0)
        except Exception:
            pass
    try:
        reader = PdfReader(pdf_file)
    except Exception:
        return []
    seen = set()
    assets = []
    seq = 0
    for page_idx, page in enumerate(reader.pages):
        images = getattr(page, 'images', []) or []
        for image in images:
            seq += 1
            raw = getattr(image, 'data', b'') or b''
            if not raw or len(raw) < 512:
                continue
            sha = hashlib.sha256(raw).hexdigest()
            if sha in seen:
                continue
            seen.add(sha)
            ext = str(getattr(image, 'name', 'img.bin') or 'img.bin').rsplit('.', 1)[-1].lower()
            name_hint = str(getattr(image, 'name', '') or '').rsplit('/', 1)[-1]
            if ext not in {'png', 'jpg', 'jpeg', 'webp'}:
                ext = 'png'
            metrics = _analyze_preview_image_bytes(raw)
            if metrics:
                w = int(metrics.get('width') or 0)
                h = int(metrics.get('height') or 0)
                area = int(metrics.get('area') or 0)
                green_ratio = float(metrics.get('green_ratio') or 0.0)
                white_ratio = float(metrics.get('white_ratio') or 0.0)
                if w <= 0 or h <= 0:
                    continue
                # Evita miniaturas demasiado pequeñas (ruido) y fondos gigantes del campo/tabla.
                if area < 18 * 18:
                    continue
                if max(w, h) > 1200 or area > (1200 * 1200):
                    continue
                # Muchos PDFs embeben el fondo del campo (muy verde). Lo excluimos para que la
                # librería no se llene de "pitch".
                if green_ratio > 0.22 and area > (520 * 380) and white_ratio < 0.55:
                    continue
            assets.append(
                {
                    'sha256': sha,
                    'raw': raw,
                    'ext': ext,
                    'name_hint': name_hint,
                    'page_idx': page_idx,
                    'seq': seq,
                    'width': int(metrics.get('width') or 0) if metrics else 0,
                    'height': int(metrics.get('height') or 0) if metrics else 0,
                }
            )
            if len(assets) >= limit:
                return assets
    return assets


def _save_pdf_graphic_assets_to_library(*, team=None, owner=None, pdf_file=None, source_pdf_name='', max_assets=60):
    """
    Persiste assets en PdfGraphicAsset con deduplicación por sha256 (por team u owner).
    """
    if not pdf_file:
        return {'saved': 0, 'skipped': 0, 'errors': 0}
    if not team and not owner:
        return {'saved': 0, 'skipped': 0, 'errors': 0}
    extracted = _extract_pdf_graphic_assets_from_pdf(pdf_file, max_assets=max_assets)
    if not extracted:
        return {'saved': 0, 'skipped': 0, 'errors': 0}
    saved = 0
    skipped = 0
    errors = 0
    for item in extracted:
        sha = str(item.get('sha256') or '').strip()
        if not sha:
            continue
        ext = str(item.get('ext') or 'png').lower().strip() or 'png'
        name_hint = str(item.get('name_hint') or '').strip()
        raw = item.get('raw') or b''
        if not raw:
            continue
        filename = f'pdf-asset-{sha[:16]}.{ext if ext != "jpeg" else "jpg"}'
        try:
            obj = PdfGraphicAsset(
                team=team,
                owner=owner,
                sha256=sha,
                title=(Path(name_hint).stem if name_hint else '')[:160],
                source_pdf_name=str(source_pdf_name or '')[:220],
                width=int(item.get('width') or 0) or None,
                height=int(item.get('height') or 0) or None,
            )
            obj.file.save(filename, ContentFile(raw), save=False)
            obj.save()
            saved += 1
        except Exception:
            # Normalmente será duplicado por constraint (o storage), lo tratamos como skip.
            try:
                existing = PdfGraphicAsset.objects.filter(sha256=sha)
                if team:
                    existing = existing.filter(team=team)
                if owner:
                    existing = existing.filter(owner=owner)
                if existing.exists():
                    skipped += 1
                    continue
            except Exception:
                pass
            errors += 1
    return {'saved': saved, 'skipped': skipped, 'errors': errors}


def _recreate_canvas_state_from_preview_image_bytes(raw_bytes, canvas_width=1054, canvas_height=684):
    """
    Intenta reconstruir una pizarra editable a partir de una imagen raster (extraída del PDF).
    Es una aproximación basada en color/contornos (beta): zonas, conos, jugadores (local/visitante) y flechas simples.
    """
    if not raw_bytes or Image is None:
        return None
    try:
        img = Image.open(io.BytesIO(raw_bytes))
        img.load()
        img = img.convert('RGB')
    except Exception:
        return None

    # Auto-crop al área del campo (dominante en verde) para mejorar el reconocimiento.
    # Muchos PDFs renderizados incluyen márgenes y tablas; sin recorte, los elementos quedan demasiado pequeños.
    try:
        w0, h0 = img.size
        if w0 > 0 and h0 > 0:
            probe_max = 320
            probe_scale = min(1.0, float(probe_max) / float(max(w0, h0)))
            probe = img
            if probe_scale < 1.0:
                probe = img.resize(
                    (max(1, int(round(w0 * probe_scale))), max(1, int(round(h0 * probe_scale)))),
                    Image.BILINEAR,
                )
            pw, ph = probe.size
            ppx = probe.load()

            minx = pw
            miny = ph
            maxx = -1
            maxy = -1
            green_count = 0
            for yy in range(ph):
                for xx in range(pw):
                    r, g, b = ppx[xx, yy]
                    if g > 70 and g > r + 14 and g > b + 14:
                        green_count += 1
                        if xx < minx:
                            minx = xx
                        if yy < miny:
                            miny = yy
                        if xx > maxx:
                            maxx = xx
                        if yy > maxy:
                            maxy = yy
            if maxx > minx and maxy > miny:
                area = float((maxx - minx + 1) * (maxy - miny + 1))
                total = float(max(1, pw * ph))
                # Recortamos si el área verde es sustancial (evita falsos positivos en PDFs sin pizarra).
                if area / total >= 0.12 and green_count / total >= 0.10:
                    pad = int(round(0.04 * float(max(pw, ph))))
                    minx = max(0, minx - pad)
                    miny = max(0, miny - pad)
                    maxx = min(pw - 1, maxx + pad)
                    maxy = min(ph - 1, maxy + pad)
                    sx = 1.0 / probe_scale
                    crop_box = (
                        int(minx * sx),
                        int(miny * sx),
                        int((maxx + 1) * sx),
                        int((maxy + 1) * sx),
                    )
                    # Clamp to image bounds
                    crop_box = (
                        max(0, min(int(crop_box[0]), w0 - 1)),
                        max(0, min(int(crop_box[1]), h0 - 1)),
                        max(1, min(int(crop_box[2]), w0)),
                        max(1, min(int(crop_box[3]), h0)),
                    )
                    if crop_box[2] > crop_box[0] + 20 and crop_box[3] > crop_box[1] + 20:
                        img = img.crop(crop_box)
    except Exception:
        pass

    try:
        world_w = max(320, int(canvas_width or 1054))
        world_h = max(180, int(canvas_height or 684))
    except Exception:
        world_w, world_h = 1054, 684

    w0, h0 = img.size
    if w0 <= 0 or h0 <= 0:
        return None
    # Más resolución => mejor detección de flechas/figuras (sin subir a tamaños que ralenticen demasiado).
    max_side = 780
    scale = min(1.0, float(max_side) / float(max(w0, h0)))
    if scale < 1.0:
        img = img.resize((max(1, int(round(w0 * scale))), max(1, int(round(h0 * scale)))), Image.BILINEAR)
    w, h = img.size
    px = img.load()

    def _reservoir_sample_point(points, px_x, px_y, count, cap=1800):
        """
        Guarda una muestra representativa de puntos del componente (para endpoints/clasificación)
        sin sesgo de "los primeros píxeles explorados" por DFS/BFS.
        Usamos una variante determinista de reservoir sampling basada en hash.
        """
        if cap <= 0:
            return
        if len(points) < cap:
            points.append((px_x, px_y))
            return
        try:
            c = int(count or 0)
        except Exception:
            c = 0
        if c <= 0:
            return
        # Hash determinista "suficientemente aleatorio" para dispersar la muestra.
        h = ((int(px_x) + 1) * 73856093) ^ ((int(px_y) + 1) * 19349663) ^ (c * 83492791)
        j = int(h % c)
        if j < cap:
            points[j] = (px_x, px_y)

    def _iter_components(predicate, min_pixels=10, max_pixels=50000):
        visited = bytearray(w * h)
        components = []
        for y in range(h):
            row_base = y * w
            for x in range(w):
                idx = row_base + x
                if visited[idx]:
                    continue
                r, g, b = px[x, y]
                if not predicate(r, g, b):
                    continue
                queue = [idx]
                visited[idx] = 1
                minx = maxx = x
                miny = maxy = y
                count = 0
                sumx = sumy = 0
                sumr = sumg = sumb = 0
                points = []
                while queue:
                    cur = queue.pop()
                    cy, cx = divmod(cur, w)
                    rr, gg, bb = px[cx, cy]
                    if not predicate(rr, gg, bb):
                        continue
                    count += 1
                    sumx += cx
                    sumy += cy
                    sumr += rr
                    sumg += gg
                    sumb += bb
                    _reservoir_sample_point(points, cx, cy, count, cap=1800)
                    if cx < minx:
                        minx = cx
                    if cx > maxx:
                        maxx = cx
                    if cy < miny:
                        miny = cy
                    if cy > maxy:
                        maxy = cy
                    if cx > 0:
                        n = cur - 1
                        if not visited[n]:
                            visited[n] = 1
                            queue.append(n)
                    if cx + 1 < w:
                        n = cur + 1
                        if not visited[n]:
                            visited[n] = 1
                            queue.append(n)
                    if cy > 0:
                        n = cur - w
                        if not visited[n]:
                            visited[n] = 1
                            queue.append(n)
                    if cy + 1 < h:
                        n = cur + w
                        if not visited[n]:
                            visited[n] = 1
                            queue.append(n)
                    if count > max_pixels:
                        break
                if count < min_pixels:
                    continue
                components.append(
                    {
                        'minx': minx,
                        'maxx': maxx,
                        'miny': miny,
                        'maxy': maxy,
                        'count': count,
                        'sumx': sumx,
                        'sumy': sumy,
                        'sumr': sumr,
                        'sumg': sumg,
                        'sumb': sumb,
                        'points': points,
                    }
                )
        return components

    def _iter_components_mask(mask_px, min_pixels=10, max_pixels=50000):
        """
        Igual que `_iter_components`, pero basado en una máscara binaria ya calculada.
        `mask_px[x, y]` debe ser >0 para considerar el pixel como parte del componente.
        """
        visited = bytearray(w * h)
        components = []
        for y in range(h):
            row_base = y * w
            for x in range(w):
                idx = row_base + x
                if visited[idx]:
                    continue
                if not mask_px[x, y]:
                    continue
                queue = [idx]
                visited[idx] = 1
                minx = maxx = x
                miny = maxy = y
                count = 0
                sumx = sumy = 0
                points = []
                while queue:
                    cur = queue.pop()
                    cy, cx = divmod(cur, w)
                    if not mask_px[cx, cy]:
                        continue
                    count += 1
                    sumx += cx
                    sumy += cy
                    _reservoir_sample_point(points, cx, cy, count, cap=1800)
                    if cx < minx:
                        minx = cx
                    if cx > maxx:
                        maxx = cx
                    if cy < miny:
                        miny = cy
                    if cy > maxy:
                        maxy = cy
                    if cx > 0:
                        n = cur - 1
                        if not visited[n]:
                            visited[n] = 1
                            queue.append(n)
                    if cx + 1 < w:
                        n = cur + 1
                        if not visited[n]:
                            visited[n] = 1
                            queue.append(n)
                    if cy > 0:
                        n = cur - w
                        if not visited[n]:
                            visited[n] = 1
                            queue.append(n)
                    if cy + 1 < h:
                        n = cur + w
                        if not visited[n]:
                            visited[n] = 1
                            queue.append(n)
                    if count > max_pixels:
                        break
                if count < min_pixels:
                    continue
                components.append(
                    {
                        'minx': minx,
                        'maxx': maxx,
                        'miny': miny,
                        'maxy': maxy,
                        'count': count,
                        'sumx': sumx,
                        'sumy': sumy,
                        'points': points,
                    }
                )
        return components

    def _map_x(x):
        return float(x) / max(1, w) * float(world_w)

    def _map_y(y):
        return float(y) / max(1, h) * float(world_h)

    def _avg_rgb(comp):
        n = max(1, int(comp.get('count') or 1))
        return (
            int((comp.get('sumr') or 0) / n),
            int((comp.get('sumg') or 0) / n),
            int((comp.get('sumb') or 0) / n),
        )

    def _bbox(comp):
        return (
            int(comp.get('minx') or 0),
            int(comp.get('miny') or 0),
            int(comp.get('maxx') or 0),
            int(comp.get('maxy') or 0),
        )

    def _is_zone_color(r, g, b):
        return g >= 185 and r >= 120 and b <= 175 and (g - b) >= 35

    def _is_marker_color(r, g, b):
        if r <= 10 and g <= 10 and b <= 10:
            return False
        mx = max(r, g, b)
        mn = min(r, g, b)
        if mx < 85:
            return False
        if mx - mn < 55:
            return False
        if g > r and g > b and mx < 210 and (g - max(r, b)) < 70:
            return False
        return True

    def _is_ink_pixel(r, g, b):
        """
        Píxeles "tinta" (flechas/trazos) sobre el césped.
        - Excluye verdes dominantes (césped).
        - Incluye grises/negros incluso con anti-alias al reescalar.
        """
        # césped (verde dominante)
        if g > 70 and g > r + 14 and g > b + 14:
            return False
        # luminancia perceptual
        lum = 0.2126 * float(r) + 0.7152 * float(g) + 0.0722 * float(b)
        if lum <= 150:
            return True
        mx = max(r, g, b)
        mn = min(r, g, b)
        sat = mx - mn
        # Muchos PDFs rasterizan flechas/trazos en gris (no negro). Capturamos grises medios,
        # pero evitamos blancos puros para no "pillar" las líneas del campo.
        if lum <= 190 and sat <= 26 and mx <= 215:
            return True
        # colores medios saturados (p.ej. flechas oscuras no-grises)
        if lum <= 175 and sat >= 45 and mx <= 215:
            return True
        return False

    zones = _iter_components(_is_zone_color, min_pixels=180)
    markers = _iter_components(_is_marker_color, min_pixels=18, max_pixels=6000)
    ink_lines = []
    try:
        mask = Image.new('L', (w, h), 0)
        mp = mask.load()
        for yy in range(h):
            for xx in range(w):
                rr, gg, bb = px[xx, yy]
                if _is_ink_pixel(rr, gg, bb):
                    mp[xx, yy] = 255
        # Conecta trazos discontinuos (dash/dot) tras reescalar.
        if ImageFilter is not None:
            try:
                mask = mask.filter(ImageFilter.MaxFilter(3))
                mp = mask.load()
            except Exception:
                pass
        ink_lines = _iter_components_mask(mp, min_pixels=28, max_pixels=22000)
    except Exception:
        # Fallback sin máscara: no reconstruye flechas, pero no rompe el import.
        ink_lines = []

    objects = []

    for comp in zones:
        x1, y1, x2, y2 = _bbox(comp)
        bw = max(1, x2 - x1 + 1)
        bh = max(1, y2 - y1 + 1)
        if bw < 18 or bh < 14:
            continue
        if (bw * bh) < 260:
            continue
        cx = (x1 + x2) / 2.0
        cy = (y1 + y2) / 2.0
        objects.append(
            {
                'type': 'rect',
                'left': _map_x(cx),
                'top': _map_y(cy),
                'originX': 'center',
                'originY': 'center',
                'width': _map_x(bw) - _map_x(0),
                'height': _map_y(bh) - _map_y(0),
                'rx': 12,
                'ry': 12,
                'fill': 'rgba(34,211,238,0.16)',
                'stroke': '#22d3ee',
                'strokeWidth': 3,
                'data': {'kind': 'zone', 'color': '#22d3ee'},
                'objectCaching': False,
            }
        )

    for comp in markers:
        x1, y1, x2, y2 = _bbox(comp)
        bw = max(1, x2 - x1 + 1)
        bh = max(1, y2 - y1 + 1)
        area = int(comp.get('count') or 0)
        if bw > 46 or bh > 46:
            continue
        if area > 2600:
            continue
        cx = (x1 + x2) / 2.0
        cy = (y1 + y2) / 2.0
        r, g, b = _avg_rgb(comp)
        is_green = g > r + 35 and g > b + 35 and g >= 120
        is_purple = b >= 120 and r >= 80 and g <= 135 and (b - g) >= 25
        is_red = r >= 140 and g <= 120 and (r - g) >= 30
        is_orange = r >= 150 and g >= 80 and b <= 120 and (r - b) >= 35

        if (is_red or is_orange) and area <= 520:
            objects.append(
                {
                    'type': 'triangle',
                    'left': _map_x(cx),
                    'top': _map_y(cy),
                    'originX': 'center',
                    'originY': 'center',
                    'width': 24,
                    'height': 24,
                    'fill': '#f97316',
                    'stroke': '#7c2d12',
                    'strokeWidth': 1.6,
                    'data': {'kind': 'cone', 'color': '#f97316'},
                    'objectCaching': False,
                }
            )
            continue

        if is_green and area <= 900:
            objects.append(
                {
                    # Importante: usamos un grupo "token" mínimo para que el editor JS
                    # lo convierta automáticamente a la chapa oficial (player_local).
                    'type': 'group',
                    'left': _map_x(cx),
                    'top': _map_y(cy),
                    'originX': 'center',
                    'originY': 'center',
                    'objectCaching': False,
                    'data': {
                        'kind': 'token',
                        'token_kind': 'player_local',
                        'playerName': 'Jugador',
                        'playerNumber': '',
                    },
                    'objects': [
                        {
                            'type': 'circle',
                            'left': 0,
                            'top': 0,
                            'originX': 'center',
                            'originY': 'center',
                            'radius': 16,
                            'fill': '#1d4ed8',
                            'stroke': '#eff6ff',
                            'strokeWidth': 2,
                            'objectCaching': False,
                        }
                    ],
                }
            )
            continue

        if is_purple and area <= 1100:
            objects.append(
                {
                    # Token rival mínimo => conversión a chapa oficial (player_rival).
                    'type': 'group',
                    'left': _map_x(cx),
                    'top': _map_y(cy),
                    'originX': 'center',
                    'originY': 'center',
                    'objectCaching': False,
                    'data': {
                        'kind': 'token',
                        'token_kind': 'player_rival',
                        'playerName': 'Rival',
                        'playerNumber': '',
                    },
                    'objects': [
                        {
                            'type': 'circle',
                            'left': 0,
                            'top': 0,
                            'originX': 'center',
                            'originY': 'center',
                            'radius': 16,
                            'fill': '#dc2626',
                            'stroke': '#fff7ed',
                            'strokeWidth': 2,
                            'objectCaching': False,
                        }
                    ],
                }
            )
            continue

    for comp in ink_lines:
        x1, y1, x2, y2 = _bbox(comp)
        bw = max(1, x2 - x1 + 1)
        bh = max(1, y2 - y1 + 1)
        bbox_area = int(bw * bh)
        count = int(comp.get('count') or 0)
        if bw < 22 and bh < 22:
            continue
        if bbox_area < 260:
            continue
        # Densidad alta => normalmente etiquetas rectangulares o iconos rellenos (no flechas).
        density = float(count) / float(max(1, bbox_area))
        if density > 0.62 and bbox_area > 520:
            continue
        points = comp.get('points') or []
        if len(points) < 12:
            continue

        # Algunas figuras geométricas llegan como contorno (no relleno) y se confunden con diagonales.
        # Intentamos detectar rectángulos/círculos para convertirlos a "shape-*" editable.
        def _edge_hit_counts(_points, tol=4):
            left = right = top = bottom = 0
            for (pxx, pyy) in _points:
                if abs(pxx - x1) <= tol:
                    left += 1
                if abs(pxx - x2) <= tol:
                    right += 1
                if abs(pyy - y1) <= tol:
                    top += 1
                if abs(pyy - y2) <= tol:
                    bottom += 1
            return left, right, top, bottom

        def _looks_like_rect_outline(_points):
            if bw < 46 or bh < 46:
                return False
            left, right, top, bottom = _edge_hit_counts(_points, tol=4)
            total = max(1, len(_points))
            min_edge = max(12, int(round(0.05 * total)))
            if left < min_edge or right < min_edge or top < min_edge or bottom < min_edge:
                return False
            edge_sum = left + right + top + bottom
            # La mayoría de puntos deben estar cerca del perímetro.
            # Nota: tras `MaxFilter`/anti-alias puede haber "relleno" parcial; usamos umbral más laxo.
            if (edge_sum / float(total)) < 0.55:
                return False
            # Evita "marcos" muy finos (probablemente líneas del campo).
            if min(bw, bh) < 18:
                return False
            return True

        def _looks_like_circle_outline(_points):
            if bw < 44 or bh < 44:
                return False
            aspect = float(bw) / float(max(1, bh))
            if aspect < 0.78 or aspect > 1.28:
                return False
            # Si hay mucha presencia en los 4 bordes del bbox, no es un círculo (es un rectángulo).
            left, right, top, bottom = _edge_hit_counts(_points, tol=4)
            total = max(1, len(_points))
            min_edge = max(12, int(round(0.06 * total)))
            if left >= min_edge and right >= min_edge and top >= min_edge and bottom >= min_edge:
                return False
            cx0 = (x1 + x2) / 2.0
            cy0 = (y1 + y2) / 2.0
            stride = max(1, int(len(_points) / 220))
            dists = []
            for (pxx, pyy) in _points[::stride]:
                dx0 = float(pxx) - cx0
                dy0 = float(pyy) - cy0
                dists.append((dx0 * dx0 + dy0 * dy0) ** 0.5)
            if len(dists) < 10:
                return False
            mean = sum(dists) / float(len(dists))
            if mean < 18:
                return False
            var = sum((d - mean) ** 2 for d in dists) / float(len(dists))
            stdev = var ** 0.5
            return stdev <= mean * 0.18

        if _looks_like_rect_outline(points):
            cx0 = (x1 + x2) / 2.0
            cy0 = (y1 + y2) / 2.0
            world_wd = _map_x(bw) - _map_x(0)
            world_ht = _map_y(bh) - _map_y(0)
            kind = 'shape-rect'
            if 0.92 <= (float(bw) / float(max(1, bh))) <= 1.08:
                kind = 'shape-square'
            objects.append(
                {
                    'type': 'rect',
                    'left': _map_x(cx0),
                    'top': _map_y(cy0),
                    'originX': 'center',
                    'originY': 'center',
                    'width': world_wd,
                    'height': world_ht,
                    'rx': 10,
                    'ry': 10,
                    'fill': 'rgba(34,211,238,0.12)',
                    'stroke': '#22d3ee',
                    'strokeWidth': 3,
                    'data': {'kind': kind},
                    'objectCaching': False,
                }
            )
            continue

        if _looks_like_circle_outline(points):
            cx0 = (x1 + x2) / 2.0
            cy0 = (y1 + y2) / 2.0
            world_wd = _map_x(bw) - _map_x(0)
            world_ht = _map_y(bh) - _map_y(0)
            radius = max(12.0, min(world_wd, world_ht) / 2.0)
            objects.append(
                {
                    'type': 'circle',
                    'left': _map_x(cx0),
                    'top': _map_y(cy0),
                    'originX': 'center',
                    'originY': 'center',
                    'radius': radius,
                    'fill': 'rgba(34,211,238,0.12)',
                    'stroke': '#22d3ee',
                    'strokeWidth': 3,
                    'data': {'kind': 'shape-circle'},
                    'objectCaching': False,
                }
            )
            continue

        min_s = 1e9
        max_s = -1e9
        min_d = 1e9
        max_d = -1e9
        p_min_s = p_max_s = p_min_d = p_max_d = points[0]
        for (pxx, pyy) in points:
            s = pxx + pyy
            d = pxx - pyy
            if s < min_s:
                min_s = s
                p_min_s = (pxx, pyy)
            if s > max_s:
                max_s = s
                p_max_s = (pxx, pyy)
            if d < min_d:
                min_d = d
                p_min_d = (pxx, pyy)
            if d > max_d:
                max_d = d
                p_max_d = (pxx, pyy)
        candidates = [(p_min_s, p_max_s), (p_min_d, p_max_d)]
        best = None
        best_len = 0.0
        for a, b in candidates:
            dx = float(b[0] - a[0])
            dy = float(b[1] - a[1])
            dist = (dx * dx + dy * dy) ** 0.5
            if dist > best_len:
                best_len = dist
                best = (a, b)
        if not best or best_len < 20:
            continue
        (ax, ay), (bx, by) = best
        x1w, y1w = _map_x(ax), _map_y(ay)
        x2w, y2w = _map_x(bx), _map_y(by)
        cx = (x1w + x2w) / 2.0
        cy = (y1w + y2w) / 2.0
        dx = x2w - x1w
        dy = y2w - y1w
        length = (dx * dx + dy * dy) ** 0.5
        if length < 52:
            continue
        angle = (180.0 / math.pi) * math.atan2(dy, dx)
        base_len = 102.0
        scale_x = max(0.55, min(6.2, float(length) / base_len))
        objects.append(
            {
                'type': 'group',
                'left': cx,
                'top': cy,
                'originX': 'center',
                'originY': 'center',
                'angle': angle,
                'scaleX': scale_x,
                'scaleY': 1.0,
                'data': {'kind': 'arrow'},
                'objectCaching': False,
                'objects': [
                    {
                        'type': 'line',
                        'x1': -50,
                        'y1': 0,
                        'x2': 40,
                        'y2': 0,
                        'originX': 'center',
                        'originY': 'center',
                        'stroke': '#22d3ee',
                        'strokeWidth': 4,
                        'objectCaching': False,
                    },
                    {
                        'type': 'triangle',
                        'left': 52,
                        'top': 0,
                        'width': 18,
                        'height': 18,
                        'angle': 90,
                        'fill': '#22d3ee',
                        'originX': 'center',
                        'originY': 'center',
                        'objectCaching': False,
                    },
                ],
            }
        )

    if not objects:
        return None
    objects_sorted = []
    objects_sorted.extend([obj for obj in objects if str(obj.get('type')) == 'rect'])
    objects_sorted.extend([obj for obj in objects if str(obj.get('type')) != 'rect'])
    return {'version': '5.3.0', 'objects': objects_sorted}


def _maybe_recreate_board_from_preview_bytes(task, preview_bytes):
    if not task or not preview_bytes or Image is None:
        return False
    try:
        portrait = False
        img_w = 0
        img_h = 0
        try:
            with Image.open(io.BytesIO(preview_bytes)) as im:
                img_w = int(getattr(im, 'width', 0) or 0)
                img_h = int(getattr(im, 'height', 0) or 0)
                portrait = bool(img_h > img_w) if img_w and img_h else False
        except Exception:
            portrait = False

        # En lugar de "reconstruir" chapas/flechas/textos (muy propenso a errores),
        # colocamos el gráfico original del PDF como fondo dentro del canvas.
        # Así la representación es 1:1 con el PDF, y encima se pueden añadir/editar elementos del sistema.
        world_w = 684 if portrait else 1054
        world_h = 1054 if portrait else 684
        if img_w <= 0 or img_h <= 0:
            img_w = world_w
            img_h = world_h
        scale = min(float(world_w) / float(img_w or 1), float(world_h) / float(img_h or 1))
        try:
            scale = float(scale)
        except Exception:
            scale = 1.0
        scale = max(0.05, min(scale, 4.0))

        # Usamos el endpoint interno (misma origin) para evitar problemas CORS/taint al exportar PNG.
        preview_src = ''
        try:
            preview_src = reverse('session-task-preview-file', args=[task.id])
            preview_name = str(getattr(getattr(task, 'task_preview_image', None), 'name', '') or '').strip()
            if preview_name:
                preview_src = f'{preview_src}?v={quote(preview_name)}'
        except Exception:
            preview_src = ''
        if not preview_src:
            return False

        recreated = {
            'version': '5.3.0',
            'objects': [
                {
                    'type': 'image',
                    'left': int(round(world_w / 2)),
                    'top': int(round(world_h / 2)),
                    'originX': 'center',
                    'originY': 'center',
                    'scaleX': scale,
                    'scaleY': scale,
                    'angle': 0,
                    'opacity': 1,
                    'src': preview_src,
                    'selectable': False,
                    'evented': False,
                    'hasControls': False,
                    'hasBorders': False,
                    'objectCaching': False,
                    'data': {
                        'kind': 'pdf-background',
                        'base': True,
                        'locked': True,
                        'source': 'pdf_preview',
                    },
                }
            ],
        }
        layout = task.tactical_layout if isinstance(getattr(task, 'tactical_layout', None), dict) else {}
        meta = layout.get('meta') if isinstance(layout.get('meta'), dict) else {}
        meta = dict(meta)
        meta.setdefault('pitch_preset', 'full_pitch')
        meta['pitch_orientation'] = 'portrait' if portrait else 'landscape'
        meta['graphic_editor'] = {
            'canvas_state': recreated,
            'canvas_width': world_w,
            'canvas_height': world_h,
        }
        layout['meta'] = meta
        task.tactical_layout = layout
        task.save(update_fields=['tactical_layout'])
        return True
    except Exception:
        return False


def _render_pdf_preview_with_pdftoppm(pdf_file):
    previews = _render_pdf_previews_with_pdftoppm(pdf_file, max_images=1)
    return previews[0] if previews else None


def _split_board_page_image_bytes(raw_bytes, max_images=3):
    """
    Intenta dividir una página que contiene varias pizarras/campos en varias imágenes recortadas.
    Útil para PDFs donde hay varias tareas en la misma página (p.ej. "Tarea 1/2/3" con 3 campos).
    Devuelve lista de JPEG bytes en orden visual (arriba->abajo, izquierda->derecha).
    """
    if not raw_bytes or Image is None:
        return []
    try:
        max_images = max(1, int(max_images or 1))
    except Exception:
        max_images = 3
    try:
        with Image.open(io.BytesIO(raw_bytes)) as img:
            img = img.convert('RGB')
            w0, h0 = img.size
            if w0 <= 0 or h0 <= 0:
                return []
            probe_max = 420
            probe_scale = min(1.0, float(probe_max) / float(max(w0, h0)))
            probe = img
            if probe_scale < 1.0:
                probe = img.resize(
                    (max(1, int(round(w0 * probe_scale))), max(1, int(round(h0 * probe_scale)))),
                    Image.BILINEAR,
                )
            w, h = probe.size
            px = probe.load()
            visited = bytearray(w * h)

            def is_green(r, g, b):
                return g > 70 and g > r + 14 and g > b + 14

            components = []
            for y in range(h):
                row = y * w
                for x in range(w):
                    idx = row + x
                    if visited[idx]:
                        continue
                    r, g, b = px[x, y]
                    if not is_green(r, g, b):
                        continue
                    stack = [idx]
                    visited[idx] = 1
                    minx = maxx = x
                    miny = maxy = y
                    count = 0
                    while stack:
                        cur = stack.pop()
                        cy, cx = divmod(cur, w)
                        rr, gg, bb = px[cx, cy]
                        if not is_green(rr, gg, bb):
                            continue
                        count += 1
                        if cx < minx:
                            minx = cx
                        if cx > maxx:
                            maxx = cx
                        if cy < miny:
                            miny = cy
                        if cy > maxy:
                            maxy = cy
                        if cx > 0:
                            n = cur - 1
                            if not visited[n]:
                                visited[n] = 1
                                stack.append(n)
                        if cx + 1 < w:
                            n = cur + 1
                            if not visited[n]:
                                visited[n] = 1
                                stack.append(n)
                        if cy > 0:
                            n = cur - w
                            if not visited[n]:
                                visited[n] = 1
                                stack.append(n)
                        if cy + 1 < h:
                            n = cur + w
                            if not visited[n]:
                                visited[n] = 1
                                stack.append(n)
                    bw = (maxx - minx + 1)
                    bh = (maxy - miny + 1)
                    area = bw * bh
                    # Filtra blobs pequeños (ruido)
                    if count < 80 or area < int(0.012 * float(w * h)):
                        continue
                    aspect = float(bw) / float(max(1, bh))
                    if aspect < 0.22 or aspect > 4.2:
                        continue
                    components.append({'minx': minx, 'miny': miny, 'maxx': maxx, 'maxy': maxy, 'area': area})

            if len(components) < 2:
                return []
            # Orden visual: arriba->abajo, izquierda->derecha
            components.sort(key=lambda c: (int(c['miny']), int(c['minx'])))
            # Mantén solo las componentes grandes primero
            components = sorted(components, key=lambda c: int(c['area']), reverse=True)[: max_images * 2]
            components.sort(key=lambda c: (int(c['miny']), int(c['minx'])))

            pad = int(round(0.03 * float(max(w, h))))
            sx = 1.0 / probe_scale
            crops = []
            for comp in components[:max_images]:
                minx = max(0, int((comp['minx'] - pad) * sx))
                miny = max(0, int((comp['miny'] - pad) * sx))
                maxx = min(w0, int((comp['maxx'] + 1 + pad) * sx))
                maxy = min(h0, int((comp['maxy'] + 1 + pad) * sx))
                if maxx <= minx + 40 or maxy <= miny + 40:
                    continue
                crop = img.crop((minx, miny, maxx, maxy))
                buf = io.BytesIO()
                crop.save(buf, format='JPEG', quality=86, optimize=True)
                crops.append(buf.getvalue())
            return crops
    except Exception:
        return []


def _render_pdf_previews_with_pdftoppm(pdf_file, max_images=1, max_pages=10, scale_to=1700):
    """
    Renderiza páginas del PDF (vía pdftoppm) y devuelve las mejores previsualizaciones.
    - Si el PDF incluye varias páginas, elegimos las más "gráficas" (ratio verde alto -> pizarra/campo).
    - Devuelve lista de (filename, ContentFile).
    """
    if pdf_file is None:
        return []
    pdftoppm_bin = shutil.which('pdftoppm')
    if not pdftoppm_bin:
        return []
    try:
        max_images = max(1, int(max_images or 1))
    except Exception:
        max_images = 1
    try:
        max_pages = max(1, int(max_pages or 1))
    except Exception:
        max_pages = 10
    try:
        scale_to = int(scale_to or 1700)
    except Exception:
        scale_to = 1700
    scale_to = max(900, min(scale_to, 3200))
    try:
        if hasattr(pdf_file, 'seek'):
            pdf_file.seek(0)
        pdf_bytes = pdf_file.read()
        if not pdf_bytes:
            return []
        with tempfile.TemporaryDirectory(prefix='task-preview-') as tmpdir:
            tmp_path = Path(tmpdir)
            source_pdf = tmp_path / 'source.pdf'
            output_base = tmp_path / 'preview'
            source_pdf.write_bytes(pdf_bytes)
            # Renderiza varias páginas. pdftoppm generará preview-1.jpg, preview-2.jpg, ...
            subprocess.run(
                [
                    pdftoppm_bin,
                    '-jpeg',
                    '-f',
                    '1',
                    '-l',
                    str(max_pages),
                    '-scale-to',
                    str(scale_to),
                    str(source_pdf),
                    str(output_base),
                ],
                check=True,
                capture_output=True,
                timeout=60,
            )
            rendered = []
            for page_idx in range(1, max_pages + 1):
                candidate_path = tmp_path / f'preview-{page_idx}.jpg'
                if not candidate_path.exists():
                    continue
                raw = candidate_path.read_bytes()
                if not raw:
                    continue
                metrics = _analyze_preview_image_bytes(raw) or {}
                score = float(metrics.get('score') or 0.0)
                green_ratio = float(metrics.get('green_ratio') or 0.0)
                white_ratio = float(metrics.get('white_ratio') or 0.0)
                rendered.append(
                    {
                        'page_idx': page_idx,
                        'raw': raw,
                        'score': score,
                        'green_ratio': green_ratio,
                        'white_ratio': white_ratio,
                    }
                )
            if not rendered:
                return []

            # Selección:
            # Preferimos páginas con "campo" (dominante verde). Esto evita elegir tablas grandes con poco verde.
            board_pages = [
                item
                for item in rendered
                if float(item.get('green_ratio') or 0.0) >= 0.08
                and float(item.get('white_ratio') or 0.0) <= 0.82
                and float(item.get('score') or 0.0) >= 16.0
            ]
            if board_pages:
                # Mantiene orden de documento: útil cuando hay varias tareas/diagramas.
                selected = sorted(board_pages, key=lambda item: int(item.get('page_idx') or 0))
            else:
                # Si no hay campo claro, caemos al score general.
                good = [item for item in rendered if float(item.get('score') or 0.0) >= 12.0]
                if good:
                    selected = sorted(good, key=lambda item: int(item.get('page_idx') or 0))
                else:
                    selected = sorted(rendered, key=lambda item: float(item.get('score') or 0.0), reverse=True)

            # Si solo hay una página de campo pero se pidieron varias imágenes, intentamos dividirla en varios campos.
            if max_images > 1 and len(selected) == 1:
                split = _split_board_page_image_bytes(selected[0].get('raw') or b'', max_images=max_images)
                if split:
                    selected = [{'page_idx': int(selected[0].get('page_idx') or 1), 'raw': chunk, 'score': 0.0} for chunk in split]

            payloads = []
            for item in selected[:max_images]:
                raw = item.get('raw') or b''
                if Image is not None and raw:
                    try:
                        with Image.open(io.BytesIO(raw)) as img:
                            optimized = img.convert('RGB')
                            # Mini-optimización para peso, manteniendo buena calidad.
                            optimized.thumbnail((1700, 1200))
                            buffer = io.BytesIO()
                            optimized.save(buffer, format='JPEG', quality=82, optimize=True)
                            raw = buffer.getvalue()
                    except Exception:
                        pass
                filename = f'task-preview-{uuid.uuid4().hex[:10]}.jpg'
                payloads.append((filename, ContentFile(raw)))
            return payloads
    except Exception:
        return []


def _default_task_preview_payload():
    try:
        fallback_path = Path(settings.BASE_DIR) / 'static' / 'football' / 'campo-futbol.jpg'
        if not fallback_path.exists() or not fallback_path.is_file():
            return None
        raw = fallback_path.read_bytes()
        if Image is not None:
            try:
                with Image.open(io.BytesIO(raw)) as img:
                    normalized = img.convert('RGB')
                    normalized.thumbnail((1200, 850))
                    buffer = io.BytesIO()
                    normalized.save(buffer, format='JPEG', quality=74, optimize=True)
                    raw = buffer.getvalue()
            except Exception:
                pass
        filename = f'task-preview-{uuid.uuid4().hex[:10]}.jpg'
        return filename, ContentFile(raw)
    except Exception:
        return None


def _ensure_task_preview_image(task, prefer_render=False):
    if not task or not getattr(task, 'task_pdf', None):
        return False
    preview_payload = _extract_preview_image_from_pdf(task.task_pdf, prefer_render=prefer_render)
    if not preview_payload:
        return False
    preview_name, preview_content = preview_payload
    try:
        task.task_preview_image.save(preview_name, preview_content, save=True)
        return bool(task.task_preview_image)
    except Exception:
        return False


def _task_preview_needs_refresh(task):
    if not task:
        return False
    preview_name = str(getattr(task, 'task_preview_image', '') or '').strip()
    if not preview_name:
        return True
    try:
        if not default_storage.exists(preview_name):
            return True
    except Exception:
        return True
    cache_key = f'football:preview-quality:{preview_name}'
    cached = cache.get(cache_key)
    if cached is not None:
        return bool(cached)
    try:
        with default_storage.open(preview_name, 'rb') as handle:
            raw = handle.read()
        needs_refresh = _is_preview_quality_low(raw)
    except Exception:
        needs_refresh = True
    cache.set(cache_key, bool(needs_refresh), 60 * 60 * 6)
    return bool(needs_refresh)


def _ensure_library_task_preview(task, force=False, prefer_render=False):
    if not task:
        return False
    current_name = str(getattr(task, 'task_preview_image', '') or '').strip()
    if current_name and not force:
        try:
            if default_storage.exists(current_name):
                return True
        except Exception:
            pass
    if getattr(task, 'task_pdf', None):
        if _ensure_task_preview_image(task, prefer_render=prefer_render):
            return True
    fallback = _default_task_preview_payload()
    if not fallback:
        return False
    fallback_name, fallback_content = fallback
    try:
        task.task_preview_image.save(fallback_name, fallback_content, save=True)
        return bool(task.task_preview_image)
    except Exception:
        return False


